function getSnapshotContentForPath(snapWS: ModWorkspace, relativePath: string): string {
  const normPath = relativePath.replace(/\\/g, '/').replace(/^\.\//, '').replace(/^\//, '');
  const modId = toSafeModId(snapWS.name);

  // 1. content.xml
  if (normPath === 'content.xml') {
    return generateContentXML(modId, snapWS);
  }

  // 2. README.md
  if (normPath.toLowerCase() === 'readme.md') {
    return `# ${snapWS.name || modId}\n\nGenerated by X4 Forge.\n`;
  }

  // 3. md/<modId>.xml
  if (normPath.startsWith('md/') && normPath.endsWith('.xml')) {
    return generateMDXML(snapWS);
  }

  // 4. UI Layouts
  if (normPath.startsWith('md_ui_layouts/') && normPath.endsWith('.xml')) {
    return generateUIXML(snapWS);
  }

  // 5. AIScripts
  if (normPath.startsWith('aiscripts/') && normPath.endsWith('.xml')) {
    const fileName = normPath.substring('aiscripts/'.length);
    const scriptName = fileName.replace('.xml', '');
    const script = snapWS.aiScripts?.find(s => s.name === scriptName || s.name + '.xml' === fileName);
    if (script) {
      return compileScriptToXML(script);
    }
  }

  // 6. Wares and Jobs in libraries/
  if (normPath === 'libraries/wares.xml') {
    return compileWaresXML(snapWS.wares || []);
  }
  if (normPath === 'libraries/jobs.xml') {
    return compileJobsXML(snapWS.jobs || []);
  }

  // 7. Translations in t/
  if (normPath.startsWith('t/') && normPath.endsWith('.xml')) {
    const fileName = normPath.substring('t/'.length);
    const tFile = snapWS.tFiles?.find(f => f.fileName === fileName || toTFileName(f) === fileName);
    if (tFile) {
      return compileTFileXML(tFile);
    }
  }

  // 8. XML diff patches (by targetFile path)
  if (snapWS.xmlPatches?.length) {
    const patches = snapWS.xmlPatches.filter(p => {
      const pTarget = (p.targetFile || '').replace(/\\/g, '/').replace(/^\.\//, '').replace(/^\//, '');
      return pTarget === normPath;
    });
    if (patches.length > 0) {
      return compileDiffDocument(patches, normPath);
    }
  }

  return '';
}

export default function CodePreview({ 
  workspace, 
  setWorkspace, 
  saveCheckpoint, 
  modWorkspacePath,
  activeEditorFile,
  setActiveEditorFile,
  selectedNode,
  compileStatus,
  compileMessage,
  handleCompileModProject,
  diagnostics,
  diagnosticSource,
  snapshotDiffWorkspace,
  onClearSnapshotDiff,
  selectedCueIds,
  autoSaveEnabled: propAutoSaveEnabled,
  setAutoSaveEnabled: propSetAutoSaveEnabled,
  codeCollapsed,
  setCodeCollapsed,
  topBarTarget
}: CodePreviewProps) {
  const [codeActiveTab, setCodeActiveTab] = useState<'md' | 'ui' | 'node' | 'file'>('md');
  const [toolActiveTab, setToolActiveTab] = useState<'analyzer' | 'playtest'>('analyzer');
  const [copied, setCopied] = useState<boolean>(false);
  
  // Cognitive Analyzer states
  const [analysisResult, setAnalysisResult] = useState<ScriptAnalysis | null>(null);
  const [analyzing, setAnalyzing] = useState<boolean>(false);
  const [analysisError, setAnalysisError] = useState<string | null>(null);
  const [lastAnalyzedWorkspace, setLastAnalyzedWorkspace] = useState<string>('');

  // Playtest Live Debugger states
  const [syncStatus, setSyncStatus] = useState<'idle' | 'syncing' | 'success' | 'error'>('idle');
  const [syncErrorMsg, setSyncErrorMsg] = useState<string>('');
  
  const [localAutoSaveEnabled, setLocalAutoSaveEnabled] = useState<boolean>(false);
  const autoSaveEnabled = propAutoSaveEnabled !== undefined ? propAutoSaveEnabled : localAutoSaveEnabled;
  const setAutoSaveEnabled = propSetAutoSaveEnabled !== undefined ? propSetAutoSaveEnabled : setLocalAutoSaveEnabled;

  // Snapshot / version-history (rollback) state
  const [snapshots, setSnapshots] = useState<{ name: string; savedAt: string }[]>([]);
  const [showSnapshots, setShowSnapshots] = useState<boolean>(false);
  const [snapshotMsg, setSnapshotMsg] = useState<string>('');
  
  const [logInput, setLogInput] = useState<string>('');
  const [diagnosingLogs, setDiagnosingLogs] = useState<boolean>(false);
  const [logAnalysis, setLogAnalysis] = useState<LogAnalysisResult | null>(null);
  const [diagnosticError, setDiagnosticError] = useState<string | null>(null);
  const [successfulFixApplied, setSuccessfulFixApplied] = useState<string | null>(null);

  // File Editor states
  const [editorContent, setEditorContent] = useState<string>('');
  const [editorSaveStatus, setEditorSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
  const [editorError, setEditorError] = useState<string>('');
  const [generatedDraft, setGeneratedDraft] = useState<string>('');
  const [generatedDraftKey, setGeneratedDraftKey] = useState<string>('');
  const [generatedDraftDirty, setGeneratedDraftDirty] = useState<boolean>(false);
  const [generatedApplyStatus, setGeneratedApplyStatus] = useState<'idle' | 'applying' | 'applied' | 'error'>('idle');
  const [generatedApplyMessage, setGeneratedApplyMessage] = useState<string>('');
  const [generatedEditorScroll, setGeneratedEditorScroll] = useState({ top: 0, left: 0 });
  const [splitEditorScroll, setSplitEditorScroll] = useState({ top: 0, left: 0 });

  // ================================================================ 
  // CUSTOM ANTI-GRAVITY IDE & DIFF PREVIEWER CONTEXTUAL VARIABLESS 
  // ================================================================ 
  interface Tab {
    id: string; // 'md', 'ui', 'node', or filesystem file path
    name: string;
    type: 'md' | 'ui' | 'node' | 'file';
    path?: string;
  }

  const [openTabs, setOpenTabs] = useState<Tab[]>([
    { id: 'md', name: 'MD.xml', type: 'md' },
    { id: 'ui', name: 'UI_LAYOUT.xml', type: 'ui' }
  ]);
  const [openFilesMap, setOpenFilesMap] = useState<Record<string, { name: string, path: string, content: string, originalContent: string }>>({});

  const [diffEnabled, setDiffEnabled] = useState<boolean>(false);
  const [diffMode, setDiffMode] = useState<'split' | 'unified'>('split');
  const [diffBaseType, setDiffBaseType] = useState<'compile' | 'original'>('compile');
  
  const effectiveDiffEnabled = diffEnabled || !!snapshotDiffWorkspace;

  // Auto-hide the code minimap in a narrow panel (G8b): the VS Code–style overview steals
  // ~40px and is low-value below this width. A CALLBACK ref reliably attaches a ResizeObserver
  // the moment the root mounts (a plain ref + [] effect missed it when the root rendered after
  // an early return), so the width tracks live as the user resizes the panel.
  const [editorWidth, setEditorWidth] = React.useState<number>(9999);
  const minimapObserverRef = React.useRef<ResizeObserver | null>(null);
  const setEditorRoot = React.useCallback((el: HTMLDivElement | null) => {
    minimapObserverRef.current?.disconnect();
    if (el && typeof ResizeObserver !== 'undefined') {
      setEditorWidth(el.getBoundingClientRect().width);
      minimapObserverRef.current = new ResizeObserver(entries => {
        for (const e of entries) setEditorWidth(e.contentRect.width);
      });
      minimapObserverRef.current.observe(el);
    }
  }, []);
  const showMinimap = editorWidth >= 560;

  // Baseline copies for live modifications comparisons
  const [initialMDCode, setInitialMDCode] = useState<string>('');
  const [initialUICode, setInitialUICode] = useState<string>('');
  const [originalMD, setOriginalMD] = useState<string>('');
  const [originalUI, setOriginalUI] = useState<string>('');

  const [initialWorkspace, setInitialWorkspace] = useState<ModWorkspace | null>(null);
  const [lastCompiledWorkspace, setLastCompiledWorkspace] = useState<ModWorkspace | null>(null);

  useEffect(() => {
    if (!initialWorkspace && workspace) {
      setInitialWorkspace(JSON.parse(JSON.stringify(workspace)));
    }
  }, [workspace]);

  useEffect(() => {
    if (compileStatus === 'success') {
      setLastCompiledWorkspace(JSON.parse(JSON.stringify(workspace)));
    }
  }, [compileStatus]);

  const mdCode = selectedCueIds && selectedCueIds.length > 0
    ? generateMDXML(workspace, selectedCueIds)
    : generateMDXML(workspace);
  const uiCode = generateUIXML(workspace);

  const generateNodeXMLPreview = (node: MDNode) => {
    let xml = `<${node.xmlTag}`;
    Object.entries(node.properties || {}).forEach(([k, v]) => {
      if (v !== undefined && v !== null && v !== '') {
        xml += ` ${k}="${v}"`;
      }
    });
    if (node.comment) {
      xml += ` comment="${node.comment}"`;
    }
    xml += ` />`;
    return xml;
  };

  const collectDownstreamNodeIds = (startIds: string[], sourceWorkspace: ModWorkspace = workspace): Set<string> => {
    const ids = new Set<string>(startIds);
    const queue = [...startIds];
    while (queue.length > 0) {
      const sourceId = queue.shift()!;
      sourceWorkspace.links
        .filter(link => link.sourceNodeId === sourceId)
        .forEach(link => {
          if (!ids.has(link.targetNodeId)) {
            ids.add(link.targetNodeId);
            queue.push(link.targetNodeId);
          }
        });
    }
    return ids;
  };

  const generateSelectedNodeHierarchyXML = (node: MDNode | null, sourceWorkspace: ModWorkspace = workspace): string => {
    if (!node) return '';
    if (node.type === 'cue') {
      return generateMDXML(sourceWorkspace, [node.id]);
    }

    const downstreamIds = collectDownstreamNodeIds([node.id], sourceWorkspace);
    const selectedNodes = sourceWorkspace.nodes.filter(n => downstreamIds.has(n.id));
    const selectedNodeIds = new Set(selectedNodes.map(n => n.id));
    const syntheticCue: MDNode = {
      id: '__preview_selected_node_cue__',
      type: 'cue',
      label: `Preview: ${node.label}`,
      xmlTag: 'cue',
      x: 0,
      y: 0,
      properties: {
        name: `Preview_${node.properties?.name || node.label || node.xmlTag}`,
        instantiate: 'false',
        namespace: 'this'
      },
      propertiesSchema: [],
      inputs: [],
      outputs: []
    };

    const hierarchyLinks = sourceWorkspace.links.filter(link =>
      selectedNodeIds.has(link.sourceNodeId) && selectedNodeIds.has(link.targetNodeId)
    );
    const syntheticLinks = [
      {
        id: '__preview_selected_node_link__',
        sourceNodeId: syntheticCue.id,
        sourcePortId: node.type === 'action' ? 'out_act' : 'out_cond',
        targetNodeId: node.id,
        targetPortId: node.type === 'action' ? 'in_act' : 'in_cond'
      },
      ...sourceWorkspace.links
        .filter(link => link.sourceNodeId === node.id && link.sourcePortId === 'out_flow')
        .map(link => ({
          id: `__preview_flow_${link.id}`,
          sourceNodeId: syntheticCue.id,
          sourcePortId: 'out_act',
          targetNodeId: link.targetNodeId,
          targetPortId: 'in_act'
        })),
      ...hierarchyLinks
    ];

    return generateMDXML({
      ...sourceWorkspace,
      nodes: [syntheticCue, ...selectedNodes],
      links: syntheticLinks
    }, [syntheticCue.id]);
  };

  let currentCode = '';
  if (codeActiveTab === 'md') {
    currentCode = selectedNode ? generateSelectedNodeHierarchyXML(selectedNode) : mdCode;
  } else if (codeActiveTab === 'ui') {
    currentCode = uiCode;
  } else if (codeActiveTab === 'node') {
    currentCode = generateSelectedNodeHierarchyXML(selectedNode);
  } else if (codeActiveTab === 'file') {
    currentCode = editorContent;
  }

  const workspaceSerialized = JSON.stringify({
    name: workspace.name,
    description: workspace.description,
    author: workspace.author,
    version: workspace.version,
    compileSettings: workspace.compileSettings,
    nodes: workspace.nodes.map(n => ({ id: n.id, type: n.type, label: n.label, xmlTag: n.xmlTag, properties: n.properties, includeInBuild: n.includeInBuild })),
    links: workspace.links,
    uiWidgets: workspace.uiWidgets.map(w => ({ id: w.id, type: w.type, label: w.label, properties: w.properties, w: w.w, h: w.h, includeInBuild: w.includeInBuild })),
    uiTheme: workspace.uiTheme,
    aiScripts: workspace.aiScripts,
    wares: workspace.wares,
    jobs: workspace.jobs,
    tFiles: workspace.tFiles,
    xmlPatches: workspace.xmlPatches
  });

  const generatedDraftSourceKey = JSON.stringify({
    tab: codeActiveTab,
    selectedNodeId: selectedNode?.id || null,
    selectedCueIds,
    activeFilePath: activeEditorFile?.path || null,
    workspaceSerialized
  });

  useEffect(() => {
    if (codeActiveTab === 'file') return;
    if (!generatedDraftDirty || generatedDraftKey !== generatedDraftSourceKey) {
      setGeneratedDraft(currentCode);
      setGeneratedDraftKey(generatedDraftSourceKey);
      setGeneratedDraftDirty(false);
      setGeneratedApplyStatus('idle');
      setGeneratedApplyMessage('');
    }
  }, [codeActiveTab, currentCode, generatedDraftDirty, generatedDraftKey, generatedDraftSourceKey]);

  const isAnalysisStale = analysisResult !== null && lastAnalyzedWorkspace !== workspaceSerialized;

  // Check if File System Access API is supported
  const isFileSystemAccessSupported = typeof window !== 'undefined' && 'showDirectoryPicker' in window;



  // Handle automatic synchronization to folder on workspace edits
  useEffect(() => {
