    setOpenFilesMap(prev => {
      const copy = { ...prev };
      delete copy[tabId];
      return copy;
    });
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(activeCodeText);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const downloadFile = () => {
    const blob = new Blob([activeCodeText], { type: 'text/xml' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = codeActiveTab === 'md' 
      ? `${workspace.name || 'custom_md_script'}.xml` 
      : codeActiveTab === 'ui'
      ? `${workspace.name || 'custom_menu_layout'}_ui.xml`
      : activeEditorFile?.name || 'edited_file.xml';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // Memory-leak-safe, super-fast line block aligner for side-by-side IDE visual comparisons
  const computeLineDiff = (oldLines: string[], newLines: string[]): { 
    originalLines: DiffLine[]; 
    modifiedLines: DiffLine[]; 
    unifiedLines: DiffLine[]; 
  } => {
    // If either is too large, use a fast simple line matching or simple slider to protect resources
    if (oldLines.length > 2500 || newLines.length > 2500) {
      const originalLines: DiffLine[] = oldLines.map((l, idx) => ({ type: 'removed', value: l, originalLineNumber: idx + 1 }));
      const modifiedLines: DiffLine[] = newLines.map((l, idx) => ({ type: 'added', value: l, modifiedLineNumber: idx + 1 }));
      const unifiedLines: DiffLine[] = [
        ...oldLines.map((l, idx) => ({ type: 'removed' as const, value: l, originalLineNumber: idx + 1 })),
        ...newLines.map((l, idx) => ({ type: 'added' as const, value: l, modifiedLineNumber: idx + 1 }))
      ];
      return { originalLines, modifiedLines, unifiedLines };
    }

    const m = oldLines.length;
    const n = newLines.length;
    const dp: number[][] = [];
    for (let i = 0; i <= m; i++) {
      dp[i] = new Array(n + 1).fill(0);
    }

    for (let i = 1; i <= m; i++) {
      for (let j = 1; j <= n; j++) {
        if (oldLines[i - 1] === newLines[j - 1]) {
          dp[i][j] = dp[i - 1][j - 1] + 1;
        } else {
          dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
        }
      }
    }

    let i = m;
    let j = n;
    
    const revOriginal: DiffLine[] = [];
    const revModified: DiffLine[] = [];
    const revUnified: DiffLine[] = [];

    while (i > 0 || j > 0) {
      if (i > 0 && j > 0 && oldLines[i - 1] === newLines[j - 1]) {
        const lineVal = oldLines[i - 1];
        revOriginal.push({ type: 'unchanged', value: lineVal, originalLineNumber: i, modifiedLineNumber: j });
        revModified.push({ type: 'unchanged', value: lineVal, originalLineNumber: i, modifiedLineNumber: j });
        revUnified.push({ type: 'unchanged', value: lineVal, originalLineNumber: i, modifiedLineNumber: j });
        i--;
        j--;
      } else if (j > 0 && (i === 0 || dp[i][j - 1] >= dp[i - 1][j])) {
        revOriginal.push({ type: 'empty', value: '', modifiedLineNumber: j });
        revModified.push({ type: 'added', value: newLines[j - 1], modifiedLineNumber: j });
        revUnified.push({ type: 'added', value: newLines[j - 1], modifiedLineNumber: j });
        j--;
      } else {
        revOriginal.push({ type: 'removed', value: oldLines[i - 1], originalLineNumber: i });
        revModified.push({ type: 'empty', value: '', originalLineNumber: i });
        revUnified.push({ type: 'removed', value: oldLines[i - 1], originalLineNumber: i });
        i--;
      }
    }

    return {
      originalLines: revOriginal.reverse(),
      modifiedLines: revModified.reverse(),
      unifiedLines: revUnified.reverse()
    };
  };

  const getDiffTexts = (): { original: string, current: string } => {
    let original = '';
    let current = '';

    if (codeActiveTab === 'md') {
      if (snapshotDiffWorkspace) {
        const snapSelected = selectedNode
          ? snapshotDiffWorkspace.nodes?.find(n => n.id === selectedNode.id) || null
          : null;
        original = snapSelected
          ? generateSelectedNodeHierarchyXML(snapSelected, snapshotDiffWorkspace)
          : generateMDXML(snapshotDiffWorkspace, selectedCueIds);
      } else {
        const baseWorkspace = diffBaseType === 'compile' 
          ? (lastCompiledWorkspace || initialWorkspace || workspace)
          : (initialWorkspace || workspace);
        const baseSelected = selectedNode
          ? baseWorkspace.nodes?.find(n => n.id === selectedNode.id) || null
          : null;
        original = baseSelected
          ? generateSelectedNodeHierarchyXML(baseSelected, baseWorkspace)
          : generateMDXML(baseWorkspace, selectedCueIds);
      }
      current = activeCodeText;
    } else if (codeActiveTab === 'ui') {
      if (snapshotDiffWorkspace) {
        original = generateUIXML(snapshotDiffWorkspace);
      } else {
        original = diffBaseType === 'compile' ? (originalUI || uiCode) : (initialUICode || uiCode);
      }
      current = activeCodeText;
    } else if (codeActiveTab === 'node') {
      current = activeCodeText;
      if (snapshotDiffWorkspace && selectedNode) {
        const snapNode = snapshotDiffWorkspace.nodes?.find(n => n.id === selectedNode.id);
        original = snapNode ? generateSelectedNodeHierarchyXML(snapNode, snapshotDiffWorkspace) : '';
      } else {
        original = '';
      }
    } else if (codeActiveTab === 'file') {
      current = activeCodeText;
      if (activeEditorFile) {
        if (snapshotDiffWorkspace) {
          original = getSnapshotContentForPath(snapshotDiffWorkspace, activeEditorFile.path);
        } else {
          original = openFilesMap[activeEditorFile.path]?.originalContent || activeEditorFile.content;
        }
      }
    }

    return { original, current };
  };

  const triggerAnalysis = async () => {
    setAnalyzing(true);
    setAnalysisError(null);
    try {
      const response = await fetch('/api/gemini/analyze', {
        method: 'POST',
        headers: getAIHeaders(),
        body: JSON.stringify({ workspace })
      });
      const data = await handleApiResponse(response, "Failed to establish telemetry connection to server.");
      setAnalysisResult(data.analysis);
      setLastAnalyzedWorkspace(workspaceSerialized);
    } catch (err: any) {
      console.error(err);
      setAnalysisError(err.message || "Failed to catalog script outline. Verify telemetry status.");
    } finally {
      setAnalyzing(false);
    }
  };

  const saveToDirectory = async (showFeedback: boolean) => {
    if (!modWorkspacePath) return;
    if (showFeedback) {
      setSyncStatus('syncing');
    }
    try {
      const deployRes = await fetch('/api/agent/deploy', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ workspace })
      });
      const deployData = await deployRes.json();
      if (deployRes.ok && deployData.success) {
        if (showFeedback) {
          setSyncStatus('success');
          setTimeout(() => setSyncStatus('idle'), 2000);
        }
      } else {
        throw new Error(deployData.error || "Failed to deploy on server.");
      }
    } catch (err: any) {
      console.error("Playtest Directory Sync Error:", err);
      if (showFeedback) {
        setSyncStatus('error');
        setSyncErrorMsg(err.message || "Disk write access refused.");
        setTimeout(() => setSyncStatus('idle'), 5000);
      }
    }
  };

  // Load the on-disk snapshot list for the current mod from <modid>/.snapshots/
  const toggleSnapshots = async () => {
    const next = !showSnapshots;
    setShowSnapshots(next);
    if (next && modWorkspacePath) {
      try {
        const response = await fetch(`/api/fs/snapshots?modId=${encodeURIComponent(toSafeModId(workspace.name))}`);
        if (response.ok) {
          const list = await response.json();
          setSnapshots(list);
        }
      } catch (err) {
        console.error("Failed to load snapshots:", err);
      }
    }
  };

  // Restore the workspace from a chosen snapshot (pushes an undo checkpoint first)
  const restoreSnapshot = async (snapshotName: string) => {
    if (!modWorkspacePath || !setWorkspace) return;
    try {
      const response = await fetch('/api/fs/restore-snapshot', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          modId: toSafeModId(workspace.name),
          snapshotName
        })
      });
      if (response.ok) {
        const resData = await response.json();
        if (resData.success && resData.workspace) {
          if (saveCheckpoint) saveCheckpoint();
          setWorkspace(resData.workspace);
          setSnapshotMsg(`Restored snapshot from ${snapshotName.replace('snapshot_', '').replace('.json', '')}`);
          setShowSnapshots(false);
          setTimeout(() => setSnapshotMsg(''), 3500);
          return;
        }
      }
      throw new Error("Failed to restore snapshot on server.");
    } catch (err: any) {
      setSnapshotMsg(err.message || 'Could not restore snapshot.');
      setTimeout(() => setSnapshotMsg(''), 3500);
    }
  };

  const handleTriggerLogAnalysis = async () => {
    if (!logInput.trim()) return;
    setDiagnosingLogs(true);
    setDiagnosticError(null);
    try {
      const response = await fetch('/api/gemini/analyze-log', {
        method: 'POST',
        headers: getAIHeaders(),
        body: JSON.stringify({ workspace, logs: logInput })
      });
      const data = await handleApiResponse(response, "Log parsing request rejected.");
      setLogAnalysis(data.analysis);
    } catch (err: any) {
      console.error(err);
      setDiagnosticError(err.message || "Failed to analyze X4 script logs via Gemini.");
    } finally {
      setDiagnosingLogs(false);
    }
  };

  const handleApplyAutoFix = (fix: any) => {
    if (!setWorkspace || !saveCheckpoint) {
      console.warn("Auto-fix not supported in this frame state.");
      return;
    }

    if (fix.type === 'update_node_property' && fix.nodeId && fix.propertyKey) {
      saveCheckpoint();
      setWorkspace(prev => {
        const updatedNodes = prev.nodes.map(n => {
          if (n.id === fix.nodeId) {
