  };

  // NOTE: All packaging/compiler helpers (mod id, content.xml, per-domain XML generators,
  // file writers, snapshots, and package validation) now live in src/lib/modCompiler.ts and
  // are shared by both the auto-sync and Compile paths via compileAndSaveAll(). The previous
  // in-component duplicates were removed during the compiler consolidation.

  const onCompileModProject = async () => {
    await handleCompileModProject();
    setToolActiveTab('playtest');
  };

  // Memo cache for whole-file highlighting: the regex passes are O(file size) and the
  // same strings are re-highlighted on every render (drag, scroll, state changes).
  // Keyed by the input string itself — V8 caches string hashes, and the generated
  // text keeps the same instance between renders, so hits are cheap. Small cap keeps
  // memory bounded when many distinct files are viewed.
  const highlightCacheRef = React.useRef(new Map<string, string>());

  const highlightXML = (rawXML: string) => {
    const cache = highlightCacheRef.current;
    const cached = cache.get(rawXML);
    if (cached !== undefined) return cached;

    const escaped = rawXML
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
    // Large-file guard: the span-wrapping regex passes below are O(file size) and run on
    // every render. For very large generated files (e.g. deadair's 868KB MD) that freezes
    // the viewer, so above the threshold we skip coloring and return escaped text only —
    // still fully readable and editable, just monochrome (standard large-file IDE behavior).
    const out = escaped.length > 100000 ? escaped : escaped
      // Color attributes FIRST (on the escaped text) so the tag/comment passes below
      // don't re-match the class="..." attributes of the <span>s we inject here.
      .replace(/([a-zA-Z0-9_:-]+)=(&quot;|")([^"&]*)(&quot;|")/g, '<span class="text-purple-400">$1</span>=<span class="text-emerald-300">$2$3$4</span>')
      .replace(/(&lt;\/?[a-zA-Z0-9_:-]+)(\s|&gt;)/g, '<span class="text-cyan-400 font-semibold">$1</span>$2')
      .replace(/(&lt;!--[\s\S]*?--&gt;)/g, '<span class="text-slate-500 font-mono italic">$1</span>');

    if (cache.size > 12) cache.clear();
    cache.set(rawXML, out);
    return out;
  };

  // Pick a searchable token for a diagnostic so we can locate its line in the generated code.
  const getDiagToken = (d: PackageDiagnostic): string | null => {
    if (d.sourceRef?.label) return d.sourceRef.label;
    if (d.sourceRef?.id && !/^(cue|node|event|action|condition)_/.test(d.sourceRef.id)) return d.sourceRef.id;
    const m = (d.message || '').match(/"([^"]+)"/);
    return m ? m[1] : null;
  };

  // Map each diagnostic to a 0-based line index in the given code (by explicit line, or token match).
  const computeLineDiagMap = (code: string, diags: PackageDiagnostic[]) => {
    const map = new Map<number, { severity: string; messages: string[] }>();
    const lines = code.split('\n');
    diags.forEach(d => {
      let idx = -1;
      if (typeof d.line === 'number' && d.line >= 1 && d.line <= lines.length) {
        idx = d.line - 1;
      } else {
        const token = getDiagToken(d);
        if (token) idx = lines.findIndex(l => l.includes(token));
      }
      if (idx >= 0) {
        const ex = map.get(idx);
        const severity = (ex?.severity === 'error' || d.severity === 'error') ? 'error' : (ex?.severity || d.severity || 'warning');
        map.set(idx, { severity, messages: [...(ex?.messages || []), d.message] });
      }
    });
    return map;
  };


  const highlightCodeCacheRef = React.useRef(new Map<string, { ext: string | undefined; out: string }>());

  const highlightCode = (rawText: string) => {
    const ext = activeEditorFile?.name.split('.').pop()?.toLowerCase();
    const cache = highlightCodeCacheRef.current;
    const cached = cache.get(rawText);
    if (cached !== undefined && cached.ext === ext) return cached.out;

    let out: string;
    // Large-file guard (see highlightXML): skip coloring for big files to keep the editor responsive.
    if (rawText.length > 100000) {
      out = rawText.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    } else if (ext === 'json') {
      out = rawText
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/("(?:\\.|[^"\\])*")(\s*:)/g, '<span class="text-purple-400">$1</span>$2')
        .replace(/:\s*("(?:\\.|[^"\\])*")/g, ': <span class="text-emerald-300">$1</span>')
        .replace(/\b(true|false|null)\b/g, '<span class="text-amber-400">$1</span>');
    } else {
      out = highlightXML(rawText);
    }

    if (cache.size > 12) cache.clear();
    cache.set(rawText, { ext, out });
    return out;
  };

  const renderMinimap = (lines: { type?: string; value: string }[]) => {
    return (
      <div className="w-10 shrink-0 border-l border-white/5 bg-[#08090d] select-none overflow-hidden flex flex-col justify-start relative pointer-events-none pr-0.5">
        <div className="absolute inset-0 flex flex-col py-2 pointer-events-none overflow-hidden scale-y-95 opacity-80 select-none">
          {lines.slice(0, 160).map((line, idx) => {
            const isAdded = line.type === 'added';
            const isRemoved = line.type === 'removed';
            
            let trackColor = 'bg-slate-700/25';
            if (isAdded) {
              trackColor = 'bg-[#10b981]/45';
            } else if (isRemoved) {
              trackColor = 'bg-[#ef4444]/45';
            } else {
              const val = line.value.trim();
              if (val.startsWith('<cue') || val.startsWith('</cue')) {
                trackColor = 'bg-amber-400/45';
              } else if (val.startsWith('<event') || val.startsWith('<action')) {
                trackColor = 'bg-cyan-400/40';
              } else if (val.startsWith('<')) {
                trackColor = 'bg-purple-400/30';
              } else if (val.length > 0) {
                trackColor = 'bg-slate-650/15';
              }
            }

            const spaceCount = line.value.length - line.value.trimStart().length;
            const indent = Math.min(spaceCount * 0.8, 12);

            return (
              <div key={idx} className="flex h-[2px] items-center my-[0.8px]" style={{ paddingLeft: `${indent}px` }}>
                <div className={`h-[1px] rounded ${trackColor}`} style={{ width: `${Math.max(4, Math.min(22, line.value.trim().length / 2))}px` }} />
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderHighlightedTextarea = (
    value: string,
    onChange: (value: string) => void,
    ariaLabel: string,
    paddingClass: string,
    scroll: { top: number; left: number },
    setScroll: React.Dispatch<React.SetStateAction<{ top: number; left: number }>>,
    toneClass = 'text-slate-300'
  ) => (
    <>
      <pre
        aria-hidden="true"
        className={`absolute inset-0 ${paddingClass} font-mono text-xs leading-relaxed whitespace-pre pointer-events-none select-none overflow-hidden ${toneClass}`}
        style={{ transform: `translate(${-scroll.left}px, ${-scroll.top}px)` }}
        dangerouslySetInnerHTML={{ __html: `${highlightXML(value)}\n` }}
      />
      <textarea
        value={value}
        onChange={e => onChange(e.target.value)}
        onScroll={e => {
          const target = e.currentTarget;
          setScroll({ top: target.scrollTop, left: target.scrollLeft });
        }}
        spellCheck={false}
        className={`absolute inset-0 w-full h-full resize-none ${paddingClass} bg-transparent text-transparent caret-cyan-300 selection:bg-cyan-500/25 outline-none font-mono text-xs leading-relaxed whitespace-pre overflow-auto scrollbar-thin`}
        aria-label={ariaLabel}
      />
    </>
  );

  const isFileEditorActive = codeActiveTab === 'file' && !!activeEditorFile;
  // Memoized: splitting + token-searching a large generated file on every render is
  // O(file size × diagnostics) — only recompute when the text or diagnostics change.
  const codeLines = React.useMemo(() => activeCodeText.split('\n'), [activeCodeText]);
  const lineDiagMap = React.useMemo(
    () => computeLineDiagMap(activeCodeText, diagnostics),
    [activeCodeText, diagnostics]
  );

  return (
    <div ref={setEditorRoot} id="antigravity_ide_container" className="flex flex-col flex-1 w-full min-w-0 h-full min-h-0 bg-[#0b0d12] text-slate-100 rounded-lg overflow-hidden border border-white/5 shadow-2xl relative">
      {/* Tab strip + compact actions — PORTALED into the persistent top bar (App) so the
          editor body is a code-only entity. Inline fallback when no portal target. */}
      {(topBarTarget ? createPortal : ((c: any): any => c))((
        <div className="bg-[#0b0d12] border-b border-white/5 select-none flex items-center justify-between w-full pl-1">
        <div className="flex items-center divide-x divide-white/5 overflow-x-auto scrollbar-none flex-1">
          {openTabs.map(tab => {
            const isActive = 
              (tab.id === 'md' && codeActiveTab === 'md') ||
              (tab.id === 'ui' && codeActiveTab === 'ui') ||
              (tab.id === 'node' && codeActiveTab === 'node') ||
              (tab.type === 'file' && codeActiveTab === 'file' && activeEditorFile?.path === tab.id);

            const isUnsaved = tab.type === 'file' && openFilesMap[tab.id] 
              ? openFilesMap[tab.id].content !== openFilesMap[tab.id].originalContent 
              : false;

            return (
              <div
                key={tab.id}
                className={`flex items-center h-9 px-3.5 border-r border-[#151722] font-mono cursor-pointer transition-all shrink-0 select-none relative group ${
                  isActive 
                    ? 'bg-[#181d2a] text-[#5fc3e4] border-t-2 border-cyan-400 font-bold'
                    : 'bg-[#0a0c10]/50 text-slate-500 hover:bg-[#131720]/80 hover:text-slate-300'
                }`}
                onClick={() => handleSelectTab(tab)}
              >
                <span className="mr-2 select-none">
                  {tab.type === 'md' && <FileCode className="w-3.5 h-3.5 text-cyan-400" />}
                  {tab.type === 'ui' && <FileJson className="w-3.5 h-[#fc5dbb]" />}
                  {tab.type === 'node' && <Terminal className="w-3.5 h-3.5 text-amber-400" />}
                  {tab.type === 'file' && (
                    tab.name.endsWith('.json') ? <FileJson className="w-3.5 h-3.5 text-emerald-400" /> :
                    tab.name.endsWith('.tsx') || tab.name.endsWith('.ts') ? <span className="text-[#3178c6] text-[10px] font-black shrink-0 select-none">TS</span> :
                    <FileCode className="w-3.5 h-3.5 text-blue-400" />
                  )}
                </span>

                <span className="text-[10px] tracking-tight">{tab.name}</span>

                {tab.type === 'file' && (
                  <button
                    type="button"
                    className="ml-2 p-0.5 rounded hover:bg-white/10 text-slate-500 hover:text-white transition-all cursor-pointer"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleCloseTab(tab.id);
                    }}
                  >
                    {isUnsaved ? (
                      <span className="block w-1.5 h-1.5 rounded-full bg-amber-400 group-hover:hidden" />
                    ) : null}
                    <X className={`w-3 h-3 ${isUnsaved ? 'hidden group-hover:block animate-pulse' : 'opacity-40 group-hover:opacity-100'}`} />
                  </button>
                )}
              </div>
            );
          })}
        </div>

        {/* COMPACT ICON-ONLY ACTIONS — the editor's single control strip (right of the tabs). */}
        <div className="flex items-center gap-0.5 px-1.5 shrink-0 select-none border-l border-white/5">
          <button
            onClick={() => setDiffEnabled(!diffEnabled)}
            title={`Diff viewer: ${effectiveDiffEnabled ? 'on' : 'off'}`}
            className={`p-1 rounded transition-all cursor-pointer ${effectiveDiffEnabled ? 'bg-amber-500/15 text-amber-400' : 'text-slate-500 hover:text-slate-300 hover:bg-white/5'}`}
          >
            <Sparkles className="w-3.5 h-3.5" />
          </button>
          {effectiveDiffEnabled && (
            <button
              onClick={() => setDiffMode(diffMode === 'split' ? 'unified' : 'split')}
              title={`Diff mode: ${diffMode}`}
              className="p-1 rounded text-slate-400 hover:text-cyan-400 hover:bg-white/5 transition-all cursor-pointer"
            >
              <Split className="w-3.5 h-3.5" />
            </button>
          )}
          <span className="w-px h-4 bg-white/10 mx-0.5" />
          <button
            onClick={onCompileModProject}
            disabled={compileStatus === 'compiling'}
            title="Compile whole workspace"
            className="p-1 rounded text-emerald-400 hover:text-white hover:bg-emerald-500/20 transition-all cursor-pointer disabled:opacity-40"
          >
            <PackageCheck className="w-3.5 h-3.5" />
          </button>
          {codeActiveTab !== 'file' && (
            <button
              onClick={applyGeneratedCodeEdit}
              disabled={!generatedDraftDirty || generatedApplyStatus === 'applying'}
              title="Apply edited XML back into the workspace"
              className="p-1 rounded text-cyan-300 hover:text-white hover:bg-cyan-500/20 transition-all cursor-pointer disabled:opacity-30 disabled:cursor-not-allowed"
            >
              <Save className="w-3.5 h-3.5" />
            </button>
          )}
          <button onClick={copyToClipboard} title="Copy active code" className="p-1 rounded text-slate-400 hover:text-cyan-400 hover:bg-white/5 transition-all cursor-pointer">
            {copied ? <Check className="w-3.5 h-3.5 text-emerald-400" /> : <Clipboard className="w-3.5 h-3.5" />}
          </button>
          <button onClick={downloadFile} title="Download active file" className="p-1 rounded text-slate-400 hover:text-cyan-400 hover:bg-white/5 transition-all cursor-pointer">
            <Download className="w-3.5 h-3.5" />
          </button>
        </div>
        </div>
      ), topBarTarget as any)}

      {/* Breadcrumb removed — the active tab already names the file; keeps the editor window clean.
          Kept only for directory-file editing, where the full path matters. */}
      {codeActiveTab === 'file' && activeEditorFile && (
        <div className="bg-[#0b0d12] py-1 px-4 text-[9px] text-slate-500 font-mono border-b border-white/5 flex items-center select-none shrink-0">
          <Folder className="w-3.5 h-3.5 text-cyan-500/80 shrink-0 mr-1.5" />
          <span className="truncate flex items-center gap-1">
            {activeEditorFile.path.split('/').map((seg, idx, arr) => (
              <React.Fragment key={seg}>
                <span className={idx === arr.length - 1 ? 'text-slate-300 font-medium' : 'text-slate-600'}>{seg}</span>
                {idx < arr.length - 1 && <span className="text-slate-700 inline">&gt;</span>}
              </React.Fragment>
            ))}
          </span>
        </div>
      )}

      {/* ================================================================ */}
      {/* SNAPSHOT DIFF MODE BANNER                                        */}
      {/* ================================================================ */}
      {snapshotDiffWorkspace && (
        <div className="bg-gradient-to-r from-cyan-950/80 via-slate-900 to-[#0c0e14] border-b border-cyan-500/30 px-4 py-2 flex items-center justify-between font-mono text-xs select-none">
          <div className="flex items-center gap-2.5">
            <div className="w-2 h-2 rounded-full bg-cyan-400 animate-pulse shrink-0" />
            <span className="text-cyan-400 font-bold uppercase tracking-wider text-[10px] shrink-0">Snapshot Diff Active</span>
            <span className="text-slate-650 select-none">|</span>
            <span className="text-slate-400 text-[10px] truncate">
              Comparing current workspace against snapshot: <span className="text-cyan-300 font-bold">{snapshotDiffWorkspace.name}</span>
            </span>
          </div>
          <button
            onClick={onClearSnapshotDiff}
            className="px-2.5 py-1 bg-cyan-500/10 hover:bg-cyan-500/20 text-cyan-400 hover:text-white border border-cyan-500/30 rounded text-[9px] font-bold tracking-wider uppercase transition-all flex items-center gap-1 cursor-pointer shrink-0"
          >
            <X className="w-3 h-3" />
            Close Diff
          </button>
        </div>
      )}

      {/* ================================================================ */}
      {/* VIEWPANE STAGE (DIFF MODE OR NORMAL CODE EDITOR)                  */}
      {/* ================================================================ */}
      <div id="xml_code_viewport" className="flex-1 flex min-h-0 relative select-text overflow-hidden m-2 rounded-lg border border-white/10 bg-[#050608] shadow-[0_3px_14px_rgba(0,0,0,0.45)]">
        {effectiveDiffEnabled ? (
          diffMode === 'split' ? (
            // ==================== SIDE-BY-SIDE DIFF MODE ====================
            <div className="flex-1 flex overflow-hidden min-h-0 bg-[#050608]">
              {/* Sync viewport inside a single vertical scrollbar space */}
              <div className="flex-1 overflow-auto scrollbar-thin flex min-h-0 select-text">
                <div className="flex flex-grow min-w-[750px] divide-x divide-white/5">
                  
                  {/* Left Lane: Reference Source */}
                  <div className="flex-1 bg-[#050608]/98 select-text">
                    <div className="sticky top-0 z-10 bg-[#11131a] border-b border-white/5 py-1.5 px-3.5 font-mono text-[9px] text-[#ef4444] font-bold flex items-center justify-between select-none">
                      <span>ORIGINAL REFERENCE</span>
                      <span className="text-[7.5px] bg-red-950/40 px-1.5 py-0.5 rounded border border-red-500/20 uppercase tracking-widest">BASELINE</span>
                    </div>
                    <div className="py-2.5 text-xs font-mono leading-relaxed">
                      {computeLineDiff(getDiffTexts().original.split('\n'), getDiffTexts().current.split('\n')).originalLines.map((line, i) => {
                        const isRemoved = line.type === 'removed';
                        const isEmpty = line.type === 'empty';
                        
                        let lineBg = 'hover:bg-white/[0.01]';
                        let textColor = 'text-slate-500';
                        if (isRemoved) {
                          lineBg = 'bg-[#ef4444]/10 border-l-2 border-[#ef4444]';
                          textColor = 'text-red-300';
                        } else if (isEmpty) {
                          lineBg = 'bg-[#151720]/15 text-transparent opacity-5 select-none pointer-events-none';
                        }

                        return (
                          <div key={i} className={`flex h-[18px] items-center ${lineBg}`}>
                            <span className="select-none text-right pr-2.5 pl-2 w-10 shrink-0 text-slate-650 text-[9.5px]">
                              {line.originalLineNumber || ''}
                            </span>
                            <span className="select-none w-4 text-center shrink-0 pr-1 text-[#ef4444] text-[9.5px] font-black">
                              {isRemoved ? '-' : ''}
                            </span>
                            <span
                              className={`flex-1 whitespace-pre pr-4 truncate ${textColor}`}
                              dangerouslySetInnerHTML={!isEmpty ? { __html: highlightXML(line.value) || '&nbsp;' } : undefined}
                            />
                          </div>
                        );
                      })}
                    </div>
                  </div>

                  {/* Right Lane: Edited Working Document */}
                  <div className="flex-1 bg-[#050608]/98 select-text">
                    <div className="sticky top-0 z-10 bg-[#11131a] border-b border-white/5 py-1.5 px-3.5 font-mono text-[9px] text-[#22c55e] font-bold flex items-center justify-between select-none">
                      <span>EDITABLE WORKING STATE</span>
                      <span className="text-[7.5px] bg-emerald-950/40 px-1.5 py-0.5 rounded border border-emerald-500/20 uppercase tracking-widest">LIVE EDITOR</span>
                    </div>
                    <div className="relative h-[calc(100%-28px)] min-h-[420px]">
                      {renderHighlightedTextarea(
                        activeCodeText,
                        value => codeActiveTab === 'file' ? handleEditorContentChange(value) : handleGeneratedDraftChange(value),
                        'Editing latest code beside snapshot',
                        'py-2.5 pl-11 pr-4',
                        splitEditorScroll,
                        setSplitEditorScroll,
                        'text-emerald-200/90'
                      )}
                      <div className="absolute left-0 top-0 bottom-0 w-10 py-2.5 bg-[#050608] border-r border-white/5 text-right pr-2 select-none pointer-events-none font-mono text-[9.5px] leading-[19.5px] text-slate-650 overflow-hidden">
                        {activeCodeText.split('\n').slice(0, 4000).map((_, i) => (
                          <div key={i}>{i + 1}</div>
                        ))}
                      </div>
                    </div>
                  </div>

                </div>
              </div>

              {/* Synchronous Minimap */}
              {showMinimap && renderMinimap(computeLineDiff(getDiffTexts().original.split('\n'), getDiffTexts().current.split('\n')).modifiedLines)}
            </div>
          ) : (
            // ==================== UNIFIED STACKED DIFF MODE ====================
            <div className="flex-1 flex overflow-hidden min-h-0 bg-[#050608]">
              <div className="flex-1 overflow-auto scrollbar-thin py-2 select-text">
                {computeLineDiff(getDiffTexts().original.split('\n'), getDiffTexts().current.split('\n')).unifiedLines.map((line, i) => {
                  const isAdded = line.type === 'added';
                  const isRemoved = line.type === 'removed';
                  
                  let lineBg = 'hover:bg-white/[0.01] border-l-2 border-transparent';
                  let textColor = 'text-slate-400';
                  let symbol = ' ';
                  let numText = '';

                  if (isAdded) {
                    lineBg = 'bg-[#22c55e]/10 border-l-2 border-[#22c55e]';
                    textColor = 'text-emerald-300';
                    symbol = '+';
                    numText = line.modifiedLineNumber ? `${line.modifiedLineNumber}` : '';
                  } else if (isRemoved) {
                    lineBg = 'bg-[#ef4444]/15 border-l-2 border-[#ef4444]';
                    textColor = 'text-red-300';
                    symbol = '-';
                    numText = line.originalLineNumber ? `${line.originalLineNumber}` : '';
                  } else {
                    numText = line.modifiedLineNumber ? `${line.modifiedLineNumber}` : `${line.originalLineNumber || ''}`;
                  }

                  return (
                    <div key={i} className={`flex h-[18px] items-center ${lineBg}`}>
                      <span className="select-none text-right pr-2.5 pl-2 w-10 shrink-0 text-slate-650 text-[9.5px]">
                        {numText}
                      </span>
                      <span className={`select-none w-4 text-center shrink-0 pr-1 text-[10px] font-black ${isAdded ? 'text-emerald-500' : isRemoved ? 'text-red-500' : 'text-slate-655'}`}>
                        {symbol}
                      </span>
                      <span
                        className={`flex-1 whitespace-pre pr-4 truncate ${textColor}`}
                        dangerouslySetInnerHTML={{ __html: highlightCode(line.value) || '&nbsp;' }}
                      />
                    </div>
                  );
                })}
              </div>

              {/* Unified Minimap */}
              {showMinimap && renderMinimap(computeLineDiff(getDiffTexts().original.split('\n'), getDiffTexts().current.split('\n')).unifiedLines)}
            </div>
          )
        ) : (
          // ==================== NORMAL WORKSPACE EDIT & DISPLAY ====================
          <div className="flex-1 flex overflow-hidden min-h-0">
            {isFileEditorActive ? (
              // EDITABLE INPUT FOR DIRECTORY FILES
              <div className="relative h-full w-full overflow-hidden flex flex-1 bg-[#050608]">
                <div className="flex-1 h-full relative overflow-auto scrollbar-thin">
                  <pre
                    aria-hidden="true"
                    className="absolute inset-0 p-4 whitespace-pre pt-3 pr-4 leading-relaxed font-mono text-xs select-none pointer-events-none text-transparent"
                    dangerouslySetInnerHTML={{ __html: highlightCode(editorContent) + '\n' }}
                  />
                  <textarea
                    value={editorContent}
                    onChange={e => handleEditorContentChange(e.target.value)}
                    spellCheck={false}
                    className="absolute inset-0 w-full h-full resize-none p-4 pt-3 pr-4 bg-transparent text-slate-300 caret-cyan-300 selection:bg-cyan-500/25 outline-none font-mono text-xs leading-relaxed whitespace-pre"
                    aria-label={`Editing ${activeEditorFile.name}`}
                  />
                </div>
                {/* Save status pill */}
                <div className="absolute bottom-3 right-4 px-2 py-1 rounded bg-[#0b0c13]/90 border border-white/5 text-[9px] text-slate-500 pointer-events-none select-none z-10 font-mono">
                  {editorSaveStatus === 'error' ? (
                    <span className="text-red-400 font-bold uppercase">{editorError}</span>
                  ) : editorSaveStatus === 'saving' ? (
                    <span className="text-cyan-400 animate-pulse">SAVING ON-DISK...</span>
                  ) : editorSaveStatus === 'saved' ? (
                    <span className="text-[#36e07a] font-bold">✔ DRAFT DEPLOYED TO BLUEPRINT</span>
                  ) : (
                    <span className="text-slate-500 lowercase">{activeEditorFile.path}</span>
                  )}
                </div>
              </div>
            ) : (
              // EDITABLE VIEWER FOR GENERATED XML TEMPLATES (MD, UI, NODE)
              <div className="relative h-full w-full overflow-hidden flex flex-1 bg-[#050608]">
                <div className="absolute left-0 top-0 bottom-0 w-11 py-3 bg-[#050608] border-r border-white/5 text-right pr-2 select-none pointer-events-none font-mono text-[9.5px] leading-[19.5px] text-slate-650 overflow-hidden">
                  {codeLines.slice(0, 4000).map((_, i) => (
                    <div key={i} className={lineDiagMap.has(i) ? (lineDiagMap.get(i)?.severity === 'error' ? 'text-red-400' : 'text-amber-300') : ''}>
                      {i + 1}
                    </div>
                  ))}
                </div>
                {renderHighlightedTextarea(
                  activeCodeText,
                  handleGeneratedDraftChange,
                  'Editing generated XML',
                  'py-3 pl-14 pr-12',
                  generatedEditorScroll,
                  setGeneratedEditorScroll
                )}
                <div className="absolute bottom-3 right-14 px-2 py-1 rounded bg-[#0b0c13]/90 border border-white/5 text-[9px] pointer-events-none select-none z-10 font-mono">
                  {generatedApplyStatus === 'error' ? (
                    <span className="text-red-400 font-bold uppercase">{generatedApplyMessage}</span>
                  ) : generatedApplyStatus === 'applying' ? (
                    <span className="text-cyan-400 animate-pulse">APPLYING XML...</span>
                  ) : generatedApplyStatus === 'applied' ? (
                    <span className="text-[#36e07a] font-bold">{generatedApplyMessage}</span>
                  ) : generatedDraftDirty ? (
                    <span className="text-amber-300 font-bold">DRAFT MODIFIED - APPLY TO WORKSPACE WHEN READY</span>
                  ) : (
                    <span className="text-slate-500 lowercase">generated XML is editable</span>
                  )}
                </div>
              </div>
            )}

            {/* Error indicators scroll-gutter */}
            {lineDiagMap.size > 0 && !effectiveDiffEnabled && (
              <div className="absolute top-0 right-1 w-2.5 h-full pointer-events-none z-10 selection:bg-transparent">
                {Array.from(lineDiagMap.entries()).map(([idx, info]) => (
                  <div
                    key={idx}
                    className={`absolute right-0 w-2 h-[3.5px] rounded-sm ${info.severity === 'error' ? 'bg-red-500' : 'bg-amber-400'}`}
                    style={{ top: `${(idx / Math.max(codeLines.length, 1)) * 100}%` }}
                  />
                ))}
              </div>
            )}

            {/* Render CSS Visual Code-Strips Minimap (auto-hidden in a narrow panel — G8b) */}
            {showMinimap && renderMinimap(codeLines.map(l => ({ value: l })))}
          </div>
        )}
      </div>

      {/* BOTTOM STATUS BAR — VS Code-style; file meta lives here now, not on the editor. */}
      <div className="bg-[#0b0d12] border-t border-white/5 px-4 py-1 flex items-center justify-between font-mono text-[9px] text-slate-500 select-none shrink-0">
        <div className="flex items-center gap-3">
          {effectiveDiffEnabled && !snapshotDiffWorkspace && (
            <div className="flex items-center gap-1.5">
              <span className="text-slate-600 uppercase text-[8px] font-extrabold tracking-wider">diff ref:</span>
              <select
                value={diffBaseType}
                onChange={(e) => setDiffBaseType(e.target.value as 'compile' | 'original')}
                className="bg-[#0c0d12] border border-white/10 text-[9px] text-slate-300 rounded px-1.5 py-0.5 outline-none font-mono focus:border-cyan-500/50 cursor-pointer"
              >
                <option value="compile">Last Compiled Build</option>
                <option value="original">Initial Loaded Template</option>
              </select>
            </div>
          )}
        </div>
        <div className="flex items-center gap-3">
          <span>UTF-8</span>
          <span className="text-slate-700">•</span>
          <span>{codeActiveTab === 'file' && activeEditorFile?.name.endsWith('.json') ? 'JSON' : 'XML / STRUCT'}</span>
          <span className="text-slate-700">•</span>
          <span>{diffEnabled ? 'DIFF_ACTIVE' : `LINES: ${codeLines.length}`}</span>
        </div>
      </div>
    </div>
  );
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * CueViewer — THE single cue tree for X4 Forge (consolidated 2026-06-12).
 *
 * Renders the Mission Director cue hierarchy from parent→sub-cue links and is
 * the one surface that NAVIGATES (click → select + focus on canvas, eye
 * toggles filter the graph), DIAGNOSES (structural lineage findings inline:
 * dead code, dangling refs, duplicates — engine: src/lib/cueLineage.ts), and
 * GOES LIVE (bind the running game's debuglog: fired cues glow, error cues
 * redden, attributed errors yield Live Fix cards — engines: logTelemetry +
 * liveFixes).
 *
 * History: this absorbs the former CueLineageTree.tsx (Doctor tab), which was
 * a second rendering of the same tree that knew how to judge but not navigate.
 * Ken's duplicate-surface catch; the Doctor now shows a one-line cue-health
 * summary that deep-links here.
 */

import React, { useEffect, useMemo, useRef, useState } from 'react';
import {
  GitCommit,
  ChevronRight,
  ChevronDown,
  Search,
  Eye,
  EyeOff,
  AlertTriangle,
  Activity,
  Radio,
  FileText
} from 'lucide-react';
import { ModWorkspace, MDNode } from '../types';
import { analyzeCueLineage } from '../lib/cueLineage';
import { parseLogTelemetry, type CueTelemetry } from '../lib/logTelemetry';
import { classifyLiveFixes, applyLiveFix, type LiveFix } from '../lib/liveFixes';

interface CueTreeNode {
  id: string;
  name: string;
  node: MDNode;
  children: CueTreeNode[];
}

interface CueViewerProps {
  workspace: ModWorkspace;
  selectedNode: MDNode | null;
  setSelectedNode: (node: MDNode | null) => void;
  setFocusNodeRequest: (req: { nodeId: string; timestamp: number } | null) => void;
  visibleCueIds: string[] | null;
  setVisibleCueIds: (ids: string[] | null) => void;
  /** Enables Live-Fix Apply (mechanical fixes run through the normal undo-able path). */
  setWorkspace?: React.Dispatch<React.SetStateAction<ModWorkspace>>;
}

export default function CueViewer({
  workspace,
  selectedNode,
  setSelectedNode,
  setFocusNodeRequest,
  visibleCueIds,
  setVisibleCueIds,
  setWorkspace
}: CueViewerProps) {
  const [searchQuery, setSearchQuery] = useState('');
  const [expandedPaths, setExpandedPaths] = useState<Record<string, boolean>>({});
  const [showFindings, setShowFindings] = useState(false);

  const allCues = useMemo(() => {
    return workspace.nodes.filter(node => node.type === 'cue');
  }, [workspace.nodes]);

  const rootCues = useMemo(() => {
    const subCueIds = new Set<string>();
    workspace.links.forEach(link => {
      if (link.targetPortId === 'in_flow' && link.sourcePortId === 'out_sub') {
        subCueIds.add(link.targetNodeId);
      }
    });
    return allCues.filter(cue => !subCueIds.has(cue.id));
  }, [allCues, workspace.links]);

  const cueTree = useMemo(() => {
    const buildTree = (cueNode: MDNode): CueTreeNode => {
      const childCueIds = workspace.links
        .filter(link => link.sourceNodeId === cueNode.id && link.sourcePortId === 'out_sub')
        .map(link => link.targetNodeId);
      const childrenNodes = allCues.filter(n => childCueIds.includes(n.id));
      return {
        id: cueNode.id,
        name: cueNode.properties?.name || cueNode.label,
        node: cueNode,
        children: childrenNodes.map(child => buildTree(child))
      };
    };
    return rootCues.map(root => buildTree(root));
  }, [rootCues, allCues, workspace.links]);

  // --- Structural lineage analysis (absorbed from CueLineageTree) ----------
  const lineage = useMemo(
    () => analyzeCueLineage(workspace.nodes || [], workspace.links || []),
    [workspace.nodes, workspace.links]
  );
  const findingsByCueId = useMemo(() => {
    const m = new Map<string, typeof lineage.findings>();
    for (const f of lineage.findings) {
      if (!f.cueId) continue;
      const arr = m.get(f.cueId) || [];
      arr.push(f);
      m.set(f.cueId, arr);
    }
    return m;
  }, [lineage.findings]);
  const errorCount = lineage.findings.filter(f => f.severity === 'error').length;
  const warnCount = lineage.findings.filter(f => f.severity === 'warning').length;

  // --- Live game-log binding (absorbed from CueLineageTree) ----------------
  // ONE log watcher app-wide: this subscribes to the same backend feed the
  // Playtest watcher uses (game-log/status → log-file-tail). The paste box is
  // an offline IMPORT for logs from other machines/sessions, not a watcher.
  const [liveMode, setLiveMode] = useState(false);
  const [liveTele, setLiveTele] = useState<Map<string, CueTelemetry> | null>(null);
  const [liveStatus, setLiveStatus] = useState('');
  const [liveEntries, setLiveEntries] = useState<any[]>([]);
  const [fixMsg, setFixMsg] = useState('');
  const [logText, setLogText] = useState('');
  const [showLog, setShowLog] = useState(false);
  const liveTick = useRef(0);

  useEffect(() => {
    if (!liveMode) { setLiveTele(null); setLiveStatus(''); setLiveEntries([]); setFixMsg(''); return; }
    let stopped = false;
    const poll = async () => {
      const tick = ++liveTick.current;
      try {
        const st = await fetch('/api/agent/game-log/status').then(r => r.json());
        const logPath = st && st.selectedLogPath;
        if (!logPath) {
          if (!stopped && tick === liveTick.current) {
            setLiveTele(null);
            setLiveStatus('no debuglog found — configure the X4 log path (see the Playtest watcher)');
          }
          return;
        }
        const cueNames = allCues.map(c => String(c.properties?.name || '')).filter(Boolean);
        const tail = await fetch('/api/agent/log-file-tail', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ path: logPath, cueNames })
        }).then(r => r.json());
        if (stopped || tick !== liveTick.current) return;
        if (tail.success && tail.telemetry) {
          setLiveTele(new Map((tail.telemetry.cues || []).map((c: CueTelemetry) => [c.name, c])));
          setLiveEntries(tail.telemetry.entries || []);
          setLiveStatus('live · ' + String(logPath).split(/[\\/]/).pop() + ' · ' + ((tail.telemetry.entries || []).length) + ' recent entries');
        } else {
          setLiveStatus(tail.error || 'tail failed');
        }
      } catch (e: any) {
        if (!stopped) setLiveStatus('feed unavailable: ' + String((e && e.message) || e));
      }
    };
    poll();
    const t = window.setInterval(poll, 10000);
    return () => { stopped = true; window.clearInterval(t); };
  }, [liveMode, allCues]);

  const pastedTele = useMemo(() => {
    if (!logText.trim()) return new Map<string, CueTelemetry>();
    const t = parseLogTelemetry(logText, allCues.map(c => String(c.properties?.name || '')).filter(Boolean));
    return new Map(t.cues.map(c => [c.name, c]));
  }, [logText, allCues]);
  const cueTele = liveMode && liveTele ? liveTele : pastedTele;

  // --- T5 Live Fix cards (absorbed) ----------------------------------------
  const liveFixes = useMemo<LiveFix[]>(
    () => (liveMode && liveEntries.length ? classifyLiveFixes(liveEntries, workspace) : []),
    [liveMode, liveEntries, workspace]
  );

  const handleApplyFix = (fix: LiveFix) => {
    if (!setWorkspace) return;
    try {
      setWorkspace(prev => applyLiveFix(prev, fix));
      setFixMsg(`Applied: ${fix.apply?.propertyKey} → ${fix.apply?.newValue}. Deploy, then run /refreshmd in-game to re-test live.`);
    } catch (e: any) {
      setFixMsg(`Apply failed: ${e?.message || e}`);
    }
  };

  const handleDeployForRefresh = async () => {
    setFixMsg('Deploying current workspace…');
    try {
      const r = await fetch('/api/agent/deploy', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({}) });
      const d = await r.json();
      setFixMsg(d.success
        ? 'Deployed. In game: Enter (chat) → type /refreshmd → Enter. The glow above shows the result live.'
        : `Deploy failed: ${d.error || r.status}`);
    } catch (e: any) {
      setFixMsg(`Deploy failed: ${e?.message || e}`);
    }
  };

  const handleJumpToNode = (nodeId?: string) => {
    if (!nodeId) return;
    const node = workspace.nodes.find(n => n.id === nodeId);
    if (node) {
      setSelectedNode(node);
      setFocusNodeRequest({ nodeId: node.id, timestamp: Date.now() });
    }
  };

  // --- original CueViewer mechanics ----------------------------------------
  const activeVisibleSet = useMemo(() => {
    if (visibleCueIds === null) {
      return new Set<string>(allCues.map(c => c.id));
    }
    return new Set<string>(visibleCueIds);
  }, [visibleCueIds, allCues]);

  const toggleFolder = (id: string) => {
    setExpandedPaths(prev => ({ ...prev, [id]: !prev[id] }));
  };

  const getDescendantIds = (node: CueTreeNode): string[] => {
    let ids: string[] = [node.id];
    node.children.forEach(child => { ids = [...ids, ...getDescendantIds(child)]; });
    return ids;
  };

  const handleToggleCueVisibility = (treeNode: CueTreeNode, e: React.MouseEvent) => {
    e.stopPropagation();
    const targetIds = getDescendantIds(treeNode);
    const isCurrentlyChecked = activeVisibleSet.has(treeNode.id);
    let nextVisibleList: string[] | null = null;
    if (isCurrentlyChecked) {
      const nextSet = new Set<string>(activeVisibleSet);
      targetIds.forEach(id => nextSet.delete(id));
      nextVisibleList = Array.from(nextSet);
    } else {
      const nextSet = new Set<string>(activeVisibleSet);
      targetIds.forEach(id => nextSet.add(id));
      nextVisibleList = Array.from(nextSet);
    }
    if (nextVisibleList.length === allCues.length) {
      setVisibleCueIds(null);
    } else {
      setVisibleCueIds(nextVisibleList);
    }
  };

  const handleSelectAll = () => setVisibleCueIds(null);
  const handleClearAll = () => setVisibleCueIds([]);

  const handleFocusCue = (cueNode: MDNode) => {
    setSelectedNode(cueNode);
    setFocusNodeRequest({ nodeId: cueNode.id, timestamp: Date.now() });
  };

  const filteredTree = useMemo(() => {
    if (!searchQuery) return cueTree;
    const lcQuery = searchQuery.toLowerCase();
    const filterNode = (node: CueTreeNode): CueTreeNode | null => {
      const selfMatches = node.name.toLowerCase().includes(lcQuery);
      const filteredChildren = node.children
        .map(child => filterNode(child))
        .filter((child): child is CueTreeNode => child !== null);
      if (selfMatches || filteredChildren.length > 0) {
        return { ...node, children: filteredChildren };
      }
      return null;
    };
    return cueTree.map(root => filterNode(root)).filter((root): root is CueTreeNode => root !== null);
  }, [cueTree, searchQuery]);

  const renderCueNode = (node: CueTreeNode, depth = 0) => {
    const isParent = node.children.length > 0;
    const isExpanded = expandedPaths[node.id] ?? true;
    const isActive = selectedNode?.id === node.id;
    const isChecked = activeVisibleSet.has(node.id);
    const initialState = node.node.properties?.state || 'active';
    const isInstantiated = node.node.properties?.instantiate === 'true';

    // health + live state for THIS cue
    const cueFindings = findingsByCueId.get(node.id) || [];
    const hasError = cueFindings.some(f => f.severity === 'error');
    const hasWarn = !hasError && cueFindings.length > 0;
    const tele = node.name ? cueTele.get(node.name) : undefined;
    const liveTint = tele
      ? (tele.errors > 0 ? 'border-l-2 border-red-500 bg-red-500/5' : 'border-l-2 border-emerald-500 bg-emerald-500/5')
      : '';

    return (
      <div key={node.id} style={{ paddingLeft: `${depth * 6}px` }}>
        <div
          className={`group flex items-center gap-1 py-0.5 px-1.5 rounded text-left transition-all font-mono text-[10.5px] border border-transparent select-none my-0.5 ${liveTint} ${
            isActive
              ? 'bg-purple-950/30 text-purple-300 border-purple-500/25 font-bold'
              : 'text-slate-200 hover:text-white hover:bg-white/[0.02]'
          }`}
        >
          <span className="shrink-0">
            {isParent ? (
              <button
                onClick={() => toggleFolder(node.id)}
                className="p-0.5 rounded hover:bg-white/10 text-slate-500 hover:text-slate-350 cursor-pointer"
              >
                {isExpanded ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
              </button>
            ) : (
              <div className="w-4 h-4 flex items-center justify-center">
                <span className="w-1 h-1 rounded-full bg-slate-650" />
              </div>
            )}
          </span>

          <button
            onClick={(e) => handleToggleCueVisibility(node, e)}
            className={`p-0.5 rounded shrink-0 transition-colors cursor-pointer ${
              isChecked
                ? 'text-cyan-400 hover:text-cyan-200 hover:bg-cyan-500/10'
                : 'text-slate-600 hover:text-slate-400 hover:bg-white/5'
            }`}
            title={isChecked ? 'Hide cue and descendants from canvas' : 'Show cue and descendants on canvas'}
          >
            {isChecked ? <Eye className="w-3.5 h-3.5 shrink-0" /> : <EyeOff className="w-3.5 h-3.5 shrink-0" />}
          </button>

          <GitCommit className={`w-3.5 h-3.5 shrink-0 ${isChecked ? 'text-purple-400' : 'text-slate-650'}`} />

          <button
            onClick={() => handleFocusCue(node.node)}
            className="flex-1 text-left truncate cursor-pointer pl-0.5 min-w-0"
            title={`Focus cue & dependencies: ${node.name}`}
          >
            <span className={`truncate font-semibold ${isChecked ? '' : 'text-slate-500 line-through decoration-slate-700'}`}>{node.name}</span>
            <span className="block text-[8px] text-slate-500 font-mono scale-95 origin-left truncate leading-tight">
              {initialState} {isInstantiated && '• dynamic'}
              {tele && <span className={tele.errors > 0 ? 'text-red-400' : 'text-emerald-400'}> • live ×{tele.hits}{tele.errors > 0 ? ` (${tele.errors} err)` : ''}</span>}
            </span>
          </button>

          {(hasError || hasWarn) && (
            <span
              className="shrink-0 cursor-help"
              title={cueFindings.map(f => `[${f.severity}] ${f.message}`).join('\n')}
            >
              <AlertTriangle className={`w-3 h-3 ${hasError ? 'text-red-400' : 'text-amber-400'}`} />
            </span>
          )}
        </div>

        {isParent && isExpanded && (
          <div className="border-l border-white/5 ml-2 my-0.5 space-y-0.5">
            {node.children.map(child => renderCueNode(child, depth + 1))}
          </div>
        )}
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full bg-transparent text-[#e0e0e0] overflow-hidden select-none font-sans">
      <div className="p-3 border-b border-white/5 shrink-0 space-y-2 bg-transparent">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-1 bg-black/20 p-0.5 rounded border border-white/5">
            <button
              onClick={handleSelectAll}
              className="p-1 px-1.5 rounded hover:bg-white/5 text-cyan-400 hover:text-cyan-200 transition-all text-[9px] font-mono font-bold cursor-pointer"
              title="Show all cues and elements"
            >
              SHOW ALL
            </button>
            <span className="text-white/10 text-[9px] font-mono px-0.5">|</span>
            <button
              onClick={handleClearAll}
              className="p-1 px-1.5 rounded hover:bg-white/5 text-slate-400 hover:text-red-400 transition-all text-[9px] font-mono font-bold cursor-pointer"
              title="Hide all cues from canvas"
            >
              CLEAR ALL
            </button>
          </div>
          <div className="flex items-center gap-1.5">
            {(errorCount > 0 || warnCount > 0) && (
              <button
                onClick={() => setShowFindings(v => !v)}
                className={`text-[9px] px-1.5 py-0.5 rounded border font-bold font-mono cursor-pointer ${
                  errorCount > 0
                    ? 'bg-red-950/40 text-red-300 border-red-500/25'
                    : 'bg-amber-950/40 text-amber-300 border-amber-500/25'
                }`}
                title="Structural lineage findings — click to expand"
              >
                {errorCount > 0 ? `${errorCount} ⛔` : ''}{errorCount > 0 && warnCount > 0 ? ' ' : ''}{warnCount > 0 ? `${warnCount} ⚠` : ''}
              </button>
            )}
            <div className="text-[9px] bg-cyan-950/40 text-cyan-400 px-1.5 py-0.5 rounded border border-cyan-500/20 font-bold font-mono">
              {visibleCueIds === null ? `${allCues.length} Cues` : `${visibleCueIds.length}/${allCues.length} Visible`}
            </div>
          </div>
        </div>

        {showFindings && lineage.findings.length > 0 && (
          <div className="space-y-1 max-h-36 overflow-y-auto scrollbar-thin">
            {lineage.findings.map((f, i) => (
              <button
                key={i}
                onClick={() => handleJumpToNode(f.cueId || (f as any).nodeId)}
                className={`w-full text-left text-[9px] font-sans leading-snug p-1.5 rounded border cursor-pointer hover:bg-white/5 ${
                  f.severity === 'error' ? 'bg-red-500/5 border-red-500/20 text-red-300' : 'bg-amber-500/5 border-amber-500/25 text-amber-300'
                }`}
                title="Jump to the offending cue/node"
              >
                [{f.severity}] {f.message}
              </button>
            ))}
          </div>
        )}

        <div className="relative">
          <Search className="absolute left-2.5 top-2.5 w-3 h-3 text-slate-500" />
          <input
            type="text"
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
            placeholder="Search Cues..."
            className="w-full pl-7 pr-2 py-1.5 rounded bg-black/40 border border-white/5 text-[10.5px] text-white placeholder-slate-500 focus:outline-none focus:border-purple-500 transition-colors font-mono"
          />
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-2 custom-scrollbar bg-transparent scrollbar-thin">
        {filteredTree.length === 0 ? (
          <div className="text-center py-8 text-[10px] font-mono text-slate-500 leading-normal">
            {allCues.length === 0
              ? 'No script cues identified in active blueprint.'
              : 'No cues matched query criteria'}
          </div>
        ) : (
          <div className="space-y-0.5">
            {filteredTree.map(rootItem => renderCueNode(rootItem))}
          </div>
        )}
      </div>

      {/* Live game-log binding + Live Fix cards (the app's ONE log consumer UI besides Playtest) */}
      <div className="p-2 border-t border-white/5 bg-[#17191e]/50 shrink-0 space-y-1.5">
        <div className="flex items-center gap-3 flex-wrap">
          <button
            onClick={() => setLiveMode(v => !v)}
            title="Watch the live X4 debuglog — the same feed the Playtest watcher uses — and light up cues in real time"
            className={`flex items-center gap-1 text-[9px] font-bold uppercase cursor-pointer ${liveMode ? 'text-emerald-300' : 'text-slate-400 hover:text-emerald-300'}`}
          >
            <Radio className={`w-3 h-3 ${liveMode ? 'animate-pulse' : ''}`} />{liveMode ? 'Live: ON' : 'Bind live game log'}
          </button>
          <button
            onClick={() => setShowLog(v => !v)}
            className="flex items-center gap-1 text-[9px] font-bold uppercase text-violet-300 hover:text-violet-200 cursor-pointer"
          >
            <Activity className="w-3 h-3" />{showLog ? 'Hide' : 'Import'} offline log{!liveMode && pastedTele.size > 0 ? ` (${pastedTele.size} lit)` : ''}
          </button>
        </div>
        {liveMode && (
          <div className="text-[8.5px] font-mono text-slate-500 truncate" title={liveStatus}>
            {liveStatus || 'connecting to debuglog feed…'}
          </div>
        )}
        {liveMode && liveFixes.length > 0 && (
          <div className="space-y-1.5">
            <div className="text-[8.5px] font-bold uppercase text-red-300 tracking-wider">
              Live fixes — {liveFixes.length} attributed error{liveFixes.length > 1 ? 's' : ''}
            </div>
            {liveFixes.slice(0, 6).map(fix => (
              <div key={fix.id} className="rounded border border-red-500/20 bg-red-500/5 p-1.5 space-y-1">
                <div className="flex items-center gap-1.5 flex-wrap">
                  <span className="text-[7.5px] font-bold uppercase text-red-300 bg-red-500/10 border border-red-500/25 rounded px-1 py-0.5">{fix.fixKind.replace('_', ' ')}</span>
                  {fix.cueName && <span className="text-[8px] font-mono text-slate-400">{fix.cueName}</span>}
                  {fix.sourceRef && (
                    <button
                      onClick={() => handleJumpToNode(fix.sourceRef!.id)}
                      className="text-[8px] font-bold text-cyan-300 hover:text-cyan-200 uppercase cursor-pointer"
                    >
                      Jump →
                    </button>
                  )}
                  {fix.autoApplicable && setWorkspace && (
                    <button
                      onClick={() => handleApplyFix(fix)}
                      className="text-[8px] font-bold text-emerald-300 hover:text-emerald-200 uppercase ml-auto cursor-pointer"
                    >
                      Apply fix
                    </button>
                  )}
                </div>
                <div className="text-[8.5px] text-slate-300 font-sans leading-snug">{fix.suggestion}</div>
                <div className="text-[8px] text-slate-500 font-mono truncate" title={fix.logLine}>{fix.logLine}</div>
              </div>
            ))}
            <div className="flex items-center gap-2">
              <button
                onClick={handleDeployForRefresh}
                className="text-[8.5px] font-bold uppercase text-fuchsia-300 hover:text-fuchsia-200 cursor-pointer"
              >
                Deploy for /refreshmd
              </button>
              {fixMsg && <span className="text-[8px] font-sans text-slate-400 leading-snug">{fixMsg}</span>}
            </div>
          </div>
        )}
        {liveMode && liveFixes.length === 0 && fixMsg && (
          <div className="text-[8px] font-sans text-slate-400">{fixMsg}</div>
        )}
        {showLog && (
          <div className="space-y-1">
            <textarea
              value={logText}
              onChange={e => setLogText(e.target.value)}
              spellCheck={false}
              placeholder={'Paste X4 debug-log text. Lines naming a cue (or [MDStudio] cue=<Name>) light it up; errors turn it red.'}
              className="w-full h-20 p-2 rounded bg-black/60 border border-white/10 text-slate-300 font-mono text-[10px] leading-snug outline-none resize-y"
            />
            <div className="flex items-center gap-2">
              <label className="text-[9px] text-cyan-400 hover:text-cyan-300 cursor-pointer flex items-center gap-1">
                <FileText className="w-3 h-3" />Load .log file
                <input type="file" accept=".log,.txt" className="hidden" onChange={e => { const fl = e.target.files?.[0]; if (fl) { const rd = new FileReader(); rd.onload = () => setLogText(String(rd.result || '')); rd.readAsText(fl); } }} />
              </label>
              {logText && <button onClick={() => setLogText('')} className="text-[9px] text-slate-500 hover:text-red-400 cursor-pointer">clear</button>}
            </div>
          </div>
        )}
        {!liveMode && !showLog && (
          <span className="block truncate font-mono text-[8.5px] text-slate-500">👁 Toggle eye to filter · click name to pan · ⚠ hover for findings</span>
        )}
      </div>
    </div>
  );
}

