    const repoName = gitRepo.trim() || toRepoName(workspace.name);
    setCreatingRepo(true);
    setTerminalLogs([]);
    addLog(`Creating new GitHub repository "${repoName}"...`);
    try {
      const res = await fetch('/api/github/create', {
        method: 'POST',
