-- Target Path: /ui/addon_menu.lua
-- Binds widgets defined visually inside HUD Layout Configurator to game actions

local menu = {
  name = "${workspace.name || "Custom_HUD"}",
  version = "${workspace.version || "1.0.0"}",
  widgets = {}
