/* ============================================================================ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * Structural integrity + each composite compiles clean when wrapped in a cue.
 * ============================================================================ */
export function runCompositeBlocksSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  for (const c of COMPOSITE_BLOCKS) {
    const { nodes, links } = c.build('seed1', 100, 100);
    const ids = nodes.map((n) => n.id as string);
    const idSet = new Set(ids);
    ok(`${c.id}_unique_ids`, ids.length === idSet.size && ids.every((id) => id.startsWith('seed1')), ids);
    ok(`${c.id}_links_internal`, links.every((l) => idSet.has(l.sourceNodeId) && idSet.has(l.targetNodeId)), links.map((l) => `${l.sourceNodeId}->${l.targetNodeId}`));
    ok(`${c.id}_entry_exists`, idSet.has(c.entryId('seed1')));

    // Compile-clean: wrap action composites under a cue; cue-composites stand alone.
    const isCueComposite = nodes.some((n) => n.type === 'cue');
    let wsNodes = nodes;
    let wsLinks = links;
    if (!isCueComposite) {
      wsNodes = [N('host_cue', 'cue', 'cue', 0, 0, { name: 'Host' }), ...nodes];
      wsLinks = [L('host_cue', 'out_act', c.entryId('seed1'), 'in_act'), ...links];
    }
    try {
      const ws = sanitizeWorkspace({ name: 'CompTest', nodes: wsNodes, links: wsLinks, uiWidgets: [] } as Partial<ModWorkspace>);
      const xml = generateMDXML(ws);
      const errors = validateModWorkspace(ws, xml).filter((d) => d.severity === 'error');
      ok(`${c.id}_compiles_clean`, errors.length === 0, errors.map((e) => e.message));
      if (c.id === 'file_bridge_poll') {
        ok('file_bridge_poll_writes_request', xml.includes('<debug_to_file') && xml.includes(`send_prompt_request.json`));
        ok('file_bridge_poll_has_timeout', xml.includes('player.age + 10s') && xml.includes(`'x4forge_bridge.send_prompt.timeout'`));
        ok('file_bridge_poll_uses_contract_event_name', xml.includes(`'x4forge_bridge.send_prompt.poll'`));
      }
    } catch (e: any) {
      ok(`${c.id}_compiles_clean`, false, 'threw: ' + (e?.message || e));
    }
  }

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, pass: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Lever 2 — external-integration / contract seam.
 *
 * A class of advanced X4 mods talks to an EXTERNAL local process over HTTP, via a
 * Lua HTTP client running inside the game. The studio's job is NOT to author that
 * external process — it owns the X4 side and the *contract* between them. This module
 * models the X4 <-> external HTTP/JSON contract as a first-class, validated artifact
 * and generates the glue Lua that runs inside X4:
 *
 *   MD  --(raise_lua_event "<ns>.<id>")-->  Lua glue  --(async HTTP)-->  external process
 *   MD  <--(AddUITriggeredEvent "<ns>.<id>.response")-- Lua glue  <--(JSON response)--
 *
 * The generated Lua is library-agnostic: the HTTP client is referenced by a
 * configurable expression (e.g. a non-blocking, callback-based client like the
 * community djfhe_http mod, or any other), so the studio never hard-codes a runtime.
 */

import { endpointEventNames } from './contractEvents';
import { buildActionWhitelistLua, buildFileBridgePollingSubgraph, validateFileBridgePollingOptions } from './fileBridgeTransport';
export { endpointEventNames } from './contractEvents';

export type ContractFieldType = 'string' | 'number' | 'boolean' | 'object' | 'array';
export type ContractMethod = 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';

export interface ContractField {
  name: string;
  type: ContractFieldType;
  required?: boolean;
  description?: string;
}

export interface ContractEndpoint {
  /** Stable identifier; used to derive Lua event names. Lowercase + underscores. */
  id: string;
  /**
   * 'http' (default): MD raises an event, the glue Lua calls the external process.
   * 'ui_event' (T4.3): an in-game Lua UI widget calls Glue.<id>(payload); the glue
   * type-guards the payload and forwards it to MD via AddUITriggeredEvent — the
   * SAME contract seam pointed at the widget→cue case (no external process).
   * 'file_bridge' (P1): MD writes a request file and polls through a bounded
   * bridge event path. The action id stays whitelisted in generated Lua.
   */
  kind?: 'http' | 'ui_event' | 'file_bridge';
  method?: ContractMethod;
  /** Path appended to baseUrl, e.g. "/v1/status". Must start with "/". */
  path?: string;
  description?: string;
  /** JSON request-body fields (for POST/PUT/PATCH). */
  request?: ContractField[];
  /** Expected JSON response fields (documentation + future response validation). */
  response?: ContractField[];
  fileBridge?: {
    directory?: string;
    requestFile?: string;
    responseFile?: string;
    pollInterval?: string;
    timeout?: string;
  };
}

export interface IntegrationContract {
  /**
   * Event namespace / mod-facing prefix, e.g. "myai". Lua event names are
   * "<namespace>.<endpoint.id>" (request, MD->Lua) and
   * "<namespace>.<endpoint.id>.response" / ".error" (Lua->MD).
   */
  namespace: string;
  /** Base URL of the external process, e.g. "http://127.0.0.1:8713". */
  baseUrl: string;
  /**
   * Lua expression that resolves to the async HTTP client. Library-agnostic and
   * configurable so the studio never hard-codes a runtime. The client is expected to
   * expose `request({ method, url, body, headers }, function(err, response) ... end)`.
   */
  httpClientExpr?: string;
  /** Lua expression that resolves to a JSON lib exposing `encode`/`decode`. */
  jsonLibExpr?: string;
  endpoints: ContractEndpoint[];
}

export interface ContractFinding {
  severity: 'error' | 'warning';
  endpointId?: string;
  message: string;
}

const ID_RE = /^[a-z][a-z0-9_]*$/;
const NS_RE = /^[a-z][a-z0-9_]*$/;
const METHODS: ContractMethod[] = ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'];
const FIELD_TYPES: ContractFieldType[] = ['string', 'number', 'boolean', 'object', 'array'];

function fileBridgeDefaults(ep: ContractEndpoint) {
  return {
    directory: ep.fileBridge?.directory || 'x4_forge_bridge',
    requestFile: ep.fileBridge?.requestFile || `${ep.id || 'endpoint'}_request.json`,
    responseFile: ep.fileBridge?.responseFile || `${ep.id || 'endpoint'}_response.json`,
    pollInterval: ep.fileBridge?.pollInterval || '1s',
    timeout: ep.fileBridge?.timeout || '10s',
  };
}

function mdPayloadExpr(ep: ContractEndpoint): string {
  const req = ep.request || [];
  const fields = [`action='${ep.id}'`, ...req.map(fld => `${fld.name}=$${fld.name}`)];
  return `table[${fields.join(', ')}]`;
}

/**
 * Validate a contract so neither end can drift. Returns findings (errors block
 * generation; warnings are advisory). An empty array means the contract is clean.
 */
export function validateContract(contract: IntegrationContract): ContractFinding[] {
  const findings: ContractFinding[] = [];
  if (!contract || typeof contract !== 'object') {
    return [{ severity: 'error', message: 'Contract is missing or not an object.' }];
  }

  if (!contract.namespace || !NS_RE.test(contract.namespace)) {
    findings.push({ severity: 'error', message: `namespace "${contract.namespace ?? ''}" must match ${NS_RE} (lowercase, starts with a letter).` });
  }
  const endpoints = Array.isArray(contract.endpoints) ? contract.endpoints : [];
  // Non-HTTP endpoints live entirely in-game or through local file exchange;
  // baseUrl only matters when at least one endpoint actually goes over HTTP.
  const hasHttp = endpoints.some(ep => ep && (ep.kind || 'http') === 'http');
  if (hasHttp) {
    if (!contract.baseUrl || !/^https?:\/\/.+/i.test(contract.baseUrl)) {
      findings.push({ severity: 'error', message: `baseUrl "${contract.baseUrl ?? ''}" must be an http(s) URL.` });
    } else if (!/^https?:\/\/(127\.0\.0\.1|localhost|0\.0\.0\.0|\[::1\])(:\d+)?/i.test(contract.baseUrl)) {
      findings.push({ severity: 'warning', message: `baseUrl "${contract.baseUrl}" is not a localhost address; external-integration mods normally talk to a *local* process.` });
    }
  }
  if (endpoints.length === 0) {
    findings.push({ severity: 'error', message: 'Contract has no endpoints.' });
  }

  const seen = new Set<string>();
  for (const ep of endpoints) {
    if (!ep || typeof ep !== 'object') {
      findings.push({ severity: 'error', message: 'An endpoint entry is missing or not an object.' });
      continue;
    }
    if (!ep.id || !ID_RE.test(ep.id)) {
      findings.push({ severity: 'error', endpointId: ep.id, message: `endpoint id "${ep.id ?? ''}" must match ${ID_RE}.` });
    } else if (seen.has(ep.id)) {
      findings.push({ severity: 'error', endpointId: ep.id, message: `duplicate endpoint id "${ep.id}".` });
    } else {
      seen.add(ep.id);
    }
    const kind = ep.kind || 'http';
    if (kind !== 'http' && kind !== 'ui_event' && kind !== 'file_bridge') {
      findings.push({ severity: 'error', endpointId: ep.id, message: `endpoint "${ep.id}" has invalid kind "${String(ep.kind)}".` });
    }
    if (kind === 'http') {
      if (!METHODS.includes(ep.method as ContractMethod)) {
        findings.push({ severity: 'error', endpointId: ep.id, message: `endpoint "${ep.id}" has invalid method "${ep.method}".` });
      }
      if (!ep.path || !ep.path.startsWith('/')) {
        findings.push({ severity: 'error', endpointId: ep.id, message: `endpoint "${ep.id}" path "${ep.path ?? ''}" must start with "/".` });
      }
    } else if (ep.method || ep.path) {
      findings.push({ severity: 'warning', endpointId: ep.id, message: `endpoint "${ep.id}" is a ${kind}; method/path are ignored.` });
    }
    if (kind === 'file_bridge' && ID_RE.test(ep.id || '')) {
      const fb = fileBridgeDefaults(ep);
      for (const message of validateFileBridgePollingOptions({
        namespace: contract.namespace || 'invalid',
        actionId: ep.id,
        directory: fb.directory,
        requestFile: fb.requestFile,
        responseFile: fb.responseFile,
        requestPayloadExpr: mdPayloadExpr(ep),
        pollInterval: fb.pollInterval,
        timeout: fb.timeout,
      })) {
        findings.push({ severity: 'error', endpointId: ep.id, message });
      }
    }
    const bodyMethods: ContractMethod[] = ['POST', 'PUT', 'PATCH'];
    if (kind === 'http' && ep.request && ep.request.length > 0 && !bodyMethods.includes(ep.method as ContractMethod)) {
      findings.push({ severity: 'warning', endpointId: ep.id, message: `endpoint "${ep.id}" is ${ep.method} but declares a request body; ${ep.method} bodies are usually ignored.` });
    }
    for (const f of [...(ep.request || []), ...(ep.response || [])]) {
      if (!f.name) findings.push({ severity: 'error', endpointId: ep.id, message: `endpoint "${ep.id}" has a field with no name.` });
      if (!FIELD_TYPES.includes(f.type)) findings.push({ severity: 'error', endpointId: ep.id, message: `endpoint "${ep.id}" field "${f.name}" has invalid type "${f.type}".` });
    }
  }
  return findings;
}

function luaComment(s: string): string {
  return String(s).replace(/\r?\n/g, ' ').replace(/--\[\[|\]\]/g, '');
}

/**
 * Generate the X4-side glue Lua for a contract. Throws if the contract has errors
 * (call validateContract first to surface them in the UI).
 */
export function generateHttpGlueLua(contract: IntegrationContract): string {
  const errors = validateContract(contract).filter(f => f.severity === 'error');
  if (errors.length > 0) {
    throw new Error(`Cannot generate glue Lua: ${errors.length} contract error(s): ${errors.map(e => e.message).join('; ')}`);
  }

  const ns = contract.namespace;
  const httpClient = contract.httpClientExpr || 'require("extensions.sn_mod_support_apis.lua.simple_http")';
  const jsonLib = contract.jsonLibExpr || 'require("json")';
  const bodyMethods: ContractMethod[] = ['POST', 'PUT', 'PATCH'];

  const header = [
    `-- Auto-generated by X4:MD Studio — HTTP integration glue for "${ns}"`,
    `-- Contract: ${contract.endpoints.length} endpoint(s) against ${contract.baseUrl}`,
    `-- This is the X4-side glue ONLY; the external process is out of the studio's scope.`,
    `-- MD -> Lua:  raise_lua_event name="${ns}.<id>"  (param = request table)`,
    `-- Lua -> MD:  event "${ns}.<id>.response" (decoded body) | "${ns}.<id>.error" (message)`,
    ''
  ].join('\n');

  const preamble = [
    `local http = ${httpClient}`,
    `local json = ${jsonLib}`,
    '',
    `local Glue = {}`,
    `local BASE_URL = ${JSON.stringify(contract.baseUrl)}`,
    `local NS = ${JSON.stringify(ns)}`,
    ''
  ].join('\n');

  const fns: string[] = [];
  const registrations: string[] = [];
  const fileBridgeEndpoints = contract.endpoints.filter(ep => (ep.kind || 'http') === 'file_bridge');
  if (fileBridgeEndpoints.length > 0) {
    fns.push(buildActionWhitelistLua({ namespace: ns, actions: fileBridgeEndpoints.map(ep => ep.id) }));
    fns.push('');
  }

  const luaTypeOf = (t: ContractFieldType): string =>
    t === 'number' ? 'number' : t === 'boolean' ? 'boolean' : (t === 'object' || t === 'array') ? 'table' : 'string';

  for (const ep of contract.endpoints) {
    const ev = endpointEventNames(ns, ep.id);

    if ((ep.kind || 'http') === 'ui_event') {
      // T4.3 — in-game UI widget → MD cue bridge: no HTTP involved. The widget's
      // Lua calls Glue.<id>(payload); the glue type-guards the declared fields
      // and forwards the table to MD via AddUITriggeredEvent (event_ui_triggered).
      const fields = ep.request || [];
      const guards: string[] = [`    payload = payload or {}`];
      for (const f of fields) {
        if (f.required) {
          guards.push(`    if payload[${JSON.stringify(f.name)}] == nil then DebugError(${JSON.stringify(`[${ns}] ${ep.id}: missing required field '${f.name}'`)}); return end`);
        }
        guards.push(`    if payload[${JSON.stringify(f.name)}] ~= nil and type(payload[${JSON.stringify(f.name)}]) ~= ${JSON.stringify(luaTypeOf(f.type))} then DebugError(${JSON.stringify(`[${ns}] ${ep.id}: field '${f.name}' must be ${luaTypeOf(f.type)}`)}); return end`);
      }
      fns.push([
        `-- ${ep.id}: ui_event${ep.description ? ` — ${luaComment(ep.description)}` : ''} (widget → MD, no HTTP)`,
        `function Glue.${ep.id}(payload)`,
        ...guards,
        `    AddUITriggeredEvent(NS, ${JSON.stringify(ep.id)}, payload)`,
        `end`,
        ``,
        `-- Other Lua (or MD via raise_lua_event "${ev.request}") can trigger it too.`,
        `RegisterEvent(${JSON.stringify(ev.request)}, function(_, param)`,
        `    Glue.${ep.id}(param)`,
        `end)`,
        ``
      ].join('\n'));
      registrations.push(ev.request);
      continue;
    }

    if ((ep.kind || 'http') === 'file_bridge') {
      fns.push([
        `-- ${ep.id}: file_bridge${ep.description ? ` — ${luaComment(ep.description)}` : ''} (MD writes request file, Lua/runtime polls response)`,
        `function Glue.${ep.id}_poll(payload)`,
        `    payload = payload or {}`,
        `    if not isAllowedAction(payload.action or ${JSON.stringify(ep.id)}) then DebugError(${JSON.stringify(`[${ns}] ${ep.id}: blocked file-bridge action`)}); return end`,
        `    AddUITriggeredEvent(NS, ${JSON.stringify(`${ep.id}.poll`)}, payload)`,
        `end`,
        ``,
        `function Glue.${ep.id}_timeout(message)`,
        `    AddUITriggeredEvent(NS, ${JSON.stringify(`${ep.id}.error`)}, tostring(message or "file bridge timeout"))`,
        `end`,
        ``,
        `RegisterEvent(${JSON.stringify(`${ev.request}.poll`)}, function(_, param)`,
        `    Glue.${ep.id}_poll(param)`,
        `end)`,
        `RegisterEvent(${JSON.stringify(`${ev.request}.timeout`)}, function(_, param)`,
        `    Glue.${ep.id}_timeout(param)`,
        `end)`,
        ``
      ].join('\n'));
      registrations.push(`${ev.request}.poll`, `${ev.request}.timeout`);
      continue;
    }

    const sendsBody = bodyMethods.includes(ep.method as ContractMethod);
    const requiredFields = (ep.request || []).filter(f => f.required).map(f => f.name);

    const validationLines = requiredFields.length > 0
      ? [
          `    payload = payload or {}`,
          ...requiredFields.map(name =>
            `    if payload[${JSON.stringify(name)}] == nil then AddUITriggeredEvent(NS, ${JSON.stringify(`${ep.id}.error`)}, "missing required field: ${name}"); return end`)
        ]
      : [`    payload = payload or {}`];

    const responseFields = (ep.response || []).map(fld => fld.name).filter(Boolean);
    const responseCheckLines = responseFields.length > 0
      ? [
          `        if ok and type(decoded) == "table" then`,
          ...responseFields.map(name =>
            `            if decoded[${JSON.stringify(name)}] == nil then DebugError(${JSON.stringify(`[${ns}] ${ep.id}: response missing field '${name}'`)}) end`),
          `        end`
        ]
      : [];

    fns.push([
      `-- ${ep.id}: ${ep.method} ${ep.path}${ep.description ? ` — ${luaComment(ep.description)}` : ''}`,
      `function Glue.${ep.id}(payload)`,
      ...validationLines,
      `    local url = BASE_URL .. ${JSON.stringify(ep.path)}`,
      `    http.request({`,
      `        method = ${JSON.stringify(ep.method)},`,
      `        url = url,`,
      sendsBody ? `        body = json.encode(payload),` : `        -- ${ep.method}: no request body`,
      `        headers = { ["Content-Type"] = "application/json" }`,
      `    }, function(err, response)`,
      `        if err ~= nil then`,
      `            AddUITriggeredEvent(NS, ${JSON.stringify(`${ep.id}.error`)}, tostring(err))`,
      `            return`,
      `        end`,
      `        local ok, decoded = pcall(json.decode, response and response.body or "")`,
      ...responseCheckLines,
      `        AddUITriggeredEvent(NS, ${JSON.stringify(`${ep.id}.response`)}, ok and decoded or {})`,
      `    end)`,
      `end`,
      ``,
      `-- MD raises "${ev.request}" with a param table; call the endpoint.`,
      `RegisterEvent(${JSON.stringify(ev.request)}, function(_, param)`,
      `    Glue.${ep.id}(param)`,
      `end)`,
      ``
    ].join('\n'));

    registrations.push(ev.request);
  }

  const footer = [
    `-- Registered ${registrations.length} MD-triggered endpoint event(s):`,
    ...registrations.map(r => `--   ${r}`),
    `return Glue`,
    ''
  ].join('\n');

  return [header, preamble, fns.join('\n'), footer].join('\n');
}

/**
 * Self-test oracle for the contract-glue engine. Mirrors the studio's other
 * `*-selftest` endpoints: builds known-good and known-bad contracts and asserts the
 * validator + generator behave. Returns { allPassed, passed, total, checks }.
 */
function sampleForType(t: ContractFieldType): string {
  switch (t) {
    case 'number': return '0';
    case 'boolean': return 'true';
    case 'array': return '[]';
    case 'object': return 'table[]';
    default: return "''";
  }
}

/**
 * Generate the MD-side scaffold for a contract: per endpoint, a `<library>` cue that
 * raises the Lua call event (with the request fields as params) and a response-handler
 * cue that listens for the Lua-fired `<ns>.<id>.response` via `event_ui_triggered`.
 * This gives the modder BOTH ends of the contract (Lua glue + MD bridge) from one place.
 * Packaged at `md/<modId>_http.xml`. Throws on a contract with errors.
 */
export function generateContractMdScript(contract: IntegrationContract, modId: string): string {
  const errors = validateContract(contract).filter(fd => fd.severity === 'error');
  if (errors.length > 0) {
    throw new Error(`Cannot generate MD scaffold: ${errors.length} contract error(s): ${errors.map(e => e.message).join('; ')}`);
  }
  const ns = contract.namespace;
  const blocks = contract.endpoints.map(ep => {
    const ev = endpointEventNames(ns, ep.id);
    const req = ep.request || [];
    if ((ep.kind || 'http') === 'ui_event') {
      const fieldList = req.map(fld => fld.name).join(', ') || 'none declared';
      return [
        `    <!-- ui_event ${ep.id} — raised by the mod's Lua UI via Glue.${ep.id}(payload) (fields: ${fieldList}). -->`,
        `    <cue name="On_${ep.id}">`,
        `      <conditions>`,
        `        <event_ui_triggered screen="'${ns}'" control="'${ep.id}'" />`,
        `      </conditions>`,
        `      <actions>`,
        `        <!-- event.param3 holds the payload table from AddUITriggeredEvent -->`,
        `        <debug_text text="'${ep.id}: '+event.param3" filter="general" />`,
        `      </actions>`,
        `    </cue>`
      ].join('\n');
    }
    if ((ep.kind || 'http') === 'file_bridge') {
      const fb = fileBridgeDefaults(ep);
      const respFields = (ep.response || []).map(fld => fld.name).join(', ') || 'no declared fields';
      return [
        `    <!-- file_bridge ${ep.id} — write request file and poll for ${fb.responseFile}. -->`,
        `    <library name="Call_${ep.id}">`,
        req.length ? `      <params>\n${req.map(fld => `        <param name="${fld.name}" />`).join('\n')}\n      </params>` : `      <!-- no request fields -->`,
        `      <actions>`,
        buildFileBridgePollingSubgraph({
          namespace: ns,
          actionId: ep.id,
          directory: fb.directory,
          requestFile: fb.requestFile,
          responseFile: fb.responseFile,
          requestPayloadExpr: mdPayloadExpr(ep),
          pollInterval: fb.pollInterval,
          timeout: fb.timeout,
        }).split('\n').map(line => `        ${line}`).join('\n'),
        `      </actions>`,
        `    </library>`,
        ``,
        `    <!-- response for ${ep.id} via file bridge (fields: ${respFields}) -->`,
        `    <cue name="On_${ep.id}_response">`,
        `      <conditions>`,
        `        <event_ui_triggered screen="'${ns}'" control="'${ep.id}.response'" />`,
        `      </conditions>`,
        `      <actions>`,
        `        <debug_text text="'${ep.id} file response: '+event.param3" filter="general" />`,
        `      </actions>`,
        `    </cue>`,
        ``,
        `    <cue name="On_${ep.id}_error">`,
        `      <conditions>`,
        `        <event_ui_triggered screen="'${ns}'" control="'${ep.id}.error'" />`,
        `      </conditions>`,
        `      <actions>`,
        `        <debug_text text="'${ep.id} file error: '+event.param3" filter="general" />`,
        `      </actions>`,
        `    </cue>`
      ].join('\n');
    }
    const paramDecls = req.map(fld => `        <param name="${fld.name}" />`).join('\n');
    const payload = req.length
      ? `table[${req.map(fld => `$${fld.name}=$${fld.name}`).join(', ')}]`
      : 'null';
    const respFields = (ep.response || []).map(fld => fld.name).join(', ') || 'no declared fields';
    return [
      `    <!-- ${ep.method} ${ep.path} — call ${ep.id}: signal this library (with params) to fire the request. -->`,
      `    <library name="Call_${ep.id}">`,
      req.length ? `      <params>\n${paramDecls}\n      </params>` : `      <!-- no request fields -->`,
      `      <actions>`,
      `        <raise_lua_event name="'${ev.request}'" param="${payload}" />`,
      `      </actions>`,
      `    </library>`,
      ``,
      `    <!-- response for ${ep.id} (fields: ${respFields}) -->`,
      `    <cue name="On_${ep.id}_response">`,
      `      <conditions>`,
      `        <event_ui_triggered screen="'${ns}'" control="'${ep.id}.response'" />`,
      `      </conditions>`,
      `      <actions>`,
      `        <!-- event.param3 holds the decoded JSON response from AddUITriggeredEvent -->`,
      `        <debug_text text="'${ep.id} response: '+event.param3" filter="general" />`,
      `      </actions>`,
      `    </cue>`,
      ``,
      `    <cue name="On_${ep.id}_error">`,
      `      <conditions>`,
      `        <event_ui_triggered screen="'${ns}'" control="'${ep.id}.error'" />`,
      `      </conditions>`,
      `      <actions>`,
      `        <debug_text text="'${ep.id} error: '+event.param3" filter="general" />`,
      `      </actions>`,
      `    </cue>`
    ].join('\n');
  }).join('\n\n');
  return `<?xml version="1.0" encoding="utf-8"?>\n<mdscript name="${modId}_http" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xsi:noNamespaceSchemaLocation="md.xsd">\n  <cues>\n${blocks}\n  </cues>\n</mdscript>`;
}

export function runContractGlueSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const good: IntegrationContract = {
    namespace: 'myai',
    baseUrl: 'http://127.0.0.1:8713',
    endpoints: [
      { id: 'get_status', method: 'GET', path: '/v1/status', response: [{ name: 'ok', type: 'boolean' }] },
      { id: 'send_prompt', method: 'POST', path: '/v1/prompt', request: [{ name: 'text', type: 'string', required: true }], response: [{ name: 'reply', type: 'string' }] },
      { id: 'hud_button_clicked', kind: 'ui_event', description: 'HUD button -> MD', request: [{ name: 'button_id', type: 'string', required: true }, { name: 'count', type: 'number' }] },
      { id: 'file_prompt', kind: 'file_bridge', description: 'File bridge prompt', request: [{ name: 'text', type: 'string', required: true }], response: [{ name: 'reply', type: 'string' }],
        fileBridge: { directory: 'x4_forge_bridge', requestFile: 'prompt_request.json', responseFile: 'prompt_response.json', pollInterval: '0.5s', timeout: '8s' } }
    ]
  };

  ok('valid_contract_clean', validateContract(good).filter(f => f.severity === 'error').length === 0);

  let lua = '';
  let threw = false;
  try { lua = generateHttpGlueLua(good); } catch { threw = true; }
  ok('generates_without_throwing', !threw && lua.length > 0);

  // every endpoint must produce a RegisterEvent + a Glue function + a response event
  const allEndpointsWired = good.endpoints.every(ep => {
    const ev = endpointEventNames(good.namespace, ep.id);
    const base = lua.includes(`RegisterEvent(${JSON.stringify(ev.request)}`)
      && lua.includes(`function Glue.${ep.id}(`);
    const kind = ep.kind || 'http';
    if (kind === 'http') return base && lua.includes(JSON.stringify(`${ep.id}.response`));
    if (kind === 'file_bridge') return lua.includes(`RegisterEvent(${JSON.stringify(`${ev.request}.poll`)}`) && lua.includes(`function Glue.${ep.id}_poll(`);
    return base;
  });
  ok('all_endpoints_wired', allEndpointsWired);

  ok('emits_json_encode_and_decode', lua.includes('json.encode(') && lua.includes('json.decode'));
  ok('post_sends_body_get_does_not',
    lua.includes('body = json.encode(payload)') && lua.includes('-- GET: no request body'));
  ok('required_field_guarded', lua.includes('missing required field: text'));
  ok('async_callback_shape', lua.includes('function(err, response)') && lua.includes('AddUITriggeredEvent('));
  ok('response_shape_validated', lua.includes("response missing field 'reply'") && lua.includes('type(decoded) == "table"'));

  // validator must catch a broken contract
  const bad: IntegrationContract = {
    namespace: 'Bad Name',
    baseUrl: 'ftp://nope',
    endpoints: [
      { id: 'Dup', method: 'FETCH' as any, path: 'no-slash' },
      { id: 'dup', method: 'GET', path: '/a' },
      { id: 'dup', method: 'GET', path: '/b' }
    ]
  };
  const badFindings = validateContract(bad);
  ok('validator_flags_bad_namespace', badFindings.some(f => /namespace/.test(f.message)));
  ok('validator_flags_bad_baseurl', badFindings.some(f => /baseUrl/.test(f.message)));
  ok('validator_flags_bad_method', badFindings.some(f => /invalid method/.test(f.message)));
  ok('validator_flags_bad_path', badFindings.some(f => /must start with/.test(f.message)));
  ok('validator_flags_duplicate_id', badFindings.some(f => /duplicate endpoint id/.test(f.message)));

  let badThrew = false;
  try { generateHttpGlueLua(bad); } catch { badThrew = true; }
  ok('generator_refuses_bad_contract', badThrew);

  // MD scaffold checks
  let md = '';
  let mdThrew = false;
  try { md = generateContractMdScript(good, 'mymod'); } catch { mdThrew = true; }
  ok('md_generates_without_throwing', !mdThrew && md.length > 0);
  ok('md_is_mdscript', md.includes('<mdscript name="mymod_http"') && md.includes('</mdscript>'));
  ok('md_wires_call_and_response', good.endpoints.every(ep => (ep.kind || 'http') === 'ui_event'
    ? (md.includes(`<cue name="On_${ep.id}">`) && md.includes(`control="'${ep.id}'"`) && !md.includes(`<library name="Call_${ep.id}">`))
    : (ep.kind || 'http') === 'file_bridge'
      ? (md.includes(`<library name="Call_${ep.id}">`) && md.includes('<debug_to_file') && md.includes(`control="'${ep.id}.response'"`))
    : (md.includes(`<library name="Call_${ep.id}">`) && md.includes(`name="'${good.namespace}.${ep.id}'"`) && md.includes(`control="'${ep.id}.response'"`))));
  ok('md_passes_request_params', md.includes('<param name="text" />') && md.includes('$text=$text'));
  let mdBadThrew = false;
  try { generateContractMdScript(bad, 'x'); } catch { mdBadThrew = true; }
  ok('md_refuses_bad_contract', mdBadThrew);

  // T4.3 — ui_event endpoint kind (widget → MD bridge, no HTTP)
  ok('ui_event_lua_no_http', (() => {
    const start = lua.indexOf('function Glue.hud_button_clicked(');
    const end = lua.indexOf('\nend', start);
    const fn = start >= 0 && end > start ? lua.slice(start, end) : '';
    return fn.length > 0 && !fn.includes('http.request') && fn.includes('AddUITriggeredEvent(NS, "hud_button_clicked"');
  })());
  ok('ui_event_type_guards',
    lua.includes('type(payload["button_id"]) ~= "string"')
    && lua.includes('type(payload["count"]) ~= "number"')
    && lua.includes("missing required field 'button_id'"));
  ok('ui_event_md_listener_only',
    md.includes('<cue name="On_hud_button_clicked">')
    && md.includes(`control="'hud_button_clicked'"`)
    && !md.includes('Call_hud_button_clicked'));
  const pureUi: IntegrationContract = { namespace: 'uionly', baseUrl: '', endpoints: [{ id: 'btn', kind: 'ui_event', request: [] }] };
  ok('pure_ui_contract_needs_no_baseurl', validateContract(pureUi).filter(f => f.severity === 'error').length === 0);
  ok('ui_event_method_warns', validateContract({
    namespace: 'x1', baseUrl: '', endpoints: [{ id: 'a', kind: 'ui_event', method: 'GET' }]
  }).some(f => f.severity === 'warning' && /ignored/.test(f.message)));
  // P1 — file_bridge endpoint kind: same contract seam, local file-poll transport.
  ok('file_bridge_lua_whitelists_action',
    lua.includes('local ALLOWED_ACTIONS') && lua.includes('["file_prompt"] = true') && lua.includes('blocked file-bridge action'));
  ok('file_bridge_lua_registers_poll_and_timeout',
    lua.includes('RegisterEvent("myai.file_prompt.poll"') && lua.includes('RegisterEvent("myai.file_prompt.timeout"'));
  ok('file_bridge_md_writes_request_file',
    md.includes('<debug_to_file') && md.includes(`name="'prompt_request.json'"`) && md.includes('prompt_response.json'));
  ok('file_bridge_md_has_bounded_poll',
    md.includes('<do_while value="player.age lt $file_prompt_file_bridge_deadline">') && md.includes('<delay exact="0.5s" />') && md.includes('player.age + 8s'));
  const pureFile: IntegrationContract = { namespace: 'fileonly', baseUrl: '', endpoints: [{ id: 'ask', kind: 'file_bridge', request: [] }] };
  ok('pure_file_bridge_contract_needs_no_baseurl', validateContract(pureFile).filter(f => f.severity === 'error').length === 0);
  ok('file_bridge_method_warns', validateContract({
    namespace: 'x1', baseUrl: '', endpoints: [{ id: 'a', kind: 'file_bridge', method: 'GET' }]
  }).some(f => f.severity === 'warning' && /ignored/.test(f.message)));
  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, pass: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Tier 2 / T2.1 — structural cue-lineage analysis over the MD node graph.
 *
 * Builds a cue dependency tree from {nodes, links} and reports *structural* broken
 * lineage — the statically-decidable subset of MD logic bugs. It deliberately does NOT
 * attempt to prove a condition is "never met" (that is runtime/satisfiability-dependent
 * and undecidable); it reports things that are unambiguously wrong from the graph alone:
 * duplicate/unnamed cue names, dangling LOCAL cue references, fully-disconnected cues,
 * and links to missing nodes. Cross-script (`md.Script.Cue`) and qualified refs are
 * treated as external and never flagged, to avoid false positives.
 *
 * Graph model (from generateMDXML / nodeToCueMap):
 *   - a cue is a node with type === 'cue'; its name is properties.name.
 *   - root cue = not targeted by an `out_sub` link.
 *   - parent -> child cue nesting: parent `out_sub` -> child `in_flow`.
 *   - a cue's trigger events: cue `out_cond` -> event/condition node `in_cond`.
 *   - cross-cue LISTEN: an `event_cue_signalled` node's properties.cue.
 *   - cross-cue SIGNAL: signal_cue / signal_cue_instantly / reset_cue / cancel_cue,
 *     read from a structured action node's properties.cue OR a `custom_xml` rawXml.
 */

import type { MDNode, MDLink } from '../types';

export type CueLineageSeverity = 'error' | 'warning';
export type CueLineageCode =
  | 'duplicate_cue_name'
  | 'unnamed_cue'
  | 'dangling_cue_ref'
  | 'isolated_cue'
  | 'dangling_link';

export interface CueLineageFinding {
  severity: CueLineageSeverity;
  code: CueLineageCode;
  cueId?: string;
  nodeId?: string;
  /** The offending reference text, when relevant. */
  ref?: string;
  message: string;
}

export interface CueLineageEdge {
  fromCueId: string;
  /** Resolved local cue id, or null when external/unresolved. */
  toCueId: string | null;
  toRef: string;
  kind: 'parent' | 'listen' | 'signal';
}

export interface CueLineageCueInfo {
  id: string;
  name: string;
  label: string;
  parentId: string | null;
  childIds: string[];
  hasTriggerEvent: boolean;
  /** Local cue names this cue listens for (event_cue_signalled). */
  listensTo: string[];
  /** Local cue names this cue signals/resets/cancels (custom_xml rawXml). */
  signals: string[];
  /** Whether any other cue listens-for or signals this cue. */
  referencedByOthers: boolean;
}

export interface CueLineageResult {
  cues: CueLineageCueInfo[];
  edges: CueLineageEdge[];
  findings: CueLineageFinding[];
}

const SIGNAL_TAGS = ['signal_cue_instantly', 'signal_cue', 'reset_cue', 'cancel_cue'];

/** Extract cue="X" targets from raw signal/reset/cancel XML inside a custom_xml node. */
export function parseSignalCueRefs(rawXml: string): string[] {
  if (!rawXml || typeof rawXml !== 'string') return [];
  const refs: string[] = [];
  const re = /<\s*(signal_cue_instantly|signal_cue|reset_cue|cancel_cue)\b[^>]*\bcue\s*=\s*"([^"]+)"/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(rawXml)) !== null) refs.push(m[2]);
  return refs;
}

/**
 * Resolve a cue reference to a *local* candidate name, or null if it should be treated
 * as external/qualified (and therefore never flagged). Strips a leading `this.`; any
 * remaining dot (e.g. `md.X.Y`, `parent.X`, `static.X`) means external/qualified.
 */
export function normalizeLocalCueRef(ref: string): string | null {
  if (!ref || typeof ref !== 'string') return null;
  let r = ref.trim();
  if (r.startsWith('this.')) r = r.slice(5);
  if (r.length === 0) return null;
  if (r.includes('.')) return null; // qualified / cross-script — external
  // MD expressions / variables aren't cue names
  if (r.startsWith('$') || r.startsWith('{')) return null;
  return r;
}

/** Map each node id to the cue id that owns it (BFS over links, excluding out_sub→in_flow). */
function buildNodeOwnership(nodes: MDNode[], links: MDLink[]): Map<string, string> {
  const nodeById = new Map(nodes.map(n => [n.id, n]));
  const adj = new Map<string, string[]>();
  const add = (a: string, b: string) => { const arr = adj.get(a) || []; arr.push(b); adj.set(a, arr); };
  for (const l of links) {
    if (l.sourcePortId === 'out_sub' && l.targetPortId === 'in_flow') continue;
    add(l.sourceNodeId, l.targetNodeId);
    add(l.targetNodeId, l.sourceNodeId);
  }
  const owner = new Map<string, string>();
  for (const cue of nodes) {
    if (cue.type !== 'cue') continue;
    owner.set(cue.id, cue.id);
    const visited = new Set([cue.id]);
    const queue = [cue.id];
    let head = 0;
    while (head < queue.length) {
      const cur = queue[head++];
      for (const nb of adj.get(cur) || []) {
        if (visited.has(nb)) continue;
        const nbNode = nodeById.get(nb);
        if (nbNode && nbNode.type !== 'cue') { visited.add(nb); owner.set(nb, cue.id); queue.push(nb); }
      }
    }
  }
  return owner;
}

export function analyzeCueLineage(nodes: MDNode[], links: MDLink[]): CueLineageResult {
  nodes = Array.isArray(nodes) ? nodes : [];
  links = Array.isArray(links) ? links : [];
  const nodeIds = new Set(nodes.map(n => n.id));
  const cueNodes = nodes.filter(n => n.type === 'cue');
  const owner = buildNodeOwnership(nodes, links);

  const findings: CueLineageFinding[] = [];
  const edges: CueLineageEdge[] = [];

  // --- dangling links (source/target node missing) ---
  for (const l of links) {
    if (!nodeIds.has(l.sourceNodeId) || !nodeIds.has(l.targetNodeId)) {
      findings.push({ severity: 'error', code: 'dangling_link', nodeId: nodeIds.has(l.sourceNodeId) ? l.targetNodeId : l.sourceNodeId,
        message: `Link "${l.id}" points to a node that no longer exists.` });
    }
  }

  // --- local cue name index ---
  const cueByName = new Map<string, string>(); // name -> cueId (first wins)
  const nameCounts = new Map<string, number>();
  for (const c of cueNodes) {
    const name = (c.properties?.name ?? '').toString().trim();
    if (name) {
      nameCounts.set(name, (nameCounts.get(name) || 0) + 1);
      if (!cueByName.has(name)) cueByName.set(name, c.id);
    }
  }

  // build per-cue info shells
  const info = new Map<string, CueLineageCueInfo>();
  for (const c of cueNodes) {
    info.set(c.id, {
      id: c.id,
      name: (c.properties?.name ?? '').toString().trim(),
      label: c.label || c.id,
      parentId: null,
      childIds: [],
      hasTriggerEvent: false,
      listensTo: [],
      signals: [],
      referencedByOthers: false
    });
  }

  // --- parent/child via out_sub, trigger events via out_cond ---
  for (const l of links) {
    if (l.sourcePortId === 'out_sub' && l.targetPortId === 'in_flow') {
      const parent = info.get(l.sourceNodeId);
      const child = info.get(l.targetNodeId);
      if (parent && child) {
        parent.childIds.push(child.id);
        child.parentId = parent.id;
        edges.push({ fromCueId: parent.id, toCueId: child.id, toRef: child.name || child.id, kind: 'parent' });
      }
    }
    if (l.sourcePortId === 'out_cond') {
      const cue = info.get(l.sourceNodeId);
      if (cue) cue.hasTriggerEvent = true;
    }
  }

  // --- cross-cue LISTEN (event_cue_signalled) ---
  for (const ev of nodes) {
    if (ev.xmlTag !== 'event_cue_signalled') continue;
    const ownerCueId = owner.get(ev.id);
    const cue = ownerCueId ? info.get(ownerCueId) : undefined;
    if (!cue) continue;
    const ref = (ev.properties?.cue ?? '').toString().trim();
    if (!ref) continue;
    const local = normalizeLocalCueRef(ref);
    const toCueId = local ? (cueByName.get(local) ?? null) : null;
    edges.push({ fromCueId: cue.id, toCueId, toRef: ref, kind: 'listen' });
    if (local) {
      cue.listensTo.push(local);
      if (toCueId) { const t = info.get(toCueId); if (t) t.referencedByOthers = true; }
      else findings.push({ severity: 'error', code: 'dangling_cue_ref', cueId: cue.id, nodeId: ev.id, ref,
        message: `Cue "${cue.name || cue.id}" listens for local cue "${ref}" which doesn't exist.` });
    }
  }

  // --- cross-cue SIGNAL: structured signal_cue/reset_cue/cancel_cue nodes OR custom_xml rawXml ---
  for (const act of nodes) {
    let refs: string[] = [];
    if (act.xmlTag === 'custom_xml') {
      refs = parseSignalCueRefs((act.properties?.rawXml ?? '').toString());
    } else if (SIGNAL_TAGS.indexOf(act.xmlTag) !== -1) {
      const cueRef = (act.properties?.cue ?? '').toString().trim();
      if (cueRef) refs = [cueRef];
    }
    if (refs.length === 0) continue;
    const ownerCueId = owner.get(act.id);
    const cue = ownerCueId ? info.get(ownerCueId) : undefined;
    if (!cue) continue;
    for (const ref of refs) {
      const local = normalizeLocalCueRef(ref);
      const toCueId = local ? (cueByName.get(local) ?? null) : null;
      edges.push({ fromCueId: cue.id, toCueId, toRef: ref, kind: 'signal' });
      if (local) {
        cue.signals.push(local);
        if (toCueId) { const t = info.get(toCueId); if (t) t.referencedByOthers = true; }
        else findings.push({ severity: 'error', code: 'dangling_cue_ref', cueId: cue.id, nodeId: act.id, ref,
          message: `Cue "${cue.name || cue.id}" signals local cue "${ref}" which doesn't exist.` });
      }
    }
  }

  // --- duplicate / unnamed cue names ---
  for (const [name, count] of nameCounts) {
    if (count > 1) findings.push({ severity: 'error', code: 'duplicate_cue_name', ref: name,
      message: `Cue name "${name}" is used by ${count} cues; cue names must be unique within a script.` });
  }
  for (const c of cueNodes) {
    const name = (c.properties?.name ?? '').toString().trim();
    if (!name) findings.push({ severity: 'warning', code: 'unnamed_cue', cueId: c.id,
      message: `Cue "${c.label || c.id}" has no name; it can't be referenced and won't compile cleanly.` });
  }

  // --- isolated cue (fully disconnected and unreferenced) ---
  const linkedNodeIds = new Set<string>();
  for (const l of links) { linkedNodeIds.add(l.sourceNodeId); linkedNodeIds.add(l.targetNodeId); }
  for (const c of cueNodes) {
    const ci = info.get(c.id)!;
    const hasAnyLink = linkedNodeIds.has(c.id);
    if (!hasAnyLink && !ci.referencedByOthers) {
      findings.push({ severity: 'warning', code: 'isolated_cue', cueId: c.id,
        message: `Cue "${ci.name || ci.label}" is fully disconnected — no conditions, actions, sub-cues, parent, or references. It is dead code.` });
    }
  }

  return { cues: Array.from(info.values()), edges, findings };
}

/** Self-test oracle: known-good and known-broken graphs assert the analyzer behaves. */
export function runCueLineageSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });
  const N = (id: string, type: any, xmlTag: string, properties: any = {}): MDNode =>
    ({ id, type, xmlTag, properties, label: id, x: 0, y: 0, propertiesSchema: [], inputs: [], outputs: [] } as any);
  const L = (id: string, s: string, sp: string, t: string, tp: string): MDLink =>
    ({ id, sourceNodeId: s, sourcePortId: sp, targetNodeId: t, targetPortId: tp });

  // ---- clean graph: Parent cue with sub-cue Child; Listener listens for Parent; Worker signals Listener ----
  const cleanNodes: MDNode[] = [
    N('c_parent', 'cue', 'cue', { name: 'Parent' }),
    N('c_child', 'cue', 'cue', { name: 'Child' }),
    N('e_child', 'event', 'event_cue_signalled', { cue: 'md.Setup.Start' }),
    N('c_listener', 'cue', 'cue', { name: 'Listener' }),
    N('e_listen', 'event', 'event_cue_signalled', { cue: 'Parent' }),
    N('c_worker', 'cue', 'cue', { name: 'Worker' }),
    N('a_signal', 'action', 'custom_xml', { rawXml: '<signal_cue cue="Listener" />' })
  ];
  const cleanLinks: MDLink[] = [
    L('l1', 'c_parent', 'out_sub', 'c_child', 'in_flow'),
    L('l2', 'c_child', 'out_cond', 'e_child', 'in_cond'),
    L('l3', 'c_listener', 'out_cond', 'e_listen', 'in_cond'),
    L('l4', 'c_worker', 'out_act', 'a_signal', 'in_act')
  ];
  const clean = analyzeCueLineage(cleanNodes, cleanLinks);
  ok('clean_no_errors', clean.findings.filter(f => f.severity === 'error').length === 0, clean.findings);
  ok('clean_parent_child_edge', clean.edges.some(e => e.kind === 'parent' && e.fromCueId === 'c_parent' && e.toCueId === 'c_child'));
  ok('clean_listen_resolves', clean.edges.some(e => e.kind === 'listen' && e.toRef === 'Parent' && e.toCueId === 'c_parent'));
  ok('clean_signal_resolves', clean.edges.some(e => e.kind === 'signal' && e.toRef === 'Listener' && e.toCueId === 'c_listener'));
  ok('external_ref_not_flagged', !clean.findings.some(f => f.code === 'dangling_cue_ref'));
  ok('child_parent_set', clean.cues.find(c => c.id === 'c_child')!.parentId === 'c_parent');

  // ---- broken graph: dup name, dangling listen, dangling signal, isolated cue, dangling link ----
  const badNodes: MDNode[] = [
    N('b1', 'cue', 'cue', { name: 'Dup' }),
    N('b2', 'cue', 'cue', { name: 'Dup' }),
    N('b3', 'cue', 'cue', { name: 'Listener2' }),
    N('be', 'event', 'event_cue_signalled', { cue: 'NoSuchCue' }),
    N('b4', 'cue', 'cue', { name: 'Signaller2' }),
    N('ba', 'action', 'custom_xml', { rawXml: '<reset_cue cue="GhostCue" />' }),
    N('b5', 'cue', 'cue', { name: 'Lonely' }),
    N('b6', 'cue', 'cue', { name: '' })
  ];
  const badLinks: MDLink[] = [
    L('bl1', 'b3', 'out_cond', 'be', 'in_cond'),
    L('bl2', 'b4', 'out_act', 'ba', 'in_act'),
    L('bl3', 'b1', 'out_act', 'missing_node', 'in_act')
  ];
  const bad = analyzeCueLineage(badNodes, badLinks);
  const has = (code: string) => bad.findings.some(f => f.code === code);
  ok('flags_duplicate_name', has('duplicate_cue_name'));
  ok('flags_dangling_listen', bad.findings.some(f => f.code === 'dangling_cue_ref' && f.ref === 'NoSuchCue'));
  ok('flags_dangling_signal', bad.findings.some(f => f.code === 'dangling_cue_ref' && f.ref === 'GhostCue'));
  ok('flags_isolated_cue', bad.findings.some(f => f.code === 'isolated_cue' && f.cueId === 'b5'));
  ok('flags_unnamed_cue', bad.findings.some(f => f.code === 'unnamed_cue' && f.cueId === 'b6'));
  ok('flags_dangling_link', has('dangling_link'));

  // helpers
  ok('normalize_strips_this', normalizeLocalCueRef('this.Foo') === 'Foo');
  ok('normalize_external_is_null', normalizeLocalCueRef('md.Setup.Start') === null);
  ok('parse_signal_multi', parseSignalCueRefs('<signal_cue cue="A"/><cancel_cue cue="B" />').join(',') === 'A,B');

  // structured signal node (not custom_xml): signal_cue with properties.cue
  const sNodes: MDNode[] = [
    N('sc1', 'cue', 'cue', { name: 'Caller' }),
    N('sc_act', 'action', 'signal_cue', { cue: 'Target' }),
    N('sc2', 'cue', 'cue', { name: 'Target' }),
    N('sc3', 'cue', 'cue', { name: 'BadCaller' }),
    N('sc_bad', 'action', 'reset_cue', { cue: 'NoStruct' })
  ];
  const sLinks: MDLink[] = [ L('sl1','sc1','out_act','sc_act','in_act'), L('sl2','sc3','out_act','sc_bad','in_act') ];
  const sr = analyzeCueLineage(sNodes, sLinks);
  ok('structured_signal_resolves', sr.edges.some(e => e.kind === 'signal' && e.toRef === 'Target' && e.toCueId === 'sc2'));
  ok('structured_signal_dangling_flagged', sr.findings.some(f => f.code === 'dangling_cue_ref' && f.ref === 'NoStruct'));

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

