 * SQLite persistence layer (ROADMAP: "SQLite persistence layer (design)").
 *
 * Backend cache + query layer for the expensive, reusable data the studio computes:
 * the packed .cat/.dat object index and the extension manifest/file index. The mod
 * being edited stays in frontend memory; generated XML stays computed on demand; the
 * filesystem remains the source of truth — this DB only *indexes* it.
 *
 * Migration stage: MIRROR-WRITE (stage 2 of 4). The in-memory path remains the source
 * of truth for all reads; this module mirrors results into SQLite and exposes query
 * helpers so reads can be flipped over once /api/agent/db-selftest proves parity.
 *
 * better-sqlite3 is an OPTIONAL native dependency: if it isn't installed, every
 * entry point no-ops and isDbAvailable() reports false (with the reason), so the
 * server runs unchanged. Install with:  npm install better-sqlite3
 */

import fs from 'fs';
import path from 'path';
import os from 'os';
import { createRequire } from 'module';

// ---------------------------------------------------------------------------
// Optional native module loading (the project is ESM; better-sqlite3 is CJS).
// ---------------------------------------------------------------------------

type SqliteDatabase = any;

let BetterSqlite3: any = null;
let loadError: string | null = null;

function loadDriver(): any {
  if (BetterSqlite3 || loadError) return BetterSqlite3;
  try {
    const require = createRequire(import.meta.url);
    BetterSqlite3 = require('better-sqlite3');
  } catch (err: any) {
    loadError = err?.message || String(err);
  }
  return BetterSqlite3;
}

export function isDbAvailable(): { available: boolean; reason?: string } {
  loadDriver();
  return BetterSqlite3 ? { available: true } : { available: false, reason: loadError || 'better-sqlite3 not installed' };
}

// ---------------------------------------------------------------------------
// Schema (v1) — exactly the ROADMAP DDL.
// ---------------------------------------------------------------------------

export const SCHEMA_VERSION = 2; // v2: + object_index.detail (needed for lossless restore)

const SCHEMA_DDL = `
CREATE TABLE IF NOT EXISTS meta (key TEXT PRIMARY KEY, value TEXT);
CREATE TABLE IF NOT EXISTS source_mtime (path TEXT PRIMARY KEY, mtime INTEGER);
CREATE TABLE IF NOT EXISTS object_index (
  kind TEXT, id TEXT, name TEXT, source_mod TEXT, source_file TEXT, macro TEXT, dlc TEXT, detail TEXT,
  PRIMARY KEY (kind, id)
);
CREATE INDEX IF NOT EXISTS idx_obj_kind ON object_index(kind);
CREATE INDEX IF NOT EXISTS idx_obj_id   ON object_index(id);
CREATE TABLE IF NOT EXISTS extensions (
  folder TEXT PRIMARY KEY, content_id TEXT, name TEXT, version TEXT, enabled INTEGER, deps_json TEXT
);
CREATE INDEX IF NOT EXISTS idx_ext_id ON extensions(content_id);
CREATE TABLE IF NOT EXISTS ext_files (
  folder TEXT, rel_path TEXT, is_diff INTEGER, selectors_json TEXT, hash TEXT,
  PRIMARY KEY (folder, rel_path)
);
CREATE INDEX IF NOT EXISTS idx_extfiles_path ON ext_files(rel_path);
`;

export interface StudioDb {
  raw: SqliteDatabase;
  path: string;
}

/**
 * Open (creating/migrating as needed) the studio cache DB. Returns null when the
 * driver is unavailable or the file can't be opened — callers must treat null as
 * "no cache" and stay on the in-memory path.
 */
export function openStudioDb(cacheDir?: string): StudioDb | null {
  if (!loadDriver()) return null;
  try {
    const dir = cacheDir || path.join(os.tmpdir(), 'x4-studio-cache');
    fs.mkdirSync(dir, { recursive: true });
    const dbPath = path.join(dir, 'index.db');
    const raw = new BetterSqlite3(dbPath);
    raw.pragma('journal_mode = WAL');
    raw.exec(SCHEMA_DDL);
    const existing = getMeta(raw, 'schema_version');
    if (existing !== String(SCHEMA_VERSION)) {
      if (existing !== null) {
        // It's a cache, not a store: on any schema change drop + recreate the data
        // tables (DDL above runs IF NOT EXISTS, so recreate explicitly).
        raw.exec('DROP TABLE IF EXISTS object_index; DROP TABLE IF EXISTS extensions; DROP TABLE IF EXISTS ext_files; DELETE FROM source_mtime; DELETE FROM meta;');
        raw.exec(SCHEMA_DDL);
      }
      setMeta(raw, 'schema_version', String(SCHEMA_VERSION));
    }
    return { raw, path: dbPath };
  } catch (err) {
    console.warn('[studio-db] open failed, continuing without SQLite cache:', err);
    return null;
  }
}

function getMeta(raw: SqliteDatabase, key: string): string | null {
  const row = raw.prepare('SELECT value FROM meta WHERE key = ?').get(key);
  return row ? row.value : null;
}

function setMeta(raw: SqliteDatabase, key: string, value: string) {
  raw.prepare('INSERT INTO meta(key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value').run(key, value);
}

export function getDbMeta(db: StudioDb, key: string): string | null {
  return getMeta(db.raw, key);
}

export function setDbMeta(db: StudioDb, key: string, value: string) {
  setMeta(db.raw, key, value);
}

// ---------------------------------------------------------------------------
// Invalidation — source mtimes + game-path binding.
// ---------------------------------------------------------------------------

/**
 * If the configured game path changed since the cache was built, wipe everything
 * (per ROADMAP: "Store game_path in meta — wipe + rebuild if it changes").
 */
export function bindGamePath(db: StudioDb, gamePath: string) {
  const prev = getMeta(db.raw, 'game_path');
  if (prev !== null && prev !== gamePath) {
    db.raw.exec('DELETE FROM object_index; DELETE FROM extensions; DELETE FROM ext_files; DELETE FROM source_mtime;');
  }
  setMeta(db.raw, 'game_path', gamePath);
}

export interface SourceStamp { path: string; mtime: number; }

/** True when every given source file's mtime matches what the cache last saw. */
export function sourcesUnchanged(db: StudioDb, stamps: SourceStamp[]): boolean {
  const stmt = db.raw.prepare('SELECT mtime FROM source_mtime WHERE path = ?');
  for (const s of stamps) {
    const row = stmt.get(s.path);
    if (!row || Number(row.mtime) !== s.mtime) return false;
  }
  return true;
}

export function recordSourceStamps(db: StudioDb, stamps: SourceStamp[]) {
  const stmt = db.raw.prepare('INSERT INTO source_mtime(path, mtime) VALUES (?, ?) ON CONFLICT(path) DO UPDATE SET mtime = excluded.mtime');
  const tx = db.raw.transaction((rows: SourceStamp[]) => {
    for (const r of rows) stmt.run(r.path, r.mtime);
  });
  tx(stamps);
}

// ---------------------------------------------------------------------------
// Object index cache (x4ObjectIndex / x4CatDat decode results).
// ---------------------------------------------------------------------------

export interface DbObjectRow {
  kind: string; id: string; name: string;
  source_mod?: string | null; source_file?: string | null; macro?: string | null; dlc?: string | null;
  detail?: string | null;
}

/** Replace the cached object index in one transaction. */
export function cacheObjectIndex(db: StudioDb, rows: DbObjectRow[], builtAt?: string) {
  const insert = db.raw.prepare(
    'INSERT INTO object_index(kind, id, name, source_mod, source_file, macro, dlc, detail) VALUES (?, ?, ?, ?, ?, ?, ?, ?) ' +
    'ON CONFLICT(kind, id) DO UPDATE SET name = excluded.name, source_mod = excluded.source_mod, source_file = excluded.source_file, macro = excluded.macro, dlc = excluded.dlc, detail = excluded.detail'
  );
  const tx = db.raw.transaction((all: DbObjectRow[]) => {
    db.raw.exec('DELETE FROM object_index;');
    for (const r of all) {
      insert.run(r.kind, r.id, r.name, r.source_mod ?? null, r.source_file ?? null, r.macro ?? null, r.dlc ?? null, r.detail ?? null);
    }
  });
  tx(rows);
  setMeta(db.raw, 'object_index_built_at', builtAt || new Date().toISOString());
}

/** Full table read backing the cold-boot restore path. */
export function readAllObjects(db: StudioDb): DbObjectRow[] {
  return db.raw.prepare('SELECT kind, id, name, source_mod, source_file, macro, dlc, detail FROM object_index').all();
}

export function objectIndexCounts(db: StudioDb): Record<string, number> {
  const out: Record<string, number> = {};
  for (const row of db.raw.prepare('SELECT kind, COUNT(*) AS n FROM object_index GROUP BY kind').all()) {
    out[row.kind] = Number(row.n);
  }
  return out;
}

/** Indexed point/prefix query — the read path that will replace the in-memory filter. */
export function queryObjectIndex(db: StudioDb, opts: { q?: string; kind?: string; limit?: number }): DbObjectRow[] {
  const limit = Math.max(1, Math.min(opts.limit ?? 100, 2000));
  const clauses: string[] = [];
  const params: any[] = [];
  if (opts.kind) { clauses.push('kind = ?'); params.push(opts.kind); }
  if (opts.q) { clauses.push('(id LIKE ? OR name LIKE ?)'); params.push(`%${opts.q}%`, `%${opts.q}%`); }
  const where = clauses.length ? `WHERE ${clauses.join(' AND ')}` : '';
  return db.raw.prepare(`SELECT kind, id, name, source_mod, source_file, macro, dlc, detail FROM object_index ${where} ORDER BY kind, id LIMIT ?`).all(...params, limit);
}

/** O(1) existence checks backing reference validation (macroname/warename/faction). */
export function objectExists(db: StudioDb, kind: string, id: string): boolean {
  return !!db.raw.prepare('SELECT 1 FROM object_index WHERE kind = ? AND id = ?').get(kind, id);
}

// ---------------------------------------------------------------------------
// Extension manifest / file index cache (Extension Doctor data).
// ---------------------------------------------------------------------------

export interface DbExtensionRow {
  folder: string; content_id: string; name?: string | null; version?: string | null;
  enabled: boolean; deps: { id: string; optional: boolean; name?: string }[];
}

export interface DbExtFileRow {
  folder: string; rel_path: string; is_diff: boolean; selectors: string[]; hash?: string | null;
}

export function cacheExtensions(db: StudioDb, exts: DbExtensionRow[], files: DbExtFileRow[]) {
  const insExt = db.raw.prepare(
    'INSERT INTO extensions(folder, content_id, name, version, enabled, deps_json) VALUES (?, ?, ?, ?, ?, ?) ' +
    'ON CONFLICT(folder) DO UPDATE SET content_id = excluded.content_id, name = excluded.name, version = excluded.version, enabled = excluded.enabled, deps_json = excluded.deps_json'
  );
  const insFile = db.raw.prepare(
    'INSERT INTO ext_files(folder, rel_path, is_diff, selectors_json, hash) VALUES (?, ?, ?, ?, ?) ' +
    'ON CONFLICT(folder, rel_path) DO UPDATE SET is_diff = excluded.is_diff, selectors_json = excluded.selectors_json, hash = excluded.hash'
  );
  const tx = db.raw.transaction(() => {
    db.raw.exec('DELETE FROM extensions; DELETE FROM ext_files;');
    for (const e of exts) insExt.run(e.folder, e.content_id, e.name ?? null, e.version ?? null, e.enabled ? 1 : 0, JSON.stringify(e.deps || []));
    for (const f of files) insFile.run(f.folder, f.rel_path, f.is_diff ? 1 : 0, JSON.stringify(f.selectors || []), f.hash ?? null);
  });
  tx();
  setMeta(db.raw, 'extensions_built_at', new Date().toISOString());
}

/** The Extension Doctor "check 3" as a single indexed GROUP BY (per ROADMAP). */
// Separator: ASCII unit separator (0x1F) via SQLite char(31) — cannot appear in folder names.
const FOLDER_SEP = String.fromCharCode(31);
export function contestedPaths(db: StudioDb): { rel_path: string; folders: string[] }[] {
  const rows = db.raw.prepare(
    `SELECT rel_path, GROUP_CONCAT(folder, char(31)) AS folders
     FROM ext_files GROUP BY rel_path HAVING COUNT(DISTINCT folder) > 1`
  ).all();
  return rows.map((r: any) => ({ rel_path: r.rel_path, folders: String(r.folders).split(FOLDER_SEP) }));
}

/** Dependency check as a join on extensions.content_id (per ROADMAP). */
export function unresolvedDependencies(db: StudioDb): { folder: string; dep_id: string; optional: boolean }[] {
  const exts = db.raw.prepare('SELECT folder, deps_json FROM extensions').all();
  const ids = new Set(db.raw.prepare('SELECT content_id FROM extensions').all().map((r: any) => String(r.content_id).toLowerCase()));
  const out: { folder: string; dep_id: string; optional: boolean }[] = [];
  for (const e of exts) {
    let deps: any[] = [];
    try { deps = JSON.parse(e.deps_json || '[]'); } catch { deps = []; }
    for (const d of deps) {
      if (d?.id && !ids.has(String(d.id).toLowerCase())) {
        out.push({ folder: e.folder, dep_id: d.id, optional: !!d.optional });
      }
    }
  }
  return out;
}

// ---------------------------------------------------------------------------
// Self-test — builds a throwaway DB and asserts the query layer matches a known
// in-memory fixture (migration step 4's oracle).
// ---------------------------------------------------------------------------

export function dbSelfTest(): { available: boolean; reason?: string; pass?: boolean; checks?: Record<string, boolean> } {
  const avail = isDbAvailable();
  if (!avail.available) return avail;

  let tmp = '';
  try {
    tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'x4db-'));
    const db = openStudioDb(tmp);
    if (!db) return { available: true, pass: false, checks: { open: false } };

    bindGamePath(db, 'G:/test/X4');

    // Fixture mirrors of the in-memory structures.
    cacheObjectIndex(db, [
      { kind: 'ship', id: 'ship_arg_s_fighter_01_macro', name: 'Eclipse' },
      { kind: 'ship', id: 'ship_par_s_fighter_02_macro', name: 'Pulsar' },
      { kind: 'ware', id: 'energycells', name: 'Energy Cells' },
      { kind: 'faction', id: 'argon', name: 'Argon Federation' }
    ]);
    cacheExtensions(db,
      [
        { folder: 'mod_a', content_id: 'mod_a', enabled: true, deps: [{ id: 'ghost_dep', optional: false }] },
        { folder: 'mod_b', content_id: 'mod_b', enabled: true, deps: [] }
      ],
      [
        { folder: 'mod_a', rel_path: 'libraries/jobs.xml', is_diff: true, selectors: ['/jobs'] },
        { folder: 'mod_b', rel_path: 'libraries/jobs.xml', is_diff: true, selectors: ['/jobs'] },
        { folder: 'mod_b', rel_path: 'md/only_b.xml', is_diff: false, selectors: [] }
      ]
    );
    recordSourceStamps(db, [{ path: '01.cat', mtime: 12345 }]);

    const counts = objectIndexCounts(db);
    const q = queryObjectIndex(db, { kind: 'ship', q: 'fighter', limit: 10 });
    const contested = contestedPaths(db);
    const missing = unresolvedDependencies(db);

    const checks: Record<string, boolean> = {
      counts: counts['ship'] === 2 && counts['ware'] === 1 && counts['faction'] === 1,
      query: q.length === 2 && q.every(r => r.kind === 'ship'),
      pointLookup: objectExists(db, 'faction', 'argon') && !objectExists(db, 'faction', 'nope'),
      contested: contested.length === 1 && contested[0].rel_path === 'libraries/jobs.xml' && contested[0].folders.length === 2,
      missingDep: missing.length === 1 && missing[0].dep_id === 'ghost_dep' && !missing[0].optional,
      mtimeHit: sourcesUnchanged(db, [{ path: '01.cat', mtime: 12345 }]),
      mtimeMiss: !sourcesUnchanged(db, [{ path: '01.cat', mtime: 99999 }]),
      gamePathWipe: (() => {
        bindGamePath(db, 'H:/other/X4'); // changed path must wipe the cache
        return objectIndexCounts(db)['ship'] === undefined;
      })()
    };
    db.raw.close();
    return { available: true, pass: Object.values(checks).every(Boolean), checks };
  } catch (err: any) {
    return { available: true, pass: false, checks: { exception: false }, reason: err?.message || String(err) };
  } finally {
    if (tmp) { try { fs.rmSync(tmp, { recursive: true, force: true }); } catch { /* best effort */ } }
  }
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * P1 transport remainder — file-bridge polling composite.
 *
 * This does not replace the existing HTTP/JSON contract seam in contractGlue. It
 * covers the narrow offline fallback shape: write a request file, poll on a
 * bounded interval, and keep a whitelist of action ids the bridge may execute.
 */

import { endpointEventNames } from './contractEvents';

export interface FileBridgePollingOptions {
  namespace: string;
  actionId: string;
  directory: string;
  requestFile: string;
  responseFile: string;
  requestPayloadExpr: string;
  pollInterval: string;
  timeout: string;
}

export interface FileBridgeActionWhitelist {
  namespace: string;
  actions: string[];
}

const ID_RE = /^[a-z][a-z0-9_]*$/;
const FILE_RE = /^[a-z0-9_.-]+$/;
const DIR_RE = /^[a-z0-9_.-]+$/;

function escapeXmlAttr(value: string): string {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function x4String(value: string): string {
  return `'${String(value).replace(/'/g, "\\'")}'`;
}

function safeTime(value: string, fallback: string): string {
  const s = String(value || '').trim();
  if (!s) return fallback;
  if (/^\d+(\.\d+)?$/.test(s)) return `${s}s`;
  return s;
}

export function validateFileBridgePollingOptions(options: FileBridgePollingOptions): string[] {
  const errors: string[] = [];
  if (!ID_RE.test(options.namespace || '')) errors.push('namespace must be lowercase snake_case and start with a letter.');
  if (!ID_RE.test(options.actionId || '')) errors.push('actionId must be lowercase snake_case and start with a letter.');
  if (!DIR_RE.test(options.directory || '')) errors.push('directory must be a safe single folder name.');
  if (!FILE_RE.test(options.requestFile || '')) errors.push('requestFile must be a safe file name.');
  if (!FILE_RE.test(options.responseFile || '')) errors.push('responseFile must be a safe file name.');
  if (!String(options.requestPayloadExpr || '').trim()) errors.push('requestPayloadExpr is required.');
  return errors;
}

/**
 * MD action subgraph fragment. Intended for a custom_xml action node or direct
 * contract preview: request write, bounded poll loop, and explicit timeout event.
 */
export function buildFileBridgePollingSubgraph(options: FileBridgePollingOptions): string {
  const errors = validateFileBridgePollingOptions(options);
  if (errors.length) throw new Error(`Invalid file bridge polling options: ${errors.join(' ')}`);

  const ev = endpointEventNames(options.namespace, options.actionId);
  const deadline = `$${options.actionId}_file_bridge_deadline`;
  const poll = safeTime(options.pollInterval, '1s');
  const timeout = safeTime(options.timeout, '10s');
  const payloadExpr = escapeXmlAttr(options.requestPayloadExpr);
  const pollParam = `table[action=${x4String(options.actionId)}, request=${x4String(options.requestFile)}, response=${x4String(options.responseFile)}]`;

  return [
    `<set_value name="${deadline}" exact="player.age + ${escapeXmlAttr(timeout)}" />`,
    `<debug_to_file directory="${escapeXmlAttr(x4String(options.directory))}" name="${escapeXmlAttr(x4String(options.requestFile))}" text="${payloadExpr}" output="false" append="false" />`,
    `<do_while value="player.age lt ${deadline}">`,
    `  <delay exact="${escapeXmlAttr(poll)}" />`,
    `  <raise_lua_event name="${escapeXmlAttr(x4String(`${ev.request}.poll`))}" param="${escapeXmlAttr(pollParam)}" />`,
    `</do_while>`,
    `<raise_lua_event name="${escapeXmlAttr(x4String(`${ev.request}.timeout`))}" param="${escapeXmlAttr(x4String(`timeout waiting for ${options.responseFile}`))}" />`,
  ].join('\n');
}

export function validateActionWhitelist(whitelist: FileBridgeActionWhitelist): string[] {
  const errors: string[] = [];
  if (!ID_RE.test(whitelist.namespace || '')) errors.push('namespace must be lowercase snake_case and start with a letter.');
  const seen = new Set<string>();
  for (const action of whitelist.actions || []) {
    if (!ID_RE.test(action)) errors.push(`invalid action id "${action}".`);
    if (seen.has(action)) errors.push(`duplicate action id "${action}".`);
    seen.add(action);
  }
  if (seen.size === 0) errors.push('at least one whitelisted action is required.');
  return errors;
}

export function buildActionWhitelistLua(whitelist: FileBridgeActionWhitelist): string {
  const errors = validateActionWhitelist(whitelist);
  if (errors.length) throw new Error(`Invalid file bridge action whitelist: ${errors.join(' ')}`);
  const lines = [
    `-- File-bridge action whitelist for ${whitelist.namespace}`,
    `local ALLOWED_ACTIONS = {`,
    ...whitelist.actions.map(action => `  [${JSON.stringify(action)}] = true,`),
    `}`,
    ``,
    `local function isAllowedAction(action)`,
    `  return ALLOWED_ACTIONS[tostring(action or "")] == true`,
    `end`,
  ];
  return lines.join('\n');
}

export function runFileBridgeTransportSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const opts: FileBridgePollingOptions = {
    namespace: 'myai',
    actionId: 'send_prompt',
    directory: 'x4_forge_bridge',
    requestFile: 'send_prompt_request.json',
    responseFile: 'send_prompt_response.json',
    requestPayloadExpr: `table[action='send_prompt', text=$text, quote='"<&']`,
    pollInterval: '0.5',
    timeout: '12',
  };

  let xml = '';
  let threw = false;
  try { xml = buildFileBridgePollingSubgraph(opts); } catch { threw = true; }
  ok('polling_subgraph_generates', !threw && xml.length > 0);
  ok('writes_request_file', xml.includes('<debug_to_file') && xml.includes(`name="'send_prompt_request.json'"`));
  ok('polls_with_timeout', xml.includes('<do_while value="player.age lt $send_prompt_file_bridge_deadline">') && xml.includes('<delay exact="0.5s" />'));
  ok('emits_timeout_event', xml.includes(`'myai.send_prompt.timeout'`) && xml.includes('timeout waiting for send_prompt_response.json'));
  ok('escapes_payload_xml', xml.includes('&quot;') && xml.includes('&lt;') && xml.includes('&amp;'));
  ok('poll_event_uses_contract_names', xml.includes(`'myai.send_prompt.poll'`) && xml.includes(`action=\\'send_prompt\\'`) === false);

  const bad = validateFileBridgePollingOptions({ ...opts, actionId: '../bad' });
  ok('validator_blocks_unsafe_action', bad.some(e => /actionId/.test(e)), bad);

  let lua = '';
  let luaThrew = false;
  try { lua = buildActionWhitelistLua({ namespace: 'myai', actions: ['send_prompt', 'get_status'] }); } catch { luaThrew = true; }
  ok('whitelist_lua_generates', !luaThrew && lua.includes('ALLOWED_ACTIONS'));
  ok('whitelist_contains_only_declared_actions', lua.includes('["send_prompt"] = true') && lua.includes('["get_status"] = true') && !lua.includes('delete_file'));
  ok('whitelist_validator_blocks_duplicates', validateActionWhitelist({ namespace: 'myai', actions: ['a', 'a'] }).some(e => /duplicate/.test(e)));

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, pass: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * #64 Phase 1 (GLM Tier A #1) — read-only galaxy/sector MAP, deterministic core.
 *
 * Parses X4's universe macro files into a flat, positioned cluster/sector graph for a
 * 2D map view. This is the VIEWER foundation only — displaying already-correct game
 * data, so there is no "valid-XML ≠ correct-placement" problem here (that lives in the
 * deferred Phase 2 editor). Grounded against the real installed files (probed via
 * /api/agent/catdat-debug?file=maps/xu_ep2_universe/...):
 *   - galaxy.xml:   <macro class="galaxy"> with <connection ref="clusters"> children,
 *                   each carrying an optional <offset><position x y z/></offset>
 *                   (absent ⇒ origin, e.g. Cluster_01) and a <macro ref="Cluster_NN_macro"/>.
 *   - clusters.xml: <macro class="cluster"> with <connection ref="sectors"> children,
 *                   each with its own offset (relative to the cluster) + sector macro ref.
 * Sector absolute position = cluster position + sector offset. X4's map plane is X/Z
 * (Y is "up"); the renderer projects on x/z. Coords are in metres (~1.5e7 between clusters).
 *
 * Pure: no fs/network — the caller supplies the two XML strings. xmldom (not regex)
 * because the macro tree nests (station/region macros live inside connections we skip).
 * House pattern: engine + runGalaxyMapSelftest() over a synthetic fixture + public GET.
 */

import { DOMParser } from '@xmldom/xmldom';

export interface Vec3 { x: number; y: number; z: number }

export interface UniverseConnection {
  name?: string;
  /** what this connection slots into: "clusters" | "sectors" | "regions" | ... */
  ref?: string;
  /** the referenced child macro name (the connection's <macro ref=.../>) */
  macroRef: string;
  /** placement offset for the child; null when no <offset> is present (⇒ origin). */
  offset: Vec3 | null;
}

export interface UniverseMacro {
  name: string;
  class?: string;
  connections: UniverseConnection[];
}

export interface GalaxyCluster {
  /** cluster macro name, e.g. "Cluster_01_macro" */
  macro: string;
  pos: Vec3;
  sectors: GalaxySector[];
}

export interface GalaxySector {
  /** sector macro name, e.g. "Cluster_01_Sector001_macro" */
  macro: string;
  /** owning cluster macro */
  cluster: string;
  /** ABSOLUTE position (cluster pos + sector offset) */
  pos: Vec3;
}

export interface GalaxyMap {
  clusters: GalaxyCluster[];
  /** flattened sectors with absolute positions, for direct rendering */
  sectors: GalaxySector[];
  /** x/z bounds across all sectors (for map fit-to-view); zeros when empty */
  bounds: { minX: number; maxX: number; minZ: number; maxZ: number };
  counts: { clusters: number; sectors: number; placedClusters: number };
  sources?: GalaxyMapSourceSummary;
}

export interface GalaxyMapSource {
  path: string;
  text: string;
  source?: string;
}

export interface GalaxyMapSourceSummary {
  baseFiles: number;
  extensionFiles: number;
  galaxyDiffsApplied: number;
  clusterMacroFilesApplied: number;
  galaxyConnectionsAdded: number;
  clusterMacrosAdded: number;
  ignoredFiles: string[];
  appliedFiles: string[];
}

const ZERO: Vec3 = { x: 0, y: 0, z: 0 };

/** Direct element children of `el` with the given tag (non-recursive). */
function directChildren(el: any, tag: string): any[] {
  const out: any[] = [];
  const kids = el?.childNodes;
  if (!kids) return out;
  for (let i = 0; i < kids.length; i++) {
    const n = kids[i];
    if (n && n.nodeType === 1 && (n.nodeName === tag || n.localName === tag)) out.push(n);
  }
  return out;
}

function num(v: string | null | undefined): number {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

/** Read a connection's <offset><position x y z/></offset>, or null if absent. */
function readOffset(connEl: any): Vec3 | null {
  const offset = directChildren(connEl, 'offset')[0];
  if (!offset) return null;
  const pos = directChildren(offset, 'position')[0];
  if (!pos) return null;
  return { x: num(pos.getAttribute('x')), y: num(pos.getAttribute('y')), z: num(pos.getAttribute('z')) };
}

/**
 * Parse an X4 universe macro file (<macros><macro ...>) into top-level macros with
 * their direct connections. Tolerant of recoverable parse noise; returns [] on failure.
 */
export function parseUniverseMacros(xml: string): UniverseMacro[] {
  if (!xml || typeof xml !== 'string') return [];
  let doc: any;
  try {
    doc = new DOMParser({ onError: () => { /* tolerate recoverable noise */ } })
      .parseFromString(xml, 'text/xml');
  } catch { return []; }
  const root = doc?.documentElement;
  if (!root) return [];

  const macros: UniverseMacro[] = [];
  for (const macroEl of directChildren(root, 'macro')) {
    const name = macroEl.getAttribute('name') || '';
    if (!name) continue;
    const cls = macroEl.getAttribute('class') || undefined;
    const connections: UniverseConnection[] = [];
    // a macro has one <connections> wrapper holding <connection> children
    for (const connsWrap of directChildren(macroEl, 'connections')) {
      for (const connEl of directChildren(connsWrap, 'connection')) {
        const childMacro = directChildren(connEl, 'macro')[0];
        const macroRef = childMacro?.getAttribute('ref') || '';
        if (!macroRef) continue; // skip connections without a referenced macro
        connections.push({
          name: connEl.getAttribute('name') || undefined,
          ref: connEl.getAttribute('ref') || undefined,
          macroRef,
          offset: readOffset(connEl),
        });
      }
    }
    macros.push({ name, class: cls, connections });
  }
  return macros;
}

/**
 * Build the positioned cluster/sector map from galaxy.xml + clusters.xml.
 * Cluster pos = galaxy-macro cluster-connection offset (origin if none).
 * Sector pos = cluster pos + cluster-macro sector-connection offset (origin if none).
 */
export function buildGalaxyMap(galaxyXml: string, clustersXml: string): GalaxyMap {
  const galaxyMacros = parseUniverseMacros(galaxyXml);
  const clusterMacros = parseUniverseMacros(clustersXml);
  return buildGalaxyMapFromMacros(galaxyMacros, clusterMacros);
}

function buildGalaxyMapFromMacros(galaxyMacros: UniverseMacro[], clusterMacros: UniverseMacro[]): GalaxyMap {
  // cluster macro name -> its sector connections (from clusters.xml)
  const clusterByName = new Map<string, UniverseMacro>();
  for (const m of clusterMacros) clusterByName.set(m.name, m);

  // galaxy macro: the one of class "galaxy" (fallback: first macro with cluster refs)
  const galaxy = galaxyMacros.find(m => m.class === 'galaxy')
    || galaxyMacros.find(m => m.connections.some(c => c.ref === 'clusters'))
    || galaxyMacros[0];

  const clusters: GalaxyCluster[] = [];
  const sectors: GalaxySector[] = [];
  let placedClusters = 0;

  const clusterConns = (galaxy?.connections || []).filter(c => c.ref === 'clusters');
  for (const cc of clusterConns) {
    const cpos = cc.offset || ZERO;
    if (cc.offset) placedClusters++;
    const clusterMacro = clusterByName.get(cc.macroRef);
    const clusterSectors: GalaxySector[] = [];
    if (clusterMacro) {
      for (const sc of clusterMacro.connections.filter(c => c.ref === 'sectors')) {
        const so = sc.offset || ZERO;
        const sector: GalaxySector = {
          macro: sc.macroRef,
          cluster: cc.macroRef,
          pos: { x: cpos.x + so.x, y: cpos.y + so.y, z: cpos.z + so.z },
        };
        clusterSectors.push(sector);
        sectors.push(sector);
      }
    }
    clusters.push({ macro: cc.macroRef, pos: { ...cpos }, sectors: clusterSectors });
  }

  let minX = Infinity, maxX = -Infinity, minZ = Infinity, maxZ = -Infinity;
  for (const s of sectors) {
    if (s.pos.x < minX) minX = s.pos.x;
    if (s.pos.x > maxX) maxX = s.pos.x;
    if (s.pos.z < minZ) minZ = s.pos.z;
    if (s.pos.z > maxZ) maxZ = s.pos.z;
  }
  const bounds = sectors.length
    ? { minX, maxX, minZ, maxZ }
    : { minX: 0, maxX: 0, minZ: 0, maxZ: 0 };

  return { clusters, sectors, bounds, counts: { clusters: clusters.length, sectors: sectors.length, placedClusters } };
}

function cloneMacro(macro: UniverseMacro): UniverseMacro {
  return {
    name: macro.name,
    class: macro.class,
    connections: macro.connections.map(c => ({
      name: c.name,
      ref: c.ref,
      macroRef: c.macroRef,
      offset: c.offset ? { ...c.offset } : null,
    })),
  };
}

function parseGalaxyConnectionAdds(diffXml: string): UniverseConnection[] {
  if (!diffXml || typeof diffXml !== 'string') return [];
  let doc: ReturnType<DOMParser['parseFromString']>;
  try {
    doc = new DOMParser({ onError: () => { /* tolerate recoverable noise */ } })
      .parseFromString(diffXml, 'text/xml');
  } catch { return []; }
  const root = doc?.documentElement;
  if (!root || root.nodeName !== 'diff') return [];

  const out: UniverseConnection[] = [];
  for (const addEl of directChildren(root, 'add')) {
    const sel = String(addEl.getAttribute('sel') || '');
    if (!/\/macros\/macro\[@name=['"]XU_EP2_universe_macro['"]\]\/connections/i.test(sel)) continue;
    for (const connEl of directChildren(addEl, 'connection')) {
      if (connEl.getAttribute('ref') !== 'clusters') continue;
      const childMacro = directChildren(connEl, 'macro')[0];
      const macroRef = childMacro?.getAttribute('ref') || '';
      if (!macroRef) continue;
      out.push({
        name: connEl.getAttribute('name') || undefined,
        ref: connEl.getAttribute('ref') || undefined,
        macroRef,
        offset: readOffset(connEl),
      });
    }
  }
  return out;
}

function isGalaxyDiffSource(source: GalaxyMapSource): boolean {
  return /(^|\/)galaxy\.xml$/i.test(source.path) && /<diff[\s>]/i.test(source.text);
}

function isClusterMacroSource(source: GalaxyMapSource): boolean {
  return /(^|\/)(clusters|[^/]*_clusters)\.xml$/i.test(source.path) && /<macros[\s>]/i.test(source.text);
}

/**
 * Merge the base universe map with extension/DLC map sources.
 * Real DLC shape observed in packed archives:
 *   - maps/xu_ep2_universe/galaxy.xml is a <diff> adding cluster connections.
 *   - maps/xu_ep2_universe/*_clusters.xml is a standalone <macros> file with cluster macros.
 */
export function buildMergedGalaxyMap(baseGalaxyXml: string, baseClustersXml: string, extensionSources: GalaxyMapSource[]): GalaxyMap {
  const galaxyMacros = parseUniverseMacros(baseGalaxyXml).map(cloneMacro);
  const clusterMacros = parseUniverseMacros(baseClustersXml).map(cloneMacro);
  const galaxy = galaxyMacros.find(m => m.class === 'galaxy')
    || galaxyMacros.find(m => m.connections.some(c => c.ref === 'clusters'))
    || galaxyMacros[0];

  const summary: GalaxyMapSourceSummary = {
    baseFiles: 2,
    extensionFiles: extensionSources.length,
    galaxyDiffsApplied: 0,
    clusterMacroFilesApplied: 0,
    galaxyConnectionsAdded: 0,
    clusterMacrosAdded: 0,
    ignoredFiles: [],
    appliedFiles: [],
  };

  for (const source of extensionSources) {
    const normalizedPath = source.path.replace(/\\/g, '/');
    if (isGalaxyDiffSource({ ...source, path: normalizedPath })) {
      const adds = parseGalaxyConnectionAdds(source.text);
      if (adds.length && galaxy) {
        galaxy.connections.push(...adds);
        summary.galaxyDiffsApplied += 1;
        summary.galaxyConnectionsAdded += adds.length;
        summary.appliedFiles.push(source.source || normalizedPath);
      } else {
        summary.ignoredFiles.push(source.source || normalizedPath);
      }
      continue;
    }

    if (isClusterMacroSource({ ...source, path: normalizedPath })) {
      const macros = parseUniverseMacros(source.text).filter(m => m.class === 'cluster' || m.connections.some(c => c.ref === 'sectors'));
      if (macros.length) {
        clusterMacros.push(...macros.map(cloneMacro));
        summary.clusterMacroFilesApplied += 1;
        summary.clusterMacrosAdded += macros.length;
        summary.appliedFiles.push(source.source || normalizedPath);
      } else {
        summary.ignoredFiles.push(source.source || normalizedPath);
      }
      continue;
    }

    summary.ignoredFiles.push(source.source || normalizedPath);
  }

  const map = buildGalaxyMapFromMacros(galaxyMacros, clusterMacros);
  return { ...map, sources: summary };
}

/* ------------------------------------------------------------------ *
 * Deterministic oracle over a synthetic fixture that mirrors the real
 * galaxy.xml / clusters.xml shapes (origin-default cluster, offset cluster,
 * composed sector positions, skipped non-sector connections).
 * House shape: { allPassed, pass, passed, total, checks[] }.
 * ------------------------------------------------------------------ */
export function runGalaxyMapSelftest(): {
  allPassed: boolean; pass: boolean; passed: number; total: number;
  checks: { name: string; pass: boolean; detail?: string }[];
} {
  const checks: { name: string; pass: boolean; detail?: string }[] = [];
  const ok = (name: string, cond: boolean, detail?: string) => checks.push({ name, pass: !!cond, detail });

  // Cluster_01: no offset (⇒ origin). Cluster_02: offset 15e6,0,25.98e6 (real-shaped).
  const galaxyXml = `<?xml version="1.0" encoding="utf-8"?>
<macros>
  <macro name="XU_universe_macro" class="galaxy">
    <component ref="standardgalaxy" />
    <connections>
      <connection name="Cluster_01_connection" ref="clusters">
        <macro ref="Cluster_01_macro" connection="galaxy" />
      </connection>
      <connection name="Cluster_02_connection" ref="clusters">
        <offset><position x="15000000" y="0" z="25980000" /></offset>
        <macro ref="Cluster_02_macro" connection="galaxy" />
      </connection>
    </connections>
  </macro>
</macros>`;

  const clustersXml = `<?xml version="1.0" encoding="utf-8"?>
<macros>
  <macro name="Cluster_01_macro" class="cluster">
    <connections>
      <connection name="C01_Sector001_connection" ref="sectors">
        <macro ref="Cluster_01_Sector001_macro" connection="cluster" />
      </connection>
      <connection name="C01_Sector002_connection" ref="sectors">
        <offset><position x="1000" y="0" z="2000" /></offset>
        <macro ref="Cluster_01_Sector002_macro" connection="cluster" />
      </connection>
      <connection name="C01_region" ref="regions">
        <offset><position x="500" y="0" z="500" /></offset>
        <macro ref="some_region_macro" connection="cluster" />
      </connection>
    </connections>
  </macro>
  <macro name="Cluster_02_macro" class="cluster">
    <connections>
      <connection name="C02_Sector001_connection" ref="sectors">
        <offset><position x="-3000" y="0" z="4000" /></offset>
        <macro ref="Cluster_02_Sector001_macro" connection="cluster" />
      </connection>
    </connections>
  </macro>
</macros>`;

  const macros = parseUniverseMacros(galaxyXml);
  ok('parses the galaxy macro', macros.length === 1 && macros[0].class === 'galaxy');
  ok('parses cluster connections', macros[0].connections.filter(c => c.ref === 'clusters').length === 2);
  ok('connection with no offset → null', macros[0].connections.find(c => c.macroRef === 'Cluster_01_macro')?.offset === null);
  ok('connection offset parsed',
    macros[0].connections.find(c => c.macroRef === 'Cluster_02_macro')?.offset?.x === 15000000);

  const map = buildGalaxyMap(galaxyXml, clustersXml);
  ok('two clusters placed', map.counts.clusters === 2, JSON.stringify(map.counts));
  ok('placedClusters counts only those with an offset', map.counts.placedClusters === 1, String(map.counts.placedClusters));

  const c1 = map.clusters.find(c => c.macro === 'Cluster_01_macro')!;
  const c2 = map.clusters.find(c => c.macro === 'Cluster_02_macro')!;
  ok('Cluster_01 defaults to origin', c1.pos.x === 0 && c1.pos.z === 0);
  ok('Cluster_02 takes galaxy offset', c2.pos.x === 15000000 && c2.pos.z === 25980000, JSON.stringify(c2.pos));

  // sector position = cluster pos + sector offset
  const s1 = map.sectors.find(s => s.macro === 'Cluster_01_Sector001_macro')!; // c1 origin + no offset
  const s2 = map.sectors.find(s => s.macro === 'Cluster_01_Sector002_macro')!; // c1 origin + (1000,_,2000)
  const s3 = map.sectors.find(s => s.macro === 'Cluster_02_Sector001_macro')!; // c2 + (-3000,_,4000)
  ok('sector with no offset sits at its cluster', s1.pos.x === 0 && s1.pos.z === 0);
  ok('sector offset composes onto cluster', s2.pos.x === 1000 && s2.pos.z === 2000, JSON.stringify(s2.pos));
  ok('sector absolute = cluster + offset', s3.pos.x === 15000000 - 3000 && s3.pos.z === 25980000 + 4000, JSON.stringify(s3.pos));

  // region connections are NOT treated as sectors
  ok('non-sector (region) connection excluded', !map.sectors.some(s => s.macro === 'some_region_macro'));
  ok('total sectors = 3 (two in C01, one in C02; region skipped)', map.counts.sectors === 3, String(map.counts.sectors));

  // bounds span ALL sectors on x/z: min from the C01 origin sector, max from C02.
  ok('bounds minX is the origin sector (C01)', map.bounds.minX === 0, JSON.stringify(map.bounds));
  ok('bounds maxX from C02 sector', map.bounds.maxX === 15000000 - 3000, JSON.stringify(map.bounds));
  ok('bounds maxZ from C02 sector', map.bounds.maxZ === 25980000 + 4000, JSON.stringify(map.bounds));

  // degrades safely
  ok('empty/garbage input → empty map', buildGalaxyMap('', '').counts.sectors === 0 && parseUniverseMacros('<x/>').length === 0);

  // DLC/extension merge: real DLCs add galaxy cluster connections via a <diff>, then
  // ship the referenced clusters in standalone *_clusters.xml macro files.
  const dlcGalaxyDiff = `<?xml version="1.0" encoding="utf-8"?>
<diff>
  <add sel="/macros/macro[@name='XU_EP2_universe_macro']/connections">
    <connection name="Cluster_900_connection" ref="clusters">
      <offset><position x="42000000" y="0" z="-7000000" /></offset>
      <macro ref="Cluster_900_macro" connection="galaxy" />
    </connection>
  </add>
  <replace sel="/macros/macro[@name='XU_EP2_universe_macro']/component"><component ref="ignored"/></replace>
</diff>`;
  const dlcClusters = `<?xml version="1.0" encoding="utf-8"?>
<macros>
  <macro name="Cluster_900_macro" class="cluster">
    <connections>
      <connection name="C900_Sector001_connection" ref="sectors">
        <offset><position x="100" y="0" z="200" /></offset>
        <macro ref="Cluster_900_Sector001_macro" connection="cluster" />
      </connection>
    </connections>
  </macro>
</macros>`;
  const merged = buildMergedGalaxyMap(galaxyXml, clustersXml, [
    { path: 'maps/xu_ep2_universe/galaxy.xml', source: 'ego_dlc_test/galaxy.xml', text: dlcGalaxyDiff },
    { path: 'maps/xu_ep2_universe/dlc_test_clusters.xml', source: 'ego_dlc_test/dlc_test_clusters.xml', text: dlcClusters },
  ]);
  const dlcSector = merged.sectors.find(s => s.macro === 'Cluster_900_Sector001_macro');
  ok('extension merge adds galaxy diff cluster connection', merged.counts.clusters === 3, JSON.stringify(merged.counts));
  ok('extension merge adds standalone cluster macro sectors', merged.counts.sectors === 4, JSON.stringify(merged.counts));
  ok('extension sector absolute = DLC cluster offset + sector offset',
    dlcSector?.pos.x === 42000100 && dlcSector?.pos.z === -6999800, JSON.stringify(dlcSector?.pos));
  ok('extension merge summary counts applied files',
    merged.sources?.galaxyDiffsApplied === 1 && merged.sources.clusterMacroFilesApplied === 1
      && merged.sources.galaxyConnectionsAdded === 1 && merged.sources.clusterMacrosAdded === 1,
    JSON.stringify(merged.sources));
  ok('unsupported diff ops ignored safely',
    !merged.sources?.ignoredFiles.includes('ego_dlc_test/galaxy.xml') && merged.sources?.appliedFiles.length === 2,
    JSON.stringify(merged.sources));

  const passed = checks.filter(c => c.pass).length;
  const allPassed = passed === checks.length;
  return { allPassed, pass: allPassed, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * A4.9 — Intent-satisfaction checker. Closes the "valid-but-wrong" gap Codex
 * flagged: a workspace can be XSD-legal yet not do what the user asked (e.g.
 * "on game start, show help" compiling fine while the game-start trigger was
 * silently dropped). This decomposes the request into structured requirements,
 * each compiled to a DETERMINISTIC graph-pattern assertion. Requirements that
 * can't be reduced to a pattern are reported as 'not-verified' (AI-claimed),
 * never as satisfied — so a green Schema/Graph can never masquerade as "did
 * what you asked". Pure (no I/O); the shared basis for the review Intent verdict
 * and the Architect per-step done-checks.
 */
import { ModWorkspace } from '../types';

export type IntentCheckSpec =
  | { kind: 'nodePresent'; xmlTag: string }
  | { kind: 'nodePropPositive'; xmlTag: string; prop: string }
  | { kind: 'triggerWired'; xmlTag: string }
  | { kind: 'actionInChain'; xmlTag: string }
  | { kind: 'manual' };

export interface IntentRequirement {
  id: string;
  label: string;
  check: IntentCheckSpec;
}

export interface IntentRequirementResult {
  id: string;
  label: string;
  status: 'pass' | 'fail' | 'not-verified';
  detail?: string;
}

export interface IntentReport {
  results: IntentRequirementResult[];
  verdict: { status: 'pass' | 'warn' | 'fail' | 'not-checked'; errors: number; warnings: number; detail?: string };
}

function nodesByTag(ws: ModWorkspace, tag: string): any[] {
  return ((ws?.nodes || []) as any[]).filter(n => String(n?.xmlTag ?? '') === tag);
}

/** Event node-ids wired into a cue's condition port (cue.out_cond → event). */
function cueWiredEventIds(ws: ModWorkspace): Set<string> {
  const ids = new Set<string>();
  const cueIds = new Set(((ws?.nodes || []) as any[]).filter(n => n?.type === 'cue').map(n => n.id));
  for (const l of ((ws as any)?.links || [])) {
    if (cueIds.has(l.sourceNodeId) && l.sourcePortId === 'out_cond') ids.add(l.targetNodeId);
  }
  return ids;
}

/** Action node-ids reachable from a cue's action chain (cue.out_act → … out_next →). */
function cueChainActionIds(ws: ModWorkspace): Set<string> {
  const ids = new Set<string>();
  const links = ((ws as any)?.links || []);
  const cueIds = ((ws?.nodes || []) as any[]).filter(n => n?.type === 'cue').map(n => n.id);
  for (const cue of cueIds) {
    const queue = links.filter((l: any) => l.sourceNodeId === cue && l.sourcePortId === 'out_act').map((l: any) => l.targetNodeId);
    const seen = new Set<string>();
    while (queue.length) {
      const id = queue.shift();
      if (seen.has(id)) continue;
      seen.add(id);
      ids.add(id);
      for (const l of links) if (l.sourceNodeId === id && l.sourcePortId === 'out_next') queue.push(l.targetNodeId);
    }
  }
  return ids;
}

/** Run the deterministic requirement assertions against a workspace. */
export function checkIntent(ws: ModWorkspace, requirements: IntentRequirement[]): IntentReport {
  const reqs = Array.isArray(requirements) ? requirements : [];
  const wiredEvents = cueWiredEventIds(ws);
  const chainActions = cueChainActionIds(ws);

  const results: IntentRequirementResult[] = reqs.map(r => {
    const c = r.check;
    let status: 'pass' | 'fail' | 'not-verified' = 'not-verified';
    let detail: string | undefined;
    switch (c?.kind) {
      case 'manual':
        status = 'not-verified';
        detail = 'No deterministic check — AI-claimed only.';
        break;
      case 'nodePresent':
        status = nodesByTag(ws, c.xmlTag).length > 0 ? 'pass' : 'fail';
        break;
      case 'nodePropPositive': {
        const ok = nodesByTag(ws, c.xmlTag).some(n => {
          const v = String(n?.properties?.[c.prop] ?? '').trim();
          if (v === '') return false;
          const num = parseFloat(v);
          return isNaN(num) ? true : num > 0;
        });
        status = ok ? 'pass' : 'fail';
        break;
      }
      case 'triggerWired':
        status = nodesByTag(ws, c.xmlTag).some(n => wiredEvents.has(n.id)) ? 'pass' : 'fail';
        break;
      case 'actionInChain':
        status = nodesByTag(ws, c.xmlTag).some(n => chainActions.has(n.id)) ? 'pass' : 'fail';
        break;
      default:
        status = 'not-verified';
        detail = 'Unknown requirement kind — treated as unverifiable.';
    }
    return { id: r.id, label: r.label, status, detail };
  });

  const checkable = results.filter(r => r.status !== 'not-verified');
  const failed = checkable.filter(r => r.status === 'fail').length;
  const notVerified = results.filter(r => r.status === 'not-verified').length;

  let verdict: IntentReport['verdict'];
  if (reqs.length === 0) {
    verdict = { status: 'not-checked', errors: 0, warnings: 0, detail: 'No requirements supplied — intent not verified.' };
  } else if (failed > 0) {
    verdict = { status: 'fail', errors: failed, warnings: notVerified, detail: `${failed} required pattern(s) missing.` };
  } else if (checkable.length > 0) {
    verdict = { status: notVerified > 0 ? 'warn' : 'pass', errors: 0, warnings: notVerified };
  } else {
    verdict = { status: 'not-checked', errors: 0, warnings: notVerified, detail: 'All requirements are AI-claimed; none machine-verifiable.' };
  }
  return { results, verdict };
}

// ---------------------------------------------------------------------------
// Deterministic oracle (synthetic fixtures; no disk/AI/key).
// ---------------------------------------------------------------------------
function mkNode(id: string, type: string, xmlTag: string, props: Record<string, any> = {}): any {
  return { id, type, label: id, xmlTag, x: 0, y: 0, properties: props };
}
function mkWs(nodes: any[], links: any[] = []): ModWorkspace {
  return { id: 'ic', name: 'IntentSelftest', version: '1.0.0', author: 'oracle', description: '', nodes, links, uiWidgets: [], uiTheme: {} as any, templates: [] } as any;
}

export function runIntentCheckSelftest(): {
  allPassed: boolean; pass: boolean; passed: number; total: number;
  checks: { name: string; pass: boolean; detail?: string }[];
} {
  const checks: { name: string; pass: boolean; detail?: string }[] = [];
  const expect = (name: string, cond: boolean, detail?: string) => checks.push({ name, pass: !!cond, detail });

  // Satisfied workspace: cue ← event_game_started (wired), cue → show_help (action chain).
  const good = mkWs(
    [mkNode('cue_0', 'cue', 'cue', { name: 'Start' }), mkNode('ev_0', 'event', 'event_game_started', {}), mkNode('act_0', 'action', 'show_help', { text: 'Welcome' })],
    [
      { id: 'l1', sourceNodeId: 'cue_0', sourcePortId: 'out_cond', targetNodeId: 'ev_0', targetPortId: 'in_cond' },
      { id: 'l2', sourceNodeId: 'cue_0', sourcePortId: 'out_act', targetNodeId: 'act_0', targetPortId: 'in_act' },
    ],
  );
  const reqs: IntentRequirement[] = [
    { id: 'r1', label: 'Trigger on game start', check: { kind: 'triggerWired', xmlTag: 'event_game_started' } },
    { id: 'r2', label: 'Show a help message', check: { kind: 'actionInChain', xmlTag: 'show_help' } },
    { id: 'r3', label: 'Reward the player', check: { kind: 'nodePresent', xmlTag: 'reward_player' } }, // absent → fail
    { id: 'r4', label: 'Feels fun', check: { kind: 'manual' } }, // not-verifiable
  ];
  const gr = checkIntent(good, reqs);
  const byId = (id: string) => gr.results.find(r => r.id === id)?.status;
  expect('triggerWired pass', byId('r1') === 'pass', byId('r1'));
  expect('actionInChain pass', byId('r2') === 'pass', byId('r2'));
  expect('absent node → fail', byId('r3') === 'fail', byId('r3'));
  expect('manual → not-verified', byId('r4') === 'not-verified', byId('r4'));
  expect('overall verdict fail (1 missing)', gr.verdict.status === 'fail' && gr.verdict.errors === 1, JSON.stringify(gr.verdict));
  expect('manual counted as warning', gr.verdict.warnings === 1, JSON.stringify(gr.verdict));

  // CODEX SCENARIO: "on game start, show help" but the game-start trigger was dropped.
  // show_help present + wired, but no event_game_started → trigger requirement FAILS,
  // even though such a workspace is otherwise XSD-legal.
  const missingTrigger = mkWs(
    [mkNode('cue_0', 'cue', 'cue', { name: 'Start' }), mkNode('act_0', 'action', 'show_help', { text: 'Welcome' })],
    [{ id: 'l2', sourceNodeId: 'cue_0', sourcePortId: 'out_act', targetNodeId: 'act_0', targetPortId: 'in_act' }],
  );
  const mr = checkIntent(missingTrigger, [reqs[0], reqs[1]]);
  expect('Codex: missing game-start trigger → FAIL', mr.results.find(r => r.id === 'r1')?.status === 'fail', JSON.stringify(mr.results));
  expect('Codex: show_help still passes', mr.results.find(r => r.id === 'r2')?.status === 'pass');
  expect('Codex: overall intent FAIL', mr.verdict.status === 'fail');

  // All-satisfied case → pass.
  const ar = checkIntent(good, [reqs[0], reqs[1]]);
  expect('all checkable pass → pass', ar.verdict.status === 'pass' && ar.verdict.errors === 0, JSON.stringify(ar.verdict));

  // No requirements → not-checked (honest stub behavior).
  expect('no requirements → not-checked', checkIntent(good, []).verdict.status === 'not-checked');

  // nodePropPositive: reward_player with money>0 passes; money=0 fails.
  const rewardOk = mkWs([mkNode('a', 'action', 'reward_player', { money: '5000' })]);
  const rewardBad = mkWs([mkNode('a', 'action', 'reward_player', { money: '0' })]);
  expect('reward money>0 → pass', checkIntent(rewardOk, [{ id: 'x', label: 'reward', check: { kind: 'nodePropPositive', xmlTag: 'reward_player', prop: 'money' } }]).results[0].status === 'pass');
  expect('reward money=0 → fail', checkIntent(rewardBad, [{ id: 'x', label: 'reward', check: { kind: 'nodePropPositive', xmlTag: 'reward_player', prop: 'money' } }]).results[0].status === 'fail');

  const passed = checks.filter(c => c.pass).length;
  const allPassed = passed === checks.length;
  return { allPassed, pass: allPassed, passed, total: checks.length, checks };
}

// liveFixes.ts — T5 Live Fix Loop engine (Inc 1).
//
// Turns live debuglog telemetry into actionable, ATTRIBUTED fix cards:
// error line → known failure class → owning node (when locatable) → suggestion,
// with a mechanical auto-apply only where the result is statically verifiable.
//
// EXTENDS (not duplicates): logTelemetry supplies the parsed entries; the
// failure classes come from what the reference/XSD validators already catch
// (unknown macro, time-format, dangling cue, null cascades); jumps reuse the
// existing navigate-to-source sourceRef contract.
//
// HONESTY BOUNDS: only errors the rule table can attribute produce cards —
// unattributable third-party log noise yields NOTHING (it stays visible in the
// raw feed). autoApplicable is set only for mechanical, verifiable rewrites
// (e.g. bare number on a time-typed property → append "s").
//
// House pattern: pure engine + runLiveFixesSelftest() + public GET, THEN UI.

import type { ModWorkspace, MDNode } from '../types';

export interface LiveLogEntry {
  severity?: string;
  message: string;
}

export interface LiveFix {
  id: string;
  fixKind: 'time_format' | 'unknown_macro' | 'dangling_cue' | 'null_expression' | 'cue_error';
  /** The offending log line (trimmed). */
  logLine: string;
  /** Owning cue name when the line could be correlated. */
  cueName?: string;
  /** navigate-to-source payload when the owning node was located. */
  sourceRef?: { kind: string; id: string; label?: string };
  suggestion: string;
  /** True only for mechanical rewrites the validators can verify statically. */
  autoApplicable: boolean;
  /** Present when autoApplicable: the exact property rewrite to perform. */
  apply?: { nodeId: string; propertyKey: string; newValue: string };
}

const TIME_KEYS = ['duration', 'timeout', 'delay', 'interval', 'time'];

/** Nodes whose named property holds the given bare value. */
function findNodeByProperty(nodes: MDNode[], key: string, value: string): MDNode | undefined {
  return nodes.find(n => String((n.properties || ({} as any))[key] ?? '') === value);
}

function findNodeWithMacro(nodes: MDNode[], macro: string): MDNode | undefined {
  return nodes.find(n => String((n.properties || ({} as any)).macro ?? '').split(' (')[0] === macro);
}

function cueNameForLine(line: string, cueNames: string[]): string | undefined {
  const marker = line.match(/\[MDStudio\]\s*cue=(\w+)/i);
  if (marker) return marker[1];
  return cueNames.find(name => name && line.includes(name));
}

/**
 * Classify parsed log entries into attributed fix cards.
 * Pure: workspace and entries in, cards out. Unattributable lines yield nothing.
 */
export function classifyLiveFixes(entries: LiveLogEntry[], workspace: Pick<ModWorkspace, 'nodes'>): LiveFix[] {
  const nodes = workspace.nodes || [];
  const cueNames = nodes
    .filter(n => n.type === 'cue')
    .map(n => String((n.properties || ({} as any)).name ?? ''))
    .filter(Boolean);
  const fixes: LiveFix[] = [];
  const seen = new Set<string>();
  let counter = 0;

  for (const entry of entries) {
    const line = String(entry?.message ?? '').trim();
    if (!line) continue;
    const severity = String(entry?.severity ?? '').toLowerCase();
    const isError = severity === 'error' || /\berror\b/i.test(line);
    if (!isError) continue;

    const cueName = cueNameForLine(line, cueNames);
    let fix: LiveFix | null = null;

    // 1) time-format: Evaluated value '8' is not of type time
    const time = line.match(/value\s+'([\d.]+)'\s+is not of type time/i);
    if (time) {
      const bare = time[1];
      let owner: MDNode | undefined;
      let ownerKey: string | undefined;
      for (const key of TIME_KEYS) {
        owner = findNodeByProperty(nodes, key, bare);
        if (owner) { ownerKey = key; break; }
      }
      fix = {
        id: `fix_${counter++}`,
        fixKind: 'time_format',
        logLine: line,
        cueName,
        sourceRef: owner ? { kind: 'md_node', id: owner.id, label: owner.xmlTag } : undefined,
        suggestion: `X4 time values need a unit: "${bare}" should be "${bare}s".` +
          (owner ? ` Found on <${owner.xmlTag}> ${ownerKey}.` : ' No matching node property found — fix manually.'),
        autoApplicable: !!(owner && ownerKey),
        ...(owner && ownerKey ? { apply: { nodeId: owner.id, propertyKey: ownerKey, newValue: `${bare}s` } } : {})
      };
    }

    // 2) unknown macro
    if (!fix) {
      const macro = line.match(/(?:macro|template)\s+'?([\w.]+_macro)'?\s+(?:not found|unknown|could not be (?:found|resolved))/i)
        || line.match(/(?:failed to (?:find|resolve)|unknown)\s+macro\s+'?([\w.]+)'?/i);
      if (macro) {
        const name = macro[1];
        const owner = findNodeWithMacro(nodes, name);
        fix = {
          id: `fix_${counter++}`,
          fixKind: 'unknown_macro',
          logLine: line,
          cueName,
          sourceRef: owner ? { kind: 'md_node', id: owner.id, label: owner.xmlTag } : undefined,
          suggestion: `Macro "${name}" does not exist in this install. Open the node and re-pick it from the live index (the picker only offers real macros).`,
          autoApplicable: false
        };
      }
    }

    // 3) dangling cue reference
    if (!fix) {
      const cueRef = line.match(/cue\s+'?([\w.]+)'?\s+(?:not found|unknown|does not exist)/i);
      if (cueRef) {
        fix = {
          id: `fix_${counter++}`,
          fixKind: 'dangling_cue',
          logLine: line,
          cueName,
          suggestion: `Cue reference "${cueRef[1]}" doesn't resolve. Check the Cue Lineage Tree for dangling refs (it flags these statically too).`,
          autoApplicable: false
        };
      }
    }

    // 4) null-expression cascade — only when attributable to one of OUR cues
    if (!fix && cueName && /(?:is null|null is not|property\s+.*\s+not (?:found|defined))/i.test(line)) {
      fix = {
        id: `fix_${counter++}`,
        fixKind: 'null_expression',
        logLine: line,
        cueName,
        suggestion: `An expression in cue "${cueName}" evaluated to null — usually a cascade from an earlier failed action (check the cards above this one first).`,
        autoApplicable: false
      };
    }

    // 5) generic attributed cue error — our cue, error line, no specific class
    if (!fix && cueName) {
      fix = {
        id: `fix_${counter++}`,
        fixKind: 'cue_error',
        logLine: line,
        cueName,
        suggestion: `Error attributed to cue "${cueName}". Jump to it and inspect the action chain.`,
        autoApplicable: false
      };
    }

    // Unattributable error → NO card (honesty bound).
    if (fix) {
      const dedupe = fix.fixKind + '|' + (fix.sourceRef?.id || fix.cueName || fix.logLine.slice(0, 60));
      if (!seen.has(dedupe)) {
        seen.add(dedupe);
        fixes.push(fix);
      }
    }
  }
  return fixes;
}

/**
 * Apply a mechanical fix. Pure: returns a NEW workspace (caller owns undo via
 * the normal setWorkspace path). Throws if the fix is not auto-applicable or
 * the target node/property has changed since classification.
 */
export function applyLiveFix<T extends Pick<ModWorkspace, 'nodes'>>(workspace: T, fix: LiveFix): T {
  if (!fix.autoApplicable || !fix.apply) throw new Error('fix is not auto-applicable');
  const { nodeId, propertyKey, newValue } = fix.apply;
  const node = (workspace.nodes || []).find(n => n.id === nodeId);
  if (!node) throw new Error('target node no longer exists');
  const expectedOld = newValue.replace(/s$/, '');
  if (String((node.properties || ({} as any))[propertyKey] ?? '') !== expectedOld) {
    throw new Error('target property changed since classification — re-scan');
  }
  return {
    ...workspace,
    nodes: workspace.nodes.map(n =>
      n.id === nodeId ? { ...n, properties: { ...n.properties, [propertyKey]: newValue } } : n
    )
  };
}

// ---------------------------------------------------------------------------
// Selftest oracle — synthetic log + workspace fixtures.
// ---------------------------------------------------------------------------

export interface LiveFixesCheck { name: string; pass: boolean; detail?: string }

export function runLiveFixesSelftest(): { allPassed: boolean; pass: boolean; passed: number; total: number; checks: LiveFixesCheck[] } {
  const checks: LiveFixesCheck[] = [];
  const ok = (name: string, pass: boolean, detail?: string) => checks.push({ name, pass, detail });

  const ws: any = {
    nodes: [
      { id: 'cue1', type: 'cue', xmlTag: 'cue', properties: { name: 'BountyCue' } },
      { id: 'n1', type: 'action', xmlTag: 'show_help', properties: { text: 'hi', duration: '8' } },
      { id: 'n2', type: 'action', xmlTag: 'create_ship', properties: { macro: 'ship_xen_i_destroyer_01_macro' } }
    ]
  };

  const entries = [
    { severity: 'error', message: "Evaluated value '8' is not of type time" },
    { severity: 'error', message: "Error: macro 'ship_xen_i_destroyer_01_macro' not found in library" },
    { severity: 'error', message: "Error in MD cue BountyCue: property lookup failed: value is null" },
    { severity: 'error', message: "cue 'md.Missing.Target' not found" },
    { severity: 'error', message: 'completely unrelated third-party mod explosion' },
    { severity: 'info', message: '[MDStudio] cue=BountyCue fired' }
  ];

  const fixes = classifyLiveFixes(entries, ws);

  ok('exactly 4 cards (unattributable + info lines yield none)', fixes.length === 4,
    fixes.map(f => f.fixKind).join(','));

  const tf = fixes.find(f => f.fixKind === 'time_format');
  ok('time_format located the owning node and is auto-applicable',
    !!tf && tf.autoApplicable && tf.sourceRef?.id === 'n1' && tf.apply?.newValue === '8s',
    tf && tf.suggestion);

  const um = fixes.find(f => f.fixKind === 'unknown_macro');
  ok('unknown_macro attributed to the create_ship node, not auto',
    !!um && !um.autoApplicable && um.sourceRef?.id === 'n2');

  const ne = fixes.find(f => f.fixKind === 'null_expression');
  ok('null cascade attributed to our cue by name', !!ne && ne.cueName === 'BountyCue');

  const dc = fixes.find(f => f.fixKind === 'dangling_cue');
  ok('dangling cue reference produces a card', !!dc);

  // apply path
  if (tf) {
    const next = applyLiveFix(ws, tf);
    ok('applyLiveFix rewrites 8 → 8s immutably',
      next.nodes.find((n: any) => n.id === 'n1').properties.duration === '8s'
      && ws.nodes.find((n: any) => n.id === 'n1').properties.duration === '8');
    let threw = false;
    try { applyLiveFix(next, tf); } catch { threw = true; }
    ok('applyLiveFix refuses a stale fix (property already changed)', threw);
  } else {
    ok('applyLiveFix rewrites 8 → 8s immutably', false, 'no time fix to apply');
  }

  let threw2 = false;
  try { applyLiveFix(ws, fixes.find(f => f.fixKind === 'unknown_macro')!); } catch { threw2 = true; }
  ok('applyLiveFix refuses non-auto fixes', threw2);

  // dedupe: same error twice → one card
  const twice = classifyLiveFixes([entries[0], entries[0]], ws);
  ok('duplicate log lines dedupe to one card', twice.length === 1);

  const passed = checks.filter(c => c.pass).length;
  const allPassed = passed === checks.length;
  return { allPassed, pass: allPassed, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Tier 2 / T3.1 — log-telemetry parser engine.
 *
 * Parses raw X4 debug-log text into structured entries and correlates each one to the
 * mod's cues, so the studio can light up the cue-lineage tree from a log (static text
 * first; a live file-tail comes later). Pure and testable — no game required.
 *
 * Correlation has two paths:
 *   1. A deterministic studio marker `[MDStudio] cue=<Name> ...` (unambiguous — the
 *      studio can emit these from its own generated cues).
 *   2. A best-effort word-boundary match of any workspace cue name in the message.
 *
 * X4's log format is NOT a stable public contract, so the line parser is intentionally
 * forgiving: it recognises a leading `[Category]` and an optional numeric/clock
 * timestamp, and falls back to treating the whole line as the message.
 */

export type LogSeverity = 'error' | 'warning' | 'info';

export interface LogEntry {
  lineNo: number;
  raw: string;
  timestamp: string | null;
  category: string | null;
  severity: LogSeverity;
  message: string;
  /** Cue names this line is correlated to (marker + name matches, deduped). */
  cueNames: string[];
  /** The cue from a deterministic `[MDStudio] cue=…` marker, if present. */
  markerCue: string | null;
}

export interface CueTelemetry {
  name: string;
  hits: number;
  errors: number;
  warnings: number;
  lastLineNo: number;
}

export interface LogTelemetryResult {
  entries: LogEntry[];
  /** Per-cue summary, only for cues that actually appeared in the log. */
  cues: CueTelemetry[];
  totals: { lines: number; errors: number; warnings: number; correlatedCues: number };
}

const ERROR_RE = /(^|[^a-z])(error|exception|failed|failure|cannot|nil value|stack traceback)([^a-z]|$)/i;
const WARN_RE = /(^|[^a-z])(warn|warning|deprecated)([^a-z]|$)/i;
const CATEGORY_RE = /^\s*\[([^\]]{1,40})\]\s*(.*)$/;
const TS_RE = /^\s*((?:\d{1,7}(?:\.\d+)?)|(?:\d{1,2}:\d{2}:\d{2}(?:\.\d+)?))\s+(.*)$/;
const MARKER_RE = /\[MDStudio\][^\n]*?\bcue\s*=\s*([A-Za-z_][A-Za-z0-9_]*)/i;

function escapeRegExp(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function classifySeverity(category: string | null, message: string): LogSeverity {
  const cat = (category || '').toLowerCase();
  if (/error/.test(cat) || ERROR_RE.test(message)) return 'error';
  if (/warn/.test(cat) || WARN_RE.test(message)) return 'warning';
  return 'info';
}

/**
 * Parse log text and correlate to the given cue names. `cueNames` is the workspace's
 * list of cue `properties.name` values (used for best-effort message matching).
 */
export function parseLogTelemetry(logText: string, cueNames: string[]): LogTelemetryResult {
  const text = typeof logText === 'string' ? logText : '';
  const names = Array.from(new Set((cueNames || []).filter(n => n && typeof n === 'string')));
  // Precompile word-boundary matchers for each cue name (longest first, so e.g.
  // "Escort_Cue_2" is preferred over "Escort_Cue" — both can still match).
  const matchers = names
    .slice()
    .sort((a, b) => b.length - a.length)
    .map(n => ({ name: n, re: new RegExp('(^|[^A-Za-z0-9_])' + escapeRegExp(n) + '([^A-Za-z0-9_]|$)') }));

  const entries: LogEntry[] = [];
  const cueMap = new Map<string, CueTelemetry>();
  let errors = 0, warnings = 0;

  const lines = text.split(/\r?\n/);
  for (let i = 0; i < lines.length; i++) {
    const raw = lines[i];
    if (!raw || raw.trim().length === 0) continue;

    let rest = raw;
    let category: string | null = null;
    const cm = raw.match(CATEGORY_RE);
    if (cm) { category = cm[1].trim(); rest = cm[2]; }

    let timestamp: string | null = null;
    const tm = rest.match(TS_RE);
    if (tm) { timestamp = tm[1]; rest = tm[2]; }

    const message = rest.trim();
    const severity = classifySeverity(category, message);
    if (severity === 'error') errors++;
    else if (severity === 'warning') warnings++;

    // correlation
    const markerMatch = raw.match(MARKER_RE);
    const markerCue = markerMatch ? markerMatch[1] : null;
    const found = new Set<string>();
    if (markerCue) found.add(markerCue);
    for (const m of matchers) if (m.re.test(message)) found.add(m.name);
    const cueNamesForLine = Array.from(found);

    const entry: LogEntry = { lineNo: i + 1, raw, timestamp, category, severity, message, cueNames: cueNamesForLine, markerCue };
    entries.push(entry);

    for (const name of cueNamesForLine) {
      let t = cueMap.get(name);
      if (!t) { t = { name, hits: 0, errors: 0, warnings: 0, lastLineNo: 0 }; cueMap.set(name, t); }
      t.hits++;
      if (severity === 'error') t.errors++;
      else if (severity === 'warning') t.warnings++;
      t.lastLineNo = i + 1;
    }
  }

  const cues = Array.from(cueMap.values()).sort((a, b) => b.errors - a.errors || b.hits - a.hits);
  return { entries, cues, totals: { lines: entries.length, errors, warnings, correlatedCues: cues.length } };
}

/** Self-test oracle over synthetic X4-style log text. */
export function runLogTelemetrySelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const cueNames = ['My_Startup_Cue', 'Escort_Cue', 'Build_Cue', 'Unused_Cue'];
  const log = [
    '[General] 100.5 Mission started for cue My_Startup_Cue',
    '[=ERROR=] 101.2 Script error in cue Escort_Cue: attempt to index a nil value',
    '[MDStudio] cue=Build_Cue event=fired payload=ok',
    '[General] 102.0 nothing interesting happened here',
    '   ',
    '[Scripts] 12:30:01 WARNING deprecated call near Escort_Cue'
  ].join('\n');

  const r = parseLogTelemetry(log, cueNames);

  ok('skips_blank_lines', r.entries.length === 5);
  ok('parses_category', r.entries[0].category === 'General');
  ok('parses_timestamp', r.entries[0].timestamp === '100.5');
  ok('clock_timestamp', r.entries[4].timestamp === '12:30:01');
  ok('error_severity', r.entries[1].severity === 'error');
  ok('warning_severity', r.entries[4].severity === 'warning');
  ok('info_severity', r.entries[3].severity === 'info');
  ok('correlates_by_name', r.entries[0].cueNames.indexOf('My_Startup_Cue') !== -1);
  ok('correlates_by_marker', r.entries[2].markerCue === 'Build_Cue' && r.entries[2].cueNames.indexOf('Build_Cue') !== -1);
  ok('error_cue_attributed', !!r.cues.find(c => c.name === 'Escort_Cue' && c.errors === 1));
  ok('escort_cue_two_hits', !!r.cues.find(c => c.name === 'Escort_Cue' && c.hits === 2));
  ok('unused_cue_absent', !r.cues.find(c => c.name === 'Unused_Cue'));
  ok('totals_errors', r.totals.errors === 1);
  ok('totals_warnings', r.totals.warnings === 1);
  ok('cues_sorted_errors_first', r.cues.length > 0 && r.cues[0].name === 'Escort_Cue');
  ok('no_false_partial_match', parseLogTelemetry('cue MyStartupCueXYZ ran', ['My_Startup_Cue']).cues.length === 0);
  ok('empty_log_safe', parseLogTelemetry('', cueNames).entries.length === 0);

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * P2 — Lua logic authoring, blocks-first.
 *
 * These are structured Lua idiom blocks, not raw snippets: each block has a typed
 * config and compiles into a known-good Lua fragment. The output is still text
 * because Lua authoring needs a real script surface, but agents can compose the
 * script from deterministic blocks first.
 */

import { analyzeLuaFiles } from './luaStaticAnalysis';

export type LuaLogicBlockKind = 'event_handler' | 'djfhe_http_call' | 'json_parse' | 'response_poll';

export interface LuaLogicBlock {
  id: string;
  kind: LuaLogicBlockKind;
  title?: string;
  config: {
    namespace?: string;
    event?: string;
    functionName?: string;
    url?: string;
    payloadVar?: string;
    responseEvent?: string;
    errorEvent?: string;
    responseVar?: string;
    jsonTextVar?: string;
    outputVar?: string;
    intervalSeconds?: string;
    maxAttempts?: string;
  };
}

export interface LuaLogicScript {
  fileName: string;
  blocks: LuaLogicBlock[];
}

const ID_RE = /^[a-zA-Z_][a-zA-Z0-9_]*$/;

function luaString(value: string): string {
  return JSON.stringify(String(value ?? ''));
}

function fnName(value: string | undefined, fallback: string): string {
  const raw = String(value || fallback).trim();
  return ID_RE.test(raw) ? raw : fallback;
}

function numLiteral(value: string | undefined, fallback: string): string {
  const raw = String(value || '').trim();
  return /^\d+(\.\d+)?$/.test(raw) ? raw : fallback;
}

export function buildLuaLogicBlock(block: LuaLogicBlock): string {
  const c = block.config || {};
  switch (block.kind) {
    case 'event_handler': {
      const ns = c.namespace || 'ai_influence';
      const event = c.event || 'chat';
      const handler = fnName(c.functionName, `on_${event}`);
      return [
        `local function ${handler}(payload)`,
        `    payload = payload or {}`,
        `    DebugError(${luaString(`[${ns}] ${event} received`)})`,
        `    return payload`,
        `end`,
        ``,
        `RegisterEvent(${luaString(`${ns}.${event}`)}, function(_, payload)`,
        `    ${handler}(payload)`,
        `end)`,
      ].join('\n');
    }
    case 'djfhe_http_call': {
      const call = fnName(c.functionName, 'call_ai_influence');
      const payloadVar = fnName(c.payloadVar, 'payload');
      const responseEvent = c.responseEvent || 'chat.response';
      const errorEvent = c.errorEvent || 'chat.error';
      return [
        `local Request = require("djfhe.http.request")`,
        `local json = require("jsonlua.json")`,
        ``,
        `local function ${call}(${payloadVar})`,
        `    local body = json.encode(${payloadVar} or {})`,
        `    local request = Request:new({`,
        `        method = "POST",`,
        `        url = ${luaString(c.url || 'http://127.0.0.1:8713/v1/chat')},`,
        `        body = body,`,
        `        headers = { ["Content-Type"] = "application/json" }`,
        `    })`,
        `    request:send(function(response, err)`,
        `        if err ~= nil then`,
        `            AddUITriggeredEvent(${luaString(c.namespace || 'ai_influence')}, ${luaString(errorEvent)}, tostring(err))`,
        `            return`,
        `        end`,
        `        AddUITriggeredEvent(${luaString(c.namespace || 'ai_influence')}, ${luaString(responseEvent)}, response and response:getBody() or "")`,
        `    end)`,
        `end`,
      ].join('\n');
    }
    case 'json_parse': {
      const parser = fnName(c.functionName, 'parse_chat_response');
      const input = fnName(c.jsonTextVar, 'jsonText');
      const output = fnName(c.outputVar, 'decoded');
      return [
        `local function ${parser}(${input})`,
        `    local ok, ${output} = pcall(json.decode, ${input} or "{}")`,
        `    if not ok then`,
        `        DebugError("AI Influence JSON parse failed: " .. tostring(${output}))`,
        `        return { ok = false }`,
        `    end`,
        `    return ${output}`,
        `end`,
      ].join('\n');
    }
    case 'response_poll': {
      const poller = fnName(c.functionName, 'poll_chat_response');
      const interval = numLiteral(c.intervalSeconds, '0.5');
      const maxAttempts = numLiteral(c.maxAttempts, '20');
      return [
        `local function ${poller}(readResponse)`,
        `    local attempts = 0`,
        `    while attempts < ${maxAttempts} do`,
        `        attempts = attempts + 1`,
        `        local response = readResponse and readResponse() or nil`,
        `        if response ~= nil and response ~= "" then return response end`,
        `        -- X4 UI Lua has no blocking sleep here; caller wires this through update ticks.`,
        `        DebugError("AI Influence poll attempt " .. tostring(attempts) .. " interval ${interval}s")`,
        `    end`,
        `    return nil`,
        `end`,
      ].join('\n');
    }
    default:
      return '';
  }
}

export function buildLuaLogicScript(script: LuaLogicScript): string {
  const blocks = script.blocks || [];
  return [
    `-- ${script.fileName || 'ai_influence_chat.lua'}`,
    `-- Generated by X4 Forge structured Lua logic blocks.`,
    ``,
    ...blocks.map(buildLuaLogicBlock),
    ``,
    `return {`,
    `    blocks = ${blocks.length}`,
    `}`,
    ``,
  ].join('\n\n');
}

export function aiInfluenceChatBlocks(): LuaLogicScript {
  return {
    fileName: 'ai_influence_chat.lua',
    blocks: [
      { id: 'on_chat', kind: 'event_handler', title: 'Receive MD chat request',
