export type LuaSnippetCategory = 'events' | 'http' | 'menu' | 'lifecycle';

export interface LuaSnippet {
  id: string;
  title: string;
  category: LuaSnippetCategory;
  description: string;
  /** <UPPERCASE> tokens the user fills in. */
  placeholders: string[];
  lua: string;
}

