  ok('fill_replaces_tokens', filled.includes('myext.get_status') && !filled.includes('<NS>'));

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Deterministic Lua static analysis for Extension Doctor.
 *
 * Layer 1: baseline Lua hygiene from luaparse (syntax + undefined globals).
 * Layer 2: Forge-native X4 rules for engine/runtime hazards.
 *
 * Globals are intentionally deterministic: a fixed seed of Lua/X4 globals plus
 * global definitions discovered from the scanned installed Lua files. AI can
 * suggest candidates later, but those suggestions must not silently enter this
 * allowlist.
 */

import { parse } from 'luaparse';

export interface LuaFileInput {
  rel: string;
  text: string;
  source: 'loose' | 'packed';
  sourcePath: string;
  extension: { folder: string; id: string; name?: string };
}

export interface LuaStaticFinding {
  layer: 'baseline' | 'x4';
  severity: 'error' | 'warning' | 'info';
  code: string;
  rel: string;
  message: string;
  symbol?: string;
  line?: number;
  column?: number;
  source: 'loose' | 'packed';
  sourcePath: string;
}

export interface LuaStaticAnalysisResult {
  filesScanned: number;
  globalAllowlistSize: number;
  findings: LuaStaticFinding[];
}

const LUA_STANDARD_GLOBALS = new Set([
  '_G', '_VERSION',
  'assert', 'collectgarbage', 'dofile', 'error', 'getfenv', 'getmetatable', 'ipairs',
  'load', 'loadfile', 'loadstring', 'module', 'next', 'pairs', 'pcall', 'print',
  'rawequal', 'rawget', 'rawset', 'require', 'select', 'setfenv', 'setmetatable',
  'tonumber', 'tostring', 'type', 'unpack', 'xpcall',
  'coroutine', 'debug', 'io', 'math', 'os', 'package', 'string', 'table'
]);

const X4_ENGINE_GLOBALS = new Set([
  'AddUITriggeredEvent', 'DebugError', 'DebugText', 'GetCurTime', 'GetNPCBlackboard',
  'GetPlayerID', 'Helper', 'IsValidWidgetElement', 'OnlineGetUserItemAmount',
  'OnlineGetUserItems', 'RegisterEvent', 'RemoveEvent', 'SetNPCBlackboard',
  'SetScript', 'SignalObject', 'TraceBack', 'ffi', 'json', 'widgetSystem'
]);

const RESTRICTED_X4_UI_CALLS = [
  { name: 'OnlineGetUserItemAmount', pattern: /\bOnlineGetUserItemAmount\s*\(/ },
  { name: 'OnlineGetUserItems', pattern: /\bOnlineGetUserItems\b/ }
];

function walkAst(node: any, visit: (node: any) => void) {
  if (!node || typeof node !== 'object') return;
  visit(node);
  for (const [key, value] of Object.entries(node)) {
    if (key === 'loc' || key === 'range' || key === 'comments' || key === 'tokens' || key === 'globals') continue;
    if (Array.isArray(value)) {
      for (const item of value) walkAst(item, visit);
    } else if (value && typeof value === 'object') {
      walkAst(value, visit);
    }
  }
}

function globalNameFromExpression(expr: any): string | null {
  if (!expr) return null;
  if (expr.type === 'Identifier') return expr.name;
  if (expr.type === 'MemberExpression') return globalNameFromExpression(expr.base);
  return null;
}

function parseLua(text: string) {
  return parse(text, {
    comments: false,
    locations: true,
    ranges: true,
    scope: true,
    luaVersion: '5.2'
  });
}

function collectGlobalDefinitions(files: LuaFileInput[]): Set<string> {
  const defs = new Set<string>();
  for (const file of files) {
    let ast: any;
    try { ast = parseLua(file.text); } catch { continue; }
    walkAst(ast, node => {
      if (node.type === 'AssignmentStatement') {
        for (const variable of node.variables || []) {
          const name = globalNameFromExpression(variable);
          if (name) defs.add(name);
        }
      }
      if (node.type === 'FunctionDeclaration' && !node.isLocal) {
        const name = globalNameFromExpression(node.identifier);
        if (name) defs.add(name);
      }
    });
  }
  return defs;
}

export function analyzeLuaFiles(files: LuaFileInput[]): LuaStaticAnalysisResult {
  const allow = new Set([...LUA_STANDARD_GLOBALS, ...X4_ENGINE_GLOBALS, ...collectGlobalDefinitions(files)]);
  const findings: LuaStaticFinding[] = [];

  for (const file of files) {
    const relLower = file.rel.toLowerCase();
    let ast: any;
    try {
      ast = parseLua(file.text);
    } catch (error: any) {
      findings.push({
        layer: 'baseline',
        severity: 'error',
        code: 'lua.syntax_error',
        rel: file.rel,
        message: `Lua parser error in ${file.rel}: ${error?.message || 'syntax error'}`,
        line: error?.line,
        column: error?.column,
        source: file.source,
        sourcePath: file.sourcePath
      });
      continue;
    }

    const seenGlobals = new Set<string>();
    for (const g of ast.globals || []) {
      const name = g?.name;
      if (!name || allow.has(name) || seenGlobals.has(name)) continue;
      seenGlobals.add(name);
      findings.push({
        layer: 'baseline',
        severity: 'info',
        code: 'lua.undefined_global',
        rel: file.rel,
        message: `${file.rel} references global "${name}" that is not in the deterministic Lua/X4 allowlist and is not defined by scanned Lua files.`,
        symbol: name,
        line: g?.loc?.start?.line,
        column: g?.loc?.start?.column,
        source: file.source,
        sourcePath: file.sourcePath
      });
      if (seenGlobals.size >= 8) break;
    }

    if (relLower.endsWith('.lua') && relLower.startsWith('ui/')) {
      for (const fn of RESTRICTED_X4_UI_CALLS) {
        if (!fn.pattern.test(file.text)) continue;
        findings.push({
          layer: 'x4',
          severity: 'error',
          code: 'lua.restricted_online_call',
          rel: file.rel,
          message: `Calls or patches restricted UI function ${fn.name} from ${file.rel}. X4 can abort online user-item calls from non-verified sources; later menu errors are likely cascade symptoms.`,
          symbol: fn.name,
          source: file.source,
          sourcePath: file.sourcePath
        });
      }
    }
  }

  return { filesScanned: files.length, globalAllowlistSize: allow.size, findings };
}

export function runLuaStaticAnalysisSelftest(): { pass: boolean; checks: { name: string; pass: boolean; detail?: string }[] } {
  const files: LuaFileInput[] = [
    {
      rel: 'ui/good.lua',
      text: 'local x = 1\nHelper.foo(x)\nfunction MyGlobal.ok() return true end\n',
      source: 'loose',
      sourcePath: 'good'
      , extension: { folder: 'good', id: 'good' }
    },
    {
      rel: 'ui/bad.lua',
      text: 'local amount = OnlineGetUserItemAmount("paint")\nMissingGlobalCall()\n',
      source: 'packed',
      sourcePath: 'ext_01.cat',
      extension: { folder: 'bad', id: 'bad' }
    },
    {
      rel: 'ui/broken.lua',
      text: 'function nope(\n',
      source: 'loose',
      sourcePath: 'broken',
      extension: { folder: 'broken', id: 'broken' }
    }
  ];
  const result = analyzeLuaFiles(files);
  const has = (code: string, pred?: (f: LuaStaticFinding) => boolean) =>
    result.findings.some(f => f.code === code && (!pred || pred(f)));
  const checks = [
    { name: 'syntax_error_detected', pass: has('lua.syntax_error', f => f.rel === 'ui/broken.lua') },
    { name: 'restricted_x4_call_detected', pass: has('lua.restricted_online_call', f => f.rel === 'ui/bad.lua' && f.layer === 'x4' && f.severity === 'error') },
    { name: 'undefined_global_detected', pass: has('lua.undefined_global', f => f.symbol === 'MissingGlobalCall' && f.layer === 'baseline') },
    { name: 'x4_seed_global_not_flagged', pass: !result.findings.some(f => f.code === 'lua.undefined_global' && f.symbol === 'Helper') },
    { name: 'scanned_global_definition_not_flagged', pass: !result.findings.some(f => f.code === 'lua.undefined_global' && f.symbol === 'MyGlobal') }
  ];
  return { pass: checks.every(c => c.pass), checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Deterministic graph auto-layout (53rd pass — UX grind, gap G11).
 *
 * Powers TIDY GRAPH. The old in-component layout didn't position control-flow `out_body`
 * chains (branch bodies stayed wherever they landed) and could overlap. This is a pure,
 * tested function instead: an indented-tree layout where every node gets its own row, so
 * no two nodes can overlap by construction, and depth → column gives clean left-to-right
 * structure (cue → conditions/actions → branch bodies indented → sub-cues indented).
 *
 * Comment frames are intentionally NOT moved (they're background grouping boxes).
 */

import type { MDNode, MDLink } from '../types';

export const LAYOUT = { COL_W: 320, ROW_H: 230, X0: 80, Y0: 80, NODE_W: 240, NODE_H: 200 };

export function computeAutoLayout(nodes: MDNode[], links: MDLink[]): Map<string, { x: number; y: number }> {
  const { COL_W, ROW_H, X0, Y0 } = LAYOUT;
  const pos = new Map<string, { x: number; y: number }>();
  const nodeById = new Map(nodes.map((n) => [n.id, n]));
  const placeable = nodes.filter((n) => n.type !== 'comment');

  const outTargets = (id: string, port: string) =>
    links.filter((l) => l.sourceNodeId === id && l.sourcePortId === port).map((l) => l.targetNodeId);
  const firstOut = (id: string, port: string) => {
    const l = links.find((x) => x.sourceNodeId === id && x.sourcePortId === port);
    return l ? l.targetNodeId : undefined;
  };

  let row = 0;
  const seen = new Set<string>();
  const place = (id: string, col: number) => {
    if (seen.has(id) || !nodeById.has(id)) return;
    seen.add(id);
    pos.set(id, { x: X0 + col * COL_W, y: Y0 + row * ROW_H });
    row++;
  };

  const layoutActionChain = (startId: string | undefined, col: number) => {
    let cur = startId;
    const guard = new Set<string>();
    while (cur && !guard.has(cur) && !seen.has(cur)) {
      guard.add(cur);
      place(cur, col);
      const body = firstOut(cur, 'out_body'); // branch/loop body indents one column deeper
      if (body) layoutActionChain(body, col + 1);
      cur = firstOut(cur, 'out_next');
    }
  };

  const layoutCue = (cueId: string, col: number) => {
    if (seen.has(cueId)) return;
    place(cueId, col);
    for (const c of outTargets(cueId, 'out_cond')) place(c, col + 1);   // triggers/conditions
    for (const a of outTargets(cueId, 'out_act')) layoutActionChain(a, col + 1); // actions
    for (const s of outTargets(cueId, 'out_sub')) {                      // sub-cues, indented
      const n = nodeById.get(s);
      if (n && n.type === 'cue') layoutCue(s, col + 1);
    }
  };

  const cues = placeable.filter((n) => n.type === 'cue');
  const subTargets = new Set(links.filter((l) => l.sourcePortId === 'out_sub').map((l) => l.targetNodeId));
  for (const c of cues.filter((c) => !subTargets.has(c.id))) layoutCue(c.id, 0); // root cues first
  for (const c of cues) if (!seen.has(c.id)) layoutCue(c.id, 0);                  // any cue cycle remnants
  for (const f of placeable) if (!seen.has(f.id)) place(f.id, 0);                 // floating/orphan nodes

  return pos;
}

/* ============================================================================ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * ============================================================================ */
export function runAutoLayoutSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });
  const N = (id: string, type: any, xmlTag: string): MDNode =>
    ({ id, type, xmlTag, properties: {}, label: id, x: 999, y: 999, propertiesSchema: [], inputs: [], outputs: [] } as any);
  const L = (s: string, sp: string, t: string): MDLink => ({ id: `${s}_${sp}_${t}`, sourceNodeId: s, sourcePortId: sp, targetNodeId: t, targetPortId: 'in' });

  const nodes = [
    N('cue', 'cue', 'cue'),
    N('ev', 'event', 'event_game_started'),
    N('a1', 'action', 'set_value'),
    N('g', 'action', 'do_if'),
    N('b1', 'action', 'reward_player'),   // body of do_if
    N('a2', 'action', 'play_sound'),      // sibling after do_if
    N('sub', 'cue', 'cue'),               // sub-cue
    N('float', 'action', 'wait'),         // orphan
    N('cmt', 'comment', 'comment'),       // must NOT be moved
  ];
  const links = [
    L('cue', 'out_cond', 'ev'),
    L('cue', 'out_act', 'a1'),
    L('a1', 'out_next', 'g'),
    L('g', 'out_body', 'b1'),
    L('g', 'out_next', 'a2'),
    L('cue', 'out_sub', 'sub'),
  ];
  const pos = computeAutoLayout(nodes, links);
  const P = (id: string) => pos.get(id)!;

  // every non-comment node placed
  ok('all_placed', ['cue', 'ev', 'a1', 'g', 'b1', 'a2', 'sub', 'float'].every((id) => pos.has(id)), [...pos.keys()]);
  // comment NOT moved (not in the layout map)
  ok('comment_untouched', !pos.has('cmt'));

  // NO overlap between any two placed nodes
  const ids = [...pos.keys()];
  let overlap = false; let bad: any = null;
  for (let i = 0; i < ids.length; i++) for (let j = i + 1; j < ids.length; j++) {
    const a = P(ids[i]), b = P(ids[j]);
    if (Math.abs(a.x - b.x) < LAYOUT.NODE_W && Math.abs(a.y - b.y) < LAYOUT.NODE_H) { overlap = true; bad = [ids[i], ids[j]]; }
  }
  ok('no_overlap', !overlap, bad);

  // cue is the left-most of its own subtree
  ok('cue_leftmost', ['ev', 'a1', 'g', 'b1', 'a2', 'sub'].every((id) => P(id).x >= P('cue').x), null);
  // branch body is indented deeper (further right) than its container
  ok('body_indented', P('b1').x > P('g').x, { body: P('b1').x, container: P('g').x });
  // sub-cue indented deeper than parent
  ok('subcue_indented', P('sub').x > P('cue').x);
  // condition placed right of the cue
  ok('condition_right_of_cue', P('ev').x > P('cue').x);

  // deterministic: same input ⇒ same output
  const pos2 = computeAutoLayout(nodes, links);
  ok('deterministic', ids.every((id) => pos2.get(id)!.x === P(id).x && pos2.get(id)!.y === P(id).y));

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Compiled-XML self-test (52nd pass, gap G2).
 *
 * The existing selftests check NODE SHAPE (does the registry/template look right). They do
 * NOT check what `generateMDXML` actually emits — which is how the G1 `check_value` bug
 * slipped through (a node that looked fine compiled to `value="$x ge 5" min="1000000"`).
 * This oracle compiles representative graphs and asserts the EMITTED XML string, so a wrong
 * attribute in an emitter is caught deterministically.
 */

import type { MDNode, MDLink, ModWorkspace } from '../types';
import { sanitizeWorkspace, generateMDXML } from '../types';

const N = (id: string, type: any, xmlTag: string, properties: any = {}): Partial<MDNode> =>
  ({ id, type, xmlTag, properties, label: id, x: 0, y: 0 } as any);
const L = (id: string, s: string, sp: string, t: string, tp = 'in'): MDLink =>
  ({ id, sourceNodeId: s, sourcePortId: sp, targetNodeId: t, targetPortId: tp });

/** Build a one-cue workspace and compile it to MD XML. */
function compile(nodes: Partial<MDNode>[], links: MDLink[]): string {
  const ws = sanitizeWorkspace({
    name: 'CompileTest', nodes, links, uiWidgets: [],
  } as Partial<ModWorkspace>);
  return generateMDXML(ws);
}

export function runCompileSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  // ---- G1: check_value as a full boolean expression ⇒ standalone, NO min/max ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('k', 'condition', 'check_value', { value: '$killcount ge 5' })],
      [L('l', 'c', 'out_cond', 'k', 'in_cond')],
    );
    ok('checkvalue_expr_standalone', /<check_value value="\$killcount ge 5"\s*\/>/.test(xml), xml.match(/<check_value[^>]*>/)?.[0]);
    ok('checkvalue_expr_no_bogus_min', !/value="\$killcount ge 5"[^>]*min=/.test(xml), xml.match(/<check_value[^>]*>/)?.[0]);
  }
  // ---- check_value compound expression ⇒ standalone ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('k', 'condition', 'check_value', { value: '$a ge 3 and $a lt 5' })],
      [L('l', 'c', 'out_cond', 'k', 'in_cond')],
    );
    ok('checkvalue_compound_standalone', /<check_value value="\$a ge 3 and \$a lt 5"\s*\/>/.test(xml), xml.match(/<check_value[^>]*>/)?.[0]);
  }
  // ---- check_value operand + explicit operator/amount ⇒ min/max form ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('k', 'condition', 'check_value', { value: 'player.money', operator: 'ge', amount: '500000' })],
      [L('l', 'c', 'out_cond', 'k', 'in_cond')],
    );
    ok('checkvalue_operand_min', /<check_value value="player\.money" min="500000"\s*\/>/.test(xml), xml.match(/<check_value[^>]*>/)?.[0]);
  }
  // ---- check_value bare operand, no operator ⇒ standalone truthiness (no bogus min) ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('k', 'condition', 'check_value', { value: '$flag' })],
      [L('l', 'c', 'out_cond', 'k', 'in_cond')],
    );
    ok('checkvalue_bare_no_min', /<check_value value="\$flag"\s*\/>/.test(xml) && !/\$flag"[^>]*min=/.test(xml), xml.match(/<check_value[^>]*>/)?.[0]);
  }

  // ---- reward_player ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('a', 'action', 'reward_player', { money: '100000' })],
      [L('l', 'c', 'out_act', 'a', 'in_act')],
    );
    ok('reward_player', /<reward_player money="100000"\s*\/>/.test(xml), xml.match(/<reward_player[^>]*>/)?.[0]);
  }
  // ---- set_value (generic emit) keeps its attributes ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('a', 'action', 'set_value', { name: '$x', exact: '0' })],
      [L('l', 'c', 'out_act', 'a', 'in_act')],
    );
    ok('set_value_attrs', /<set_value[^>]*name="\$x"[^>]*exact="0"[^>]*\/>/.test(xml), xml.match(/<set_value[^>]*>/)?.[0]);
  }
  // ---- show_help: text→custom, duration carries a unit ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('a', 'action', 'show_help', { text: 'Hi', duration: 5 })],
      [L('l', 'c', 'out_act', 'a', 'in_act')],
    );
    ok('show_help_custom', /<show_help custom="'Hi'"/.test(xml), xml.match(/<show_help[^>]*>/)?.[0]);
    ok('show_help_duration_unit', /duration="5s"/.test(xml), xml.match(/<show_help[^>]*>/)?.[0]);
  }
  // ---- create_ship: owner as a CHILD element, not a faction attr ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('a', 'action', 'create_ship', { name: '$S', macro: 'ship_arg_m_fighter_01_a_macro', faction: 'argon', sector: 'player.sector' })],
      [L('l', 'c', 'out_act', 'a', 'in_act')],
    );
    ok('create_ship_owner_child', /<owner exact="faction\.argon"\s*\/>/.test(xml), xml.match(/<create_ship[\s\S]*?<\/create_ship>/)?.[0]?.slice(0, 120));
    ok('create_ship_no_faction_attr', !/<create_ship[^>]*faction=/.test(xml));
  }
  // ---- do_if nests its out_body chain ----
  {
    const xml = compile(
      [N('c', 'cue', 'cue', { name: 'C' }), N('g', 'action', 'do_if', { value: '$x gt 1' }), N('b', 'action', 'reward_player', { money: '5' })],
      [L('la', 'c', 'out_act', 'g', 'in_act'), L('lb', 'g', 'out_body', 'b', 'in_act')],
    );
    ok('do_if_nests_body', /<do_if value="\$x gt 1">[\s\S]*<reward_player money="5"\s*\/>[\s\S]*<\/do_if>/.test(xml), xml.match(/<do_if[\s\S]*?<\/do_if>/)?.[0]);
  }

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Determinism Doctrine — Phase 3: the deterministic critic.
 *
 * A small, named lint library over the semantics registry. It replaces the AI
 * "Playtester Guidance" speculation with rules that are deterministic and
 * false-positive-free *by construction* — every finding is a fact the rule can
 * justify from the graph + registry, never a guess.
 *
 * Rules:
 *   (a) ref_mismatch       — a cue's trigger object and an action object are NOT
 *                            equivalent. Crucially SUPPRESSED when `areEquivalentRefs`
 *                            is true: this is the exact case the AI false-positived on
 *                            (`playership` vs `player.primaryship`). The oracle proves
 *                            the non-flag.
 *   (b) oneway_no_restore  — an action with a "does not restore" registry note whose
 *                            written state key is never restored later in the cue
 *                            (the deterministic "no shield recharge").
 *   (c) unguarded_high_risk— a spawn/economy/irreversible action in a cue triggered by
 *                            a frequently-firing event, with no guard (condition or do_if).
 *
 * Reuses the explainer's canonical graph-walk (`triggerNodesOf`/`actionChainOf`) and the
 * registry (`areEquivalentRefs`/`semanticsForNode`) — one module per capability.
 */

import type { MDNode, MDLink } from '../types';
import { areEquivalentRefs, semanticsForNode } from './mdSemantics';
import { triggerNodesOf, actionChainOf } from './mdExplain';

export type CriticSeverity = 'info' | 'warning';
export type CriticCode = 'ref_mismatch' | 'oneway_no_restore' | 'unguarded_high_risk';

export interface CriticFinding {
  severity: CriticSeverity;
  code: CriticCode;
  cueId: string;
  cueName: string;
  nodeId?: string;
  message: string;
}
export interface CriticResult {
  findings: CriticFinding[];
  /** Counts by code, for quick UI/summary. */
  summary: Record<string, number>;
}

/** Events that fire often enough that an unconditional high-risk action is worth a note. */
const FREQUENT_EVENTS = new Set<string>([
  'event_object_changed_sector',
  'event_player_money_changed',
  'event_object_attacked',
]);

const GUARD_CONDITION_TAGS = new Set<string>(['check_value', 'custom_condition']);

/** The primary object reference of a node's top-level `object` attribute, or null. */
function primaryObjectRef(node: MDNode): string | null {
  const v = node?.properties?.object;
  if (v == null) return null;
  const s = String(v).trim();
  if (!s) return null;
  // Variables/expressions/literals are not static object references we can compare.
  if (s.startsWith('$') || s.startsWith('{') || /^-?\d/.test(s)) return null;
  if (!/^[a-zA-Z_][\w.]*$/.test(s)) return null;
  return s;
}

function cueNameOf(cue: MDNode): string {
  return (cue.properties?.name && String(cue.properties.name).trim()) || cue.label || cue.id;
}

export function critiqueWorkspace(nodes: MDNode[], links: MDLink[]): CriticResult {
  nodes = Array.isArray(nodes) ? nodes.filter((n) => n && n.includeInBuild !== false) : [];
  links = Array.isArray(links) ? links : [];
  const nodeById = new Map(nodes.map((n) => [n.id, n]));
  const cues = nodes.filter((n) => n.type === 'cue');
  const findings: CriticFinding[] = [];

  for (const cue of cues) {
    const cueName = cueNameOf(cue);
    const triggers = triggerNodesOf(cue.id, nodeById, links);
    const actions = actionChainOf(cue.id, nodeById, links);

    // --- (a) ref_mismatch — suppressed when equivalent (the anti-false-positive) ---
    const triggerObj = triggers.map(primaryObjectRef).find((r): r is string => !!r);
    if (triggerObj) {
      for (const a of actions) {
        const ao = primaryObjectRef(a);
        if (ao && !areEquivalentRefs(triggerObj, ao)) {
          findings.push({
            severity: 'info', code: 'ref_mismatch', cueId: cue.id, cueName, nodeId: a.id,
            message: `Cue "${cueName}" triggers on "${triggerObj}" but action <${a.xmlTag}> targets "${ao}". These are not known to be the same entity — confirm it's intended.`,
          });
        }
        // equivalent refs (e.g. playership ≡ player.primaryship) are intentionally NOT flagged.
      }
    }

    // --- (b) oneway_no_restore ---
    // Count writes per state key across the cue's actions. A one-way-write action is
    // only flagged when the cue touches that key EXACTLY ONCE — if the key is written
    // more than once we assume a deliberate drop+restore pair and stay silent (this
    // also prevents flagging the restoring action itself).
    const writeCounts: Record<string, number> = {};
    for (const a of actions) for (const w of semanticsForNode(a).writes) writeCounts[w] = (writeCounts[w] || 0) + 1;
    for (const a of actions) {
      const sem = semanticsForNode(a);
      const isOneWay = !!sem.note && /does not restore/i.test(sem.note);
      if (isOneWay && sem.writes.length > 0) {
        const key = sem.writes[0];
        if ((writeCounts[key] || 0) <= 1) {
          findings.push({
            severity: 'warning', code: 'oneway_no_restore', cueId: cue.id, cueName, nodeId: a.id,
            message: `Cue "${cueName}": <${a.xmlTag}> performs a one-way write to ${key} and nothing else in the cue restores it. If the change is meant to be temporary, add a restore step.`,
          });
        }
      }
    }

    // --- (c) unguarded_high_risk on a frequent trigger ---
    const frequentTrigger = triggers.find((t) => FREQUENT_EVENTS.has(t.xmlTag));
    const hasGuard = triggers.some((t) => GUARD_CONDITION_TAGS.has(t.xmlTag))
      || actions.some((a) => a.xmlTag === 'do_if' || a.xmlTag === 'do_while');
    if (frequentTrigger && !hasGuard) {
      for (const a of actions) {
        const risk = semanticsForNode(a).risk;
        if (risk === 'spawn' || risk === 'economy' || risk === 'irreversible') {
          findings.push({
            severity: 'info', code: 'unguarded_high_risk', cueId: cue.id, cueName, nodeId: a.id,
            message: `Cue "${cueName}": <${a.xmlTag}> (${risk}) runs unconditionally on a frequently-firing trigger (<${frequentTrigger.xmlTag}>). Consider a condition/guard so it doesn't fire more often than intended.`,
          });
        }
      }
    }
  }

  const summary: Record<string, number> = {};
  for (const f of findings) summary[f.code] = (summary[f.code] || 0) + 1;
  return { findings, summary };
}

/* ------------------------------------------------------------------ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * Proves each rule fires on a positive AND, for the headline rule, that equivalent
 * references are NOT flagged (the deterministic fix for the AI's false positive).
 * ------------------------------------------------------------------ */
export function runCriticSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });
  const N = (id: string, type: any, xmlTag: string, properties: any = {}): MDNode =>
    ({ id, type, xmlTag, properties, label: id, x: 0, y: 0, propertiesSchema: [], inputs: [], outputs: [] } as any);
  const L = (id: string, s: string, sp: string, t: string, tp = 'in'): MDLink =>
    ({ id, sourceNodeId: s, sourcePortId: sp, targetNodeId: t, targetPortId: tp });
  const has = (r: CriticResult, code: string, nodeId?: string) =>
    r.findings.some((f) => f.code === code && (nodeId ? f.nodeId === nodeId : true));

  // ---- (a) ref_mismatch: equivalent NOT flagged, non-equivalent flagged ----
  // Trigger on playership; one action targets player.primaryship (EQUIVALENT → suppressed),
  // another targets station.alpha (NOT equivalent → flagged).
  const eqNodes: MDNode[] = [
    N('c', 'cue', 'cue', { name: 'RefCue' }),
    N('ev', 'event', 'event_object_changed_sector', { object: 'playership', sector: 'player.sector' }),
    N('a_eq', 'action', 'set_object_shieldlevel', { object: 'player.primaryship', level: '0' }),
    N('a_ne', 'action', 'set_owner', { object: 'station.alpha', exact: 'xenon' }),
  ];
  const eqLinks: MDLink[] = [
    L('l1', 'c', 'out_cond', 'ev', 'in_cond'),
    L('l2', 'c', 'out_act', 'a_eq', 'in_act'),
    L('l3', 'a_eq', 'out_next', 'a_ne', 'in_act'),
  ];
  const rEq = critiqueWorkspace(eqNodes, eqLinks);
  ok('equiv_ref_NOT_flagged', !has(rEq, 'ref_mismatch', 'a_eq'), rEq.findings); // THE headline: no false positive
  ok('nonequiv_ref_flagged', has(rEq, 'ref_mismatch', 'a_ne'), rEq.findings);

  // ---- (b) oneway_no_restore: fires when not restored, suppressed when restored ----
  const owNoRestore = critiqueWorkspace(
    [N('c2', 'cue', 'cue', { name: 'Drain' }), N('s1', 'action', 'set_object_shieldlevel', { object: 'playership', level: '0' })],
    [L('m1', 'c2', 'out_act', 's1', 'in_act')]
  );
  ok('oneway_fires', has(owNoRestore, 'oneway_no_restore', 's1'), owNoRestore.findings);

  const owRestored = critiqueWorkspace(
    [N('c3', 'cue', 'cue', { name: 'DrainRestore' }),
     N('s2', 'action', 'set_object_shieldlevel', { object: 'playership', level: '0' }),
     N('s3', 'action', 'set_object_shieldlevel', { object: 'playership', level: '100' })],
    [L('m2', 'c3', 'out_act', 's2', 'in_act'), L('m3', 's2', 'out_next', 's3', 'in_act')]
  );
  ok('oneway_suppressed_when_restored', !has(owRestored, 'oneway_no_restore'), owRestored.findings);

  // ---- (c) unguarded_high_risk: fires on frequent trigger + high-risk action, suppressed by a guard ----
  const unguarded = critiqueWorkspace(
    [N('c4', 'cue', 'cue', { name: 'Spawner' }),
     N('e4', 'event', 'event_object_changed_sector', { object: 'playership' }),
     N('cs', 'action', 'create_ship', { macro: 'ship_xen', faction: 'xenon' })],
    [L('n1', 'c4', 'out_cond', 'e4', 'in_cond'), L('n2', 'c4', 'out_act', 'cs', 'in_act')]
  );
  ok('unguarded_fires', has(unguarded, 'unguarded_high_risk', 'cs'), unguarded.findings);

  const guardedDoIf = critiqueWorkspace(
    [N('c5', 'cue', 'cue', { name: 'GuardedSpawner' }),
     N('e5', 'event', 'event_object_changed_sector', { object: 'playership' }),
     N('g', 'action', 'do_if', { value: '$ready' }),
     N('cs2', 'action', 'create_ship', { macro: 'ship_xen', faction: 'xenon' })],
    [L('o1', 'c5', 'out_cond', 'e5', 'in_cond'), L('o2', 'c5', 'out_act', 'g', 'in_act'), L('o3', 'g', 'out_next', 'cs2', 'in_act')]
  );
  ok('unguarded_suppressed_by_doif', !has(guardedDoIf, 'unguarded_high_risk'), guardedDoIf.findings);

  const guardedCheck = critiqueWorkspace(
    [N('c6', 'cue', 'cue', { name: 'CheckedSpawner' }),
     N('e6', 'event', 'event_object_changed_sector', { object: 'playership' }),
     N('chk', 'condition', 'check_value', { value: '$ready' }),
     N('cs3', 'action', 'create_ship', { macro: 'ship_xen', faction: 'xenon' })],
    [L('p1', 'c6', 'out_cond', 'e6', 'in_cond'), L('p2', 'c6', 'out_cond', 'chk', 'in_cond'), L('p3', 'c6', 'out_act', 'cs3', 'in_act')]
  );
  ok('unguarded_suppressed_by_condition', !has(guardedCheck, 'unguarded_high_risk'), guardedCheck.findings);

  // non-frequent trigger: high-risk action is NOT flagged by rule (c)
  const infreq = critiqueWorkspace(
    [N('c7', 'cue', 'cue', { name: 'OnceSpawner' }),
     N('e7', 'event', 'event_game_started', {}),
     N('cs4', 'action', 'create_ship', { macro: 'ship_xen', faction: 'xenon' })],
    [L('q1', 'c7', 'out_cond', 'e7', 'in_cond'), L('q2', 'c7', 'out_act', 'cs4', 'in_act')]
  );
  ok('infrequent_not_flagged', !has(infreq, 'unguarded_high_risk'), infreq.findings);

  // ---- clean cue produces no findings ----
  const clean = critiqueWorkspace(
    [N('c8', 'cue', 'cue', { name: 'Clean' }),
     N('e8', 'event', 'event_game_started', {}),
     N('snd', 'action', 'play_sound', { object: 'playership', sound: 'beep' })],
    [L('r1', 'c8', 'out_cond', 'e8', 'in_cond'), L('r2', 'c8', 'out_act', 'snd', 'in_act')]
  );
  ok('clean_no_findings', clean.findings.length === 0, clean.findings);

  // summary counts
  ok('summary_counts', typeof rEq.summary['ref_mismatch'] === 'number' && rEq.summary['ref_mismatch'] === 1, rEq.summary);

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Friendly node names (51st pass — Approachability Track 1).
 *
 * Forge's palette and freshly-spawned schema nodes show the RAW md.xsd tag
 * (`event_object_destroyed`, `set_value`, `check_value`), which reads like "learn the
 * syntax." This registry maps the common tags to plain English the way a UE5 Blueprint
 * palette does ("On Game Start", "Set Variable", "Compare Value"). The raw tag is never
 * thrown away — it stays as the node's `xmlTag` and is shown as a subtitle — so power
 * users still see the truth. Deterministic; presentation only.
 */

