/** Materialize a template id into a full (sanitized) workspace ready to load. */
export function buildTemplateWorkspace(id: string): ModWorkspace {
  const tpl = MOD_TEMPLATES.find((t) => t.id === id) || MOD_TEMPLATES[0];
  const { nodes, links } = tpl.build();
  return sanitizeWorkspace({
    name: tpl.name,
    description: `Started from the "${tpl.title}" template in X4 Forge.`,
    nodes, links, uiWidgets: [],
  } as Partial<ModWorkspace>);
}

/* ============================================================================ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * Every non-blank template must compile to 0 validation errors.
 * ============================================================================ */
export function runModTemplatesSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  ok('has_blank', MOD_TEMPLATES.some((t) => t.id === 'blank'));
  ok('has_multiple', MOD_TEMPLATES.length >= 3);

  for (const tpl of MOD_TEMPLATES) {
    if (tpl.id === 'blank') continue;
    try {
      const ws = buildTemplateWorkspace(tpl.id);
      const diags = validateModWorkspace(ws, generateMDXML(ws));
      const errors = diags.filter((d) => d.severity === 'error');
      ok(`template_${tpl.id}_compiles_clean`, errors.length === 0, errors.map((e) => e.message));
      ok(`template_${tpl.id}_has_nodes`, ws.nodes.length > 0);
    } catch (e: any) {
      ok(`template_${tpl.id}_compiles_clean`, false, 'threw: ' + (e?.message || e));
    }
  }

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Selective node alignment + distribution — the UE5-Blueprint "align / straighten /
 * distribute" ergonomics that Forge lacked (TIDY GRAPH only does whole-graph auto-layout).
 *
 * Pure geometry over the selected nodes' positions: deterministic, no side effects.
 * The Canvas calls `computeAlignment` and applies the returned positions through the
 * normal workspace/undo path.
 */

export type AlignMode =
  | 'left' | 'right' | 'top' | 'bottom'
  | 'hcenter'        // align horizontal centers → a vertical column (same center-x)
  | 'vcenter'        // align vertical centers → a horizontal row (same center-y)
  | 'distribute-h'   // even horizontal spacing between centers
  | 'distribute-v';  // even vertical spacing between centers

export interface AlignNode { id: string; x: number; y: number; width?: number; height?: number; }

const DEFAULT_W = 240; // Forge node cards are w-60 (240px)
const DEFAULT_H = 120;
const w = (n: AlignNode) => (typeof n.width === 'number' && n.width > 0 ? n.width : DEFAULT_W);
const h = (n: AlignNode) => (typeof n.height === 'number' && n.height > 0 ? n.height : DEFAULT_H);
const r = (v: number) => Math.round(v);

/**
 * Compute new {x,y} for the selected nodes under an alignment/distribute mode.
 * Returns only the nodes that actually move. Needs ≥2 selected (≥3 for distribute).
 */
export function computeAlignment(
  nodes: AlignNode[],
  selectedIds: string[],
  mode: AlignMode
): Record<string, { x: number; y: number }> {
  const idset = new Set(selectedIds);
  const sel = (Array.isArray(nodes) ? nodes : []).filter((n) => n && idset.has(n.id));
  const out: Record<string, { x: number; y: number }> = {};
  if (sel.length < 2) return out;

  const put = (n: AlignNode, x: number, y: number) => {
    if (r(x) !== r(n.x) || r(y) !== r(n.y)) out[n.id] = { x: r(x), y: r(y) };
  };

  switch (mode) {
    case 'left': {
      const x = Math.min(...sel.map((n) => n.x));
      for (const n of sel) put(n, x, n.y);
      break;
    }
    case 'right': {
      const right = Math.max(...sel.map((n) => n.x + w(n)));
      for (const n of sel) put(n, right - w(n), n.y);
      break;
    }
    case 'top': {
      const y = Math.min(...sel.map((n) => n.y));
      for (const n of sel) put(n, n.x, y);
      break;
    }
    case 'bottom': {
      const bottom = Math.max(...sel.map((n) => n.y + h(n)));
      for (const n of sel) put(n, n.x, bottom - h(n));
      break;
    }
    case 'hcenter': {
      const cx = sel.reduce((s, n) => s + (n.x + w(n) / 2), 0) / sel.length;
      for (const n of sel) put(n, cx - w(n) / 2, n.y);
      break;
    }
    case 'vcenter': {
      const cy = sel.reduce((s, n) => s + (n.y + h(n) / 2), 0) / sel.length;
      for (const n of sel) put(n, n.x, cy - h(n) / 2);
      break;
    }
    case 'distribute-h': {
      if (sel.length < 3) return out;
      const sorted = [...sel].sort((a, b) => (a.x + w(a) / 2) - (b.x + w(b) / 2));
      const minC = sorted[0].x + w(sorted[0]) / 2;
      const maxC = sorted[sorted.length - 1].x + w(sorted[sorted.length - 1]) / 2;
      const step = (maxC - minC) / (sorted.length - 1);
      sorted.forEach((n, i) => put(n, (minC + step * i) - w(n) / 2, n.y));
      break;
    }
    case 'distribute-v': {
      if (sel.length < 3) return out;
      const sorted = [...sel].sort((a, b) => (a.y + h(a) / 2) - (b.y + h(b) / 2));
      const minC = sorted[0].y + h(sorted[0]) / 2;
      const maxC = sorted[sorted.length - 1].y + h(sorted[sorted.length - 1]) / 2;
      const step = (maxC - minC) / (sorted.length - 1);
      sorted.forEach((n, i) => put(n, n.x, (minC + step * i) - h(n) / 2));
      break;
    }
  }
  return out;
}

/* ------------------------------------------------------------------ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * ------------------------------------------------------------------ */
export function runNodeAlignSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });
  const N = (id: string, x: number, y: number, width = 240, height = 100): AlignNode => ({ id, x, y, width, height });

  // three nodes at different x/y, equal size
  const ns = [N('a', 0, 0), N('b', 100, 50), N('c', 300, 200)];
  const ids = ['a', 'b', 'c'];

  // left: all share min x (0)
  const left = computeAlignment(ns, ids, 'left');
  ok('left_aligns_min_x', left['b']?.x === 0 && left['c']?.x === 0 && !left['a'], left);

  // right: all share max right edge (300+240=540) → x = 540-240 = 300
  const right = computeAlignment(ns, ids, 'right');
  ok('right_aligns_right_edge', right['a']?.x === 300 && right['b']?.x === 300 && !right['c'], right);

  // top: all share min y (0)
  const top = computeAlignment(ns, ids, 'top');
  ok('top_aligns_min_y', top['b']?.y === 0 && top['c']?.y === 0 && !top['a'], top);

  // bottom: max bottom = 200+100=300 → y = 300-100 = 200
  const bottom = computeAlignment(ns, ids, 'bottom');
  ok('bottom_aligns_bottom_edge', bottom['a']?.y === 200 && bottom['b']?.y === 200 && !bottom['c'], bottom);

  // hcenter: centers x = (120, 220, 420) avg = 253.33 → center; everyone shares same center-x
  const hc = computeAlignment(ns, ids, 'hcenter');
  const centersX = ns.map((n) => (hc[n.id]?.x ?? n.x) + 120);
  ok('hcenter_same_center_x', Math.max(...centersX) - Math.min(...centersX) <= 1, centersX);

  // distribute-h: 3 nodes → middle node's center evenly between first & last centers (120 & 420) = 270 → x=150
  const dh = computeAlignment(ns, ids, 'distribute-h');
  ok('distribute_h_even', dh['b']?.x === 150, dh);

  // distribute needs ≥3
  ok('distribute_needs_three', Object.keys(computeAlignment([N('a',0,0),N('b',100,0)], ['a','b'], 'distribute-h')).length === 0);

  // <2 selected → no-op
  ok('noop_single', Object.keys(computeAlignment(ns, ['a'], 'left')).length === 0);

  // only moves nodes that change (already-aligned node omitted)
  const already = computeAlignment([N('x', 5, 0), N('y', 5, 40)], ['x', 'y'], 'left');
  ok('omits_unmoved', Object.keys(already).length === 0, already);

  // unequal widths: right-align respects per-node width
  const uw = computeAlignment([N('p', 0, 0, 100, 50), N('q', 0, 100, 240, 50)], ['p', 'q'], 'right');
  // right edge = max(0+100, 0+240)=240 → p.x = 240-100 = 140, q.x stays 0
  ok('right_respects_width', uw['p']?.x === 140 && !uw['q'], uw);

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Node-level schema diagnostics — maps the game-schema validation back to the EXACT
 * node that produced it, so the canvas can show an in-your-face error/warning badge on
 * the offending node instead of burying it in the Doctor panel.
 *
 * Deterministic and schema-driven: the only source of truth is the parsed md.xsd index
 * (passed in as a minimal `NodeSchemaView` so the engine stays pure and testable). No AI.
 *
 * Two checks, both node-mappable:
 *   - unknown_element: the node's xmlTag is not a declared element in the game schema
 *     (catches e.g. `add_value`, which isn't real — the real form is `set_value operation="add"`).
 *   - missing_required_attr: a schema-required attribute is absent from the node.
 *     Skipped for the handful of curated tags the compiler RENAMES/relocates attributes for
 *     (show_help→custom, create_ship→owner child, etc.), to avoid false positives — those
 *     are still covered by the post-compile XML validation in the Doctor.
 */

import type { MDNode } from '../types';

export interface NodeSchemaView {
  /** Is this element declared in the game schema (md.xsd/common.xsd)? */
  has(tag: string): boolean;
  /** Required attribute names for a declared element. */
  requiredAttrs(tag: string): string[];
  /** Whether the schema actually loaded (if false, callers should skip — no false negatives). */
  loaded: boolean;
}

export type NodeDiagSeverity = 'error' | 'warning';
export type NodeDiagCode = 'unknown_element' | 'missing_required_attr';
export interface NodeDiagnostic {
  nodeId: string;
  severity: NodeDiagSeverity;
  code: NodeDiagCode;
  tag: string;
  message: string;
}

/** Node kinds/tags the studio owns — never validated as schema elements. */
const STUDIO_SPECIAL_TAGS = new Set([
  'cue', 'comment', 'custom_xml', 'custom_event', 'custom_condition',
]);
const STUDIO_SPECIAL_TYPES = new Set(['cue', 'comment', 'variable']);

/** Tags the compiler transforms (renames/relocates attrs) — skip attribute checks. */
const TRANSFORM_TAGS = new Set([
  'show_help', 'create_ship', 'create_station', 'set_object_shieldlevel', 'set_object_hulllevel',
]);

export function validateNodesAgainstSchema(nodes: MDNode[], schema: NodeSchemaView): NodeDiagnostic[] {
  const out: NodeDiagnostic[] = [];
  if (!schema || !schema.loaded) return out; // no schema → assert nothing (no false flags)
  for (const n of Array.isArray(nodes) ? nodes : []) {
    if (!n || n.includeInBuild === false) continue;
    const tag = n.xmlTag;
    if (!tag) continue;
    if (STUDIO_SPECIAL_TAGS.has(tag) || STUDIO_SPECIAL_TYPES.has(n.type as string)) continue;

    if (!schema.has(tag)) {
      out.push({
        nodeId: n.id, severity: 'warning', code: 'unknown_element', tag,
        message: `<${tag}> is not a declared element in the game schema (md.xsd). Likely a typo or wrong element name.`,
      });
      continue;
    }
    if (TRANSFORM_TAGS.has(tag)) continue;

    for (const a of schema.requiredAttrs(tag)) {
      const v = n.properties ? n.properties[a] : undefined;
      if (v === undefined || v === null || String(v).trim() === '') {
        out.push({
          nodeId: n.id, severity: 'error', code: 'missing_required_attr', tag,
          message: `<${tag}> is missing required attribute "${a}".`,
        });
      }
    }
  }
  return out;
}

/** Severity rollup per node, for the canvas badge. */
export function summarizeByNode(diags: NodeDiagnostic[]): Record<string, { severity: NodeDiagSeverity; messages: string[] }> {
  const map: Record<string, { severity: NodeDiagSeverity; messages: string[] }> = {};
  for (const d of diags) {
    const cur = map[d.nodeId] || { severity: 'warning' as NodeDiagSeverity, messages: [] };
    cur.messages.push(d.message);
    if (d.severity === 'error') cur.severity = 'error';
    map[d.nodeId] = cur;
  }
  return map;
}

/* ------------------------------------------------------------------ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * Uses a MOCK schema view so it's pure and game-file-independent.
 * ------------------------------------------------------------------ */
export function runNodeDiagnosticsSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });
  const N = (id: string, type: any, xmlTag: string, properties: any = {}): MDNode =>
    ({ id, type, xmlTag, properties, label: id, x: 0, y: 0, propertiesSchema: [], inputs: [], outputs: [] } as any);

  const mock: NodeSchemaView = {
    loaded: true,
    has: (t) => ['set_value', 'remove_value', 'reward_player', 'write_to_logbook', 'set_faction_relation', 'show_help', 'event_game_started'].includes(t),
    requiredAttrs: (t) => t === 'write_to_logbook' ? ['title'] : t === 'set_faction_relation' ? ['value'] : t === 'set_value' ? ['name'] : [],
  };

  const nodes: MDNode[] = [
    N('c', 'cue', 'cue', { name: 'C' }),
    N('add', 'action', 'add_value', { name: '$x' }),                              // unknown element (not real)
    N('sv', 'action', 'set_value', { name: '$x', exact: '1' }),                   // ok
    N('logBad', 'action', 'write_to_logbook', { category: 'general', text: 'hi' }), // missing required title
    N('logOk', 'action', 'write_to_logbook', { title: 'T', text: 'hi' }),         // ok
    N('relBad', 'action', 'set_faction_relation', { faction: 'player' }),         // missing required value
    N('cx', 'action', 'custom_xml', { rawXml: '<foo/>' }),                        // studio-special: skipped
    N('help', 'action', 'show_help', { text: 'hi' }),                             // transform tag: attr check skipped (text→custom)
  ];
  const d = validateNodesAgainstSchema(nodes, mock);
  const has = (nodeId: string, code: string) => d.some((x) => x.nodeId === nodeId && x.code === code);

  ok('unknown_element_flagged', has('add', 'unknown_element'), d);
  ok('valid_node_clean', !d.some((x) => x.nodeId === 'sv'));
  ok('missing_required_attr_flagged', has('logBad', 'missing_required_attr'), d);
  ok('present_required_attr_clean', !d.some((x) => x.nodeId === 'logOk'), d);
  ok('missing_value_flagged', has('relBad', 'missing_required_attr'), d);
  ok('custom_xml_skipped', !d.some((x) => x.nodeId === 'cx'));
  ok('transform_tag_attr_skipped', !d.some((x) => x.nodeId === 'help'), d);
  ok('cue_skipped', !d.some((x) => x.nodeId === 'c'));

  // severity: unknown=warning, missing-attr=error
  ok('unknown_is_warning', d.find((x) => x.nodeId === 'add')!.severity === 'warning');
  ok('missing_attr_is_error', d.find((x) => x.nodeId === 'logBad')!.severity === 'error');

  // rollup
  const sum = summarizeByNode(d);
  ok('rollup_error_node', sum['logBad']?.severity === 'error');
  ok('rollup_has_messages', (sum['add']?.messages || []).length === 1);

  // no schema → no findings (no false negatives surfaced as false positives)
  ok('unloaded_schema_silent', validateNodesAgainstSchema(nodes, { ...mock, loaded: false }).length === 0);

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

// overrideMap.ts — T4.4 Override Visualizer engine (Inc 1).
//
// EXTENDS the Extension Doctor (server.ts runExtensionDoctor): the Doctor detects
// that >=2 mods touch the same base file and simulates load order; this module is
// the per-element drill-down on top of that data — for one target file, it builds
// the map of WHO rewrites WHAT (element/attribute granularity) and WHO WINS by
// load order. It deliberately reuses the Doctor's data shapes (folder/isDiff/
// selectors records, loadOrder array) and its xpath+xmldom resolution approach.
// It is NOT a new scan system: the server collects records, this module analyzes.
//
// House pattern: pure engine + runOverrideMapSelftest() oracle + public GET
// (wired in server.ts), THEN UI (Inc 2: PackageModDoctor drill-down panel).

import * as xpathLib from "xpath";
import { DOMParser } from "@xmldom/xmldom";
import { selectorFor } from "./xpathSynth";

export interface PatchSelector { op: string; sel: string }

/** One mod's file occupying the target base path — same shape the Doctor collects. */
export interface OverrideRecord {
  folder: string;
  /** false = full-file override (no <diff> root) */
  isDiff: boolean;
  selectors: PatchSelector[];
}

export interface OverrideClaim {
  folder: string;
  /** add | replace | remove | fullfile */
  op: string;
  sel: string;
}

export interface OverrideEntry {
  /** Human-readable node identity: element path, element path + "/@attr", or "(entire file)". */
  node: string;
  kind: "element" | "attribute" | "file" | "selector";
  /** Claims sorted by simulated load order (earliest first). */
  claims: OverrideClaim[];
  /** >=2 distinct mods AND at least one destructive op (replace/remove/fullfile). */
  contested: boolean;
  /** >=2 distinct mods, all ops are add — X4 merges appends, low risk. */
  merged: boolean;
  /** Last-loaded claimant (the one whose change survives) — always set. */
  winner: string;
}

export interface OverrideMap {
  targetFile: string;
  /** Whether node identity was resolved against real base content ("base") or by
   *  normalized selector-string identity only ("string" — pre-T4.1 fallback). */
  resolution: "base" | "string";
  /** Folders claiming this file, in simulated load order. */
  loadOrder: string[];
  entries: OverrideEntry[];
  counts: { contested: number; merged: number; single: number };
}

export interface AnalyzeOverridesInput {
  targetFile: string;
  records: OverrideRecord[];
  /** Simulated global load order (folder names) from the Extension Doctor. */
  loadOrder: string[];
  /** Resolved vanilla content of targetFile, when available (loose or .cat/.dat). */
  baseContent?: string | null;
}

// Bounds mirror the Doctor's xpath-overlap guards.
const MAX_BASE_BYTES = 2_000_000;
const MAX_SELECTOR_EVALS = 200;
const MAX_MATCHES_PER_SELECTOR = 50;
const MAX_ENTRIES = 500;

// Element-path identity is delegated to xpathSynth.selectorFor — one selector
// builder for the whole codebase (review unification; a local near-duplicate
// lived here until the 38th pass).

function normalizeSel(sel: string): string {
  return sel.replace(/\s+/g, " ").trim();
}

function loadRankMap(loadOrder: string[]): Map<string, number> {
  return new Map(loadOrder.map((f, i) => [f, i]));
}

/**
 * Build the per-element override map for one contested base file.
 * Pure: no fs, no network — the caller supplies records, load order, and
 * (optionally) the resolved vanilla content.
 */
export function analyzeOverrides(input: AnalyzeOverridesInput): OverrideMap {
  const { targetFile, records, baseContent } = input;
  const rank = loadRankMap(input.loadOrder);
  const byRank = (a: string, b: string) => (rank.get(a) ?? -1) - (rank.get(b) ?? -1);

  // Folders touching this file, in simulated load order.
  const fileLoadOrder = [...new Set(records.map(r => r.folder))].sort(byRank);

  // node-identity key -> { kind, claims[] }
  const buckets = new Map<string, { kind: OverrideEntry["kind"]; claims: OverrideClaim[] }>();
  const claim = (key: string, kind: OverrideEntry["kind"], c: OverrideClaim) => {
    const b = buckets.get(key) || { kind, claims: [] };
    b.claims.push(c);
    buckets.set(key, b);
  };

  // Full-file overrides claim the whole document.
  for (const r of records) {
    if (!r.isDiff) claim("(entire file)", "file", { folder: r.folder, op: "fullfile", sel: "(entire file)" });
  }

  // Diff selectors: resolve against base content when we can, else bucket by
  // normalized selector string (honest fallback — flagged via `resolution`).
  let resolution: OverrideMap["resolution"] = "string";
  let doc: any = null;
  if (baseContent && baseContent.length <= MAX_BASE_BYTES) {
    try {
      doc = new DOMParser({ onError: () => { /* tolerate recoverable parse noise */ } })
        .parseFromString(baseContent, "text/xml");
      if (doc && doc.documentElement) resolution = "base";
      else doc = null;
    } catch { doc = null; }
  }

  let evaluated = 0;
  for (const r of records) {
    if (!r.isDiff) continue;
    for (const s of r.selectors) {
      const op = (s.op || "").toLowerCase();
      const c: OverrideClaim = { folder: r.folder, op, sel: s.sel };
      let matchedAny = false;
      if (doc && evaluated < MAX_SELECTOR_EVALS) {
        evaluated++;
        let matches: any;
        try { matches = xpathLib.select(s.sel, doc); } catch { matches = null; }
        if (Array.isArray(matches)) {
          for (const n of matches.slice(0, MAX_MATCHES_PER_SELECTOR)) {
            if (n && n.nodeType === 2) {
              // attribute node — key on owner element path + /@name
              const owner = (n as any).ownerElement;
              const key = `${owner ? selectorFor(owner) : ""}/@${n.nodeName}`;
              claim(key, "attribute", c);
              matchedAny = true;
            } else if (n && n.nodeType === 1) {
              claim(selectorFor(n), "element", c);
              matchedAny = true;
            }
          }
        }
      }
      // Selector unresolvable (no base, eval budget spent, bad xpath, or zero
      // matches — e.g. it targets another mod's addition): identity = the string.
      if (!matchedAny) claim(normalizeSel(s.sel), "selector", c);
    }
  }

  const entries: OverrideEntry[] = [];
  for (const [node, b] of buckets) {
    if (entries.length >= MAX_ENTRIES) break;
    const claims = [...b.claims].sort((a, c2) => byRank(a.folder, c2.folder));
    const folders = [...new Set(claims.map(x => x.folder))].sort(byRank);
    const destructive = claims.some(x => x.op === "replace" || x.op === "remove" || x.op === "fullfile");
    const contested = folders.length >= 2 && destructive;
    const merged = folders.length >= 2 && !destructive;
    entries.push({ node, kind: b.kind, claims, contested, merged, winner: folders[folders.length - 1] });
  }
  // contested first, then merged, then singles; stable by node name within groups
  const sevRank = (e: OverrideEntry) => (e.contested ? 0 : e.merged ? 1 : 2);
  entries.sort((a, b2) => sevRank(a) - sevRank(b2) || a.node.localeCompare(b2.node));

  const counts = { contested: 0, merged: 0, single: 0 };
  for (const e of entries) {
    if (e.contested) counts.contested++;
    else if (e.merged) counts.merged++;
    else counts.single++;
  }

  return { targetFile, resolution, loadOrder: fileLoadOrder, entries, counts };
}

/**
 * X4 load order: alphabetical by folder name (case-insensitive), with declared
 * dependencies loaded before their dependents. Deterministic topological sort —
 * extracted (38th pass) so runExtensionDoctor and the override-map endpoint
 * share ONE implementation instead of two copies.
 */
export function simulateLoadOrder(exts: { folder: string; idLower: string; deps: { id: string }[] }[]): string[] {
  const byIdLower = new Map(exts.map(e => [e.idLower, e]));
  const order: string[] = [];
  const visited = new Set<string>();
  const visiting = new Set<string>();
  const visit = (e: { folder: string; idLower: string; deps: { id: string }[] }) => {
    if (visited.has(e.folder)) return;
    if (visiting.has(e.folder)) return; // dependency cycle — bail out of the branch
    visiting.add(e.folder);
    for (const d of [...e.deps].sort((a, b) => a.id.localeCompare(b.id))) {
      const dep = byIdLower.get(d.id.toLowerCase());
      if (dep) visit(dep);
    }
    visiting.delete(e.folder);
    visited.add(e.folder);
    order.push(e.folder);
  };
  for (const e of [...exts].sort((a, b) => a.folder.toLowerCase().localeCompare(b.folder.toLowerCase()))) visit(e);
  return order;
}

// ---------------------------------------------------------------------------
// Selftest oracle — synthetic 3-mod collision (per ROADMAP T4.4 Inc 1).
// ---------------------------------------------------------------------------

export interface SelftestCheck { name: string; pass: boolean; detail?: string }

export function runOverrideMapSelftest(): { allPassed: boolean; pass: boolean; passed: number; total: number; checks: SelftestCheck[] } {
  const checks: SelftestCheck[] = [];
  const ok = (name: string, pass: boolean, detail?: string) => checks.push({ name, pass, detail });

  const base = `<?xml version="1.0"?>
<jobs>
  <job id="shared"><orders foo="1" bar="2"/></job>
  <job id="solo"><orders foo="9"/></job>
</jobs>`;

  const records: OverrideRecord[] = [
    { folder: "mod_a", isDiff: true, selectors: [{ op: "replace", sel: "/jobs/job[@id='shared']" }] },
    { folder: "mod_b", isDiff: true, selectors: [
      { op: "remove", sel: "//job[@id='shared']" },        // different string, SAME node as mod_a's
      { op: "add", sel: "/jobs" }
    ] },
    { folder: "mod_c", isDiff: true, selectors: [
      { op: "add", sel: "/jobs" },                          // add+add with mod_b — merges
      { op: "replace", sel: "/jobs/job[@id='shared']/orders/@foo" } // attribute-level
    ] }
  ];
  const loadOrder = ["mod_a", "mod_b", "mod_c"];

  // --- with base content (real node identity) ---
  const m = analyzeOverrides({ targetFile: "libraries/jobs.xml", records, loadOrder, baseContent: base });

  ok("base resolution active", m.resolution === "base", `resolution=${m.resolution}`);

  const shared = m.entries.find(e => e.node === "/jobs/job[@id='shared']");
  ok("cross-string node identity: mod_a replace + mod_b remove land on ONE element entry",
    !!shared && shared.kind === "element" && new Set(shared.claims.map(c => c.folder)).size === 2,
    shared ? `claims=${shared.claims.map(c => `${c.folder}:${c.op}`).join(",")}` : "entry missing");
  ok("shared element contested with load-order winner mod_b",
    !!shared && shared.contested && shared.winner === "mod_b",
    shared ? `contested=${shared.contested} winner=${shared.winner}` : "entry missing");

  const adds = m.entries.find(e => e.node === "/jobs" && e.kind === "element");
  ok("add+add to shared parent is merged, not contested",
    !!adds && adds.merged && !adds.contested,
    adds ? `merged=${adds.merged} contested=${adds.contested}` : "entry missing");

  const attr = m.entries.find(e => e.kind === "attribute");
  ok("attribute-level claim resolves to element-path/@attr",
    !!attr && attr.node === "/jobs/job[@id='shared']/orders/@foo" && attr.winner === "mod_c",
    attr ? `node=${attr.node}` : "no attribute entry");
  ok("single-owner attribute is neither contested nor merged",
    !!attr && !attr.contested && !attr.merged);

  ok("counts consistent",
    m.counts.contested + m.counts.merged + m.counts.single === m.entries.length,
    JSON.stringify(m.counts));

  // --- full-file override joins the fight ---
  const m2 = analyzeOverrides({
    targetFile: "libraries/jobs.xml",
    records: [...records, { folder: "zz_fullmod", isDiff: false, selectors: [] }],
    loadOrder: [...loadOrder, "zz_fullmod"],
    baseContent: base
  });
  const ff = m2.entries.find(e => e.kind === "file");
  ok("full-file override produces an '(entire file)' claim with op fullfile",
    !!ff && ff.claims.some(c => c.op === "fullfile" && c.folder === "zz_fullmod"));

  // --- no base content: honest string-identity fallback ---
  const m3 = analyzeOverrides({ targetFile: "libraries/jobs.xml", records, loadOrder, baseContent: null });
  ok("no-base fallback reports resolution=string", m3.resolution === "string");
  const aStr = m3.entries.find(e => e.node === "/jobs/job[@id='shared']" && e.kind === "selector");
  const bStr = m3.entries.find(e => e.node === "//job[@id='shared']" && e.kind === "selector");
  ok("without base, differing selector strings stay separate entries (no fabricated identity)",
    !!aStr && !!bStr && aStr !== bStr);

  // --- dangling selector (matches nothing in base) falls back per-selector ---
  const m4 = analyzeOverrides({
    targetFile: "libraries/jobs.xml",
    records: [{ folder: "mod_x", isDiff: true, selectors: [{ op: "remove", sel: "//job[@id='does_not_exist']" }] }],
    loadOrder: ["mod_x"],
    baseContent: base
  });
  ok("zero-match selector degrades to a selector-identity entry without crashing",
    m4.entries.length === 1 && m4.entries[0].kind === "selector" && m4.entries[0].winner === "mod_x");

  const lo = simulateLoadOrder([
    { folder: "mod_b", idLower: "mod_b", deps: [{ id: "zdep_id" }] },
    { folder: "mod_z", idLower: "zdep_id", deps: [] }
  ]);
  ok("simulateLoadOrder: dependencies load before dependents despite alphabetical order",
    lo.join(",") === "mod_z,mod_b", lo.join(","));

  const passed = checks.filter(c => c.pass).length;
  const allPassed = passed === checks.length;
  return { allPassed, pass: allPassed, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Port-semantics layer (50th pass).
 *
 * Forge's raw port `type` (flow|data|parent|child) is too coarse to express two things
 * the editor and simulator need:
 *   1. WHAT A PORT ACCEPTS — so the drag-off-pin quick-add (#2) can filter to genuinely
 *      compatible nodes without emptying the menu on flow-type drags.
 *   2. THAT A CONTROL-FLOW NODE HAS A BODY distinct from its NEXT sibling — so the
 *      simulator can gate do_if branches precisely instead of conservatively tainting
 *      everything downstream.
 *
 * This module adds a thin deterministic semantic layer over the existing port ids. It
 * changes no wire behavior on its own; consumers (quick-add filter, compiler, simulator)
 * opt in. It is strictly additive and backward-compatible.
 */

import type { MDNode, MDLink, Port } from '../types';

/** Semantic connection class. An output of slot X connects to an input of slot X. */
export type Slot = 'condition' | 'action' | 'cue';

export interface PortSemantic {
  direction: 'in' | 'out';
  /** For an input: the class it accepts. For an output: the class it connects to. */
  slot: Slot;
}

/**
 * The single source of truth mapping each known port id → its direction + slot.
 * Outputs are tagged with the slot of the inputs they legally connect to.
 */
export const PORT_SLOTS: Record<string, PortSemantic> = {
  // cue ports
  in_flow: { direction: 'in', slot: 'cue' },        // a cue's parent socket (target of out_sub)
  out_sub: { direction: 'out', slot: 'cue' },       // a cue's sub-cue socket → connects to in_flow
  out_cond: { direction: 'out', slot: 'condition' },// a cue's conditions socket → connects to in_cond
  out_act: { direction: 'out', slot: 'action' },    // a cue's actions socket → connects to in_act
  // condition / event ports
  in_cond: { direction: 'in', slot: 'condition' },  // a condition/event input
  out_flow: { direction: 'out', slot: 'action' },   // event/condition trigger flow → connects to in_act
  // action ports
  in_act: { direction: 'in', slot: 'action' },      // an action input
  out_next: { direction: 'out', slot: 'action' },   // action → next action
  out_body: { direction: 'out', slot: 'action' },   // control-flow BODY → first action inside the branch
};

/** Control-flow container tags that own a body (their actions nest inside the element). */
export const CONTAINER_TAGS = new Set<string>([
  'do_if', 'do_elseif', 'do_else', 'do_while', 'do_for_each', 'do_all',
]);

export function isContainerTag(tag: string | undefined | null): boolean {
  return !!tag && CONTAINER_TAGS.has(String(tag));
}

const slotOf = (portId: string): PortSemantic | undefined => PORT_SLOTS[portId];

/**
 * Can a wire drawn FROM `sourcePortId` (on some node) legally land on `targetNode`?
 * - source is an OUTPUT of slot X ⇒ target must expose an INPUT of slot X.
 * - source is an INPUT of slot X ⇒ target must expose an OUTPUT of slot X.
 * Unknown ports are permissive (return true) so we never over-filter on data we don't model.
 */
export function canConnect(sourcePortId: string, targetNode: Pick<MDNode, 'inputs' | 'outputs'>): boolean {
  const src = slotOf(sourcePortId);
  if (!src) return true; // unknown port id ⇒ don't block
  const ports: Port[] = src.direction === 'out' ? (targetNode.inputs || []) : (targetNode.outputs || []);
  const wantDir = src.direction === 'out' ? 'in' : 'out';
  return ports.some((p) => {
    const ps = slotOf(p.id);
    return ps && ps.direction === wantDir && ps.slot === src.slot;
  });
}

/** Filter a list of node templates to those a wire from `sourcePortId` can connect to. */
export function compatibleTemplates<T extends Pick<MDNode, 'inputs' | 'outputs'>>(
  sourcePortId: string,
  templates: T[],
): T[] {
  return templates.filter((t) => canConnect(sourcePortId, t));
}

/**
 * The action chain INSIDE a control-flow node's body: first node via out_body, then
 * following out_next. Cycle-safe. Empty when the node has no out_body wiring (legacy flat).
 */
export function bodyChainOf(nodeId: string, nodeById: Map<string, MDNode>, links: MDLink[]): MDNode[] {
  const out: MDNode[] = [];
  const first = links.find((l) => l.sourceNodeId === nodeId && l.sourcePortId === 'out_body');
  if (!first) return out;
  let cur = nodeById.get(first.targetNodeId);
  const seen = new Set<string>();
  while (cur && !seen.has(cur.id)) {
    seen.add(cur.id);
    out.push(cur);
    const next = links.find((l) => l.sourceNodeId === cur!.id && l.sourcePortId === 'out_next');
    cur = next ? nodeById.get(next.targetNodeId) : undefined;
  }
  return out;
}

/** True if the node has a wired body (⇒ precise gating is possible for it). */
export function hasBody(nodeId: string, links: MDLink[]): boolean {
  return links.some((l) => l.sourceNodeId === nodeId && l.sourcePortId === 'out_body');
}

/* ============================================================================ *
 * Self-test oracle. House contract: { allPassed, passed, total, checks }.
 * ============================================================================ */
export function runPortSemanticsSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const mk = (inIds: string[], outIds: string[]): Pick<MDNode, 'inputs' | 'outputs'> => ({
    inputs: inIds.map((id) => ({ id, name: id, type: 'child' as const })),
    outputs: outIds.map((id) => ({ id, name: id, type: 'flow' as const })),
  });
  const actionNode = mk(['in_act'], ['out_next']);
  const containerNode = mk(['in_act'], ['out_next', 'out_body']);
  const eventNode = mk(['in_cond'], ['out_flow']);
  const conditionNode = mk(['in_cond'], ['out_flow']);
  const cueNode = mk(['in_flow'], ['out_cond', 'out_act', 'out_sub']);

  // ---- output → input slot matching ----
  ok('out_next→action_ok', canConnect('out_next', actionNode) === true);
  ok('out_next→container_ok', canConnect('out_next', containerNode) === true);
  ok('out_next→event_no', canConnect('out_next', eventNode) === false);
  ok('out_next→cue_no', canConnect('out_next', cueNode) === false);
  ok('out_act→action_ok', canConnect('out_act', actionNode) === true);
  ok('out_cond→event_ok', canConnect('out_cond', eventNode) === true);
  ok('out_cond→condition_ok', canConnect('out_cond', conditionNode) === true);
  ok('out_cond→action_no', canConnect('out_cond', actionNode) === false);
  ok('out_sub→cue_ok', canConnect('out_sub', cueNode) === true);
  ok('out_sub→action_no', canConnect('out_sub', actionNode) === false);
  ok('out_flow→action_ok', canConnect('out_flow', actionNode) === true);
  ok('out_body→action_ok', canConnect('out_body', actionNode) === true);

  // ---- input-source drag (dragging from an input pin) ----
  ok('in_act←action_out', canConnect('in_act', actionNode) === true); // action has out_next (action slot)
  // in_cond is slot 'condition'; the producer of a 'condition' slot is a cue's out_cond — NOT an
  // event's out_flow (which is slot 'action'). So in_cond matches the cue, not the event.
  ok('in_cond←cue_out', canConnect('in_cond', cueNode) === true);    // cue has out_cond (condition slot)
  ok('in_cond←event_no', canConnect('in_cond', eventNode) === false);
  ok('in_flow←cue_out', canConnect('in_flow', cueNode) === true);    // cue has out_sub (cue slot)

  // ---- the regression guard: flow-type drag must NOT empty the menu ----
  const templates = [actionNode, containerNode, eventNode, cueNode];
  ok('flow_drag_not_empty', compatibleTemplates('out_next', templates).length === 2, compatibleTemplates('out_next', templates).length);
  ok('cond_drag_filters', compatibleTemplates('out_cond', templates).length === 1);
  ok('sub_drag_filters', compatibleTemplates('out_sub', templates).length === 1);

  // ---- unknown port id is permissive ----
  ok('unknown_port_permissive', canConnect('out_mystery', actionNode) === true);

  // ---- container detection ----
  ok('container_do_if', isContainerTag('do_if') === true);
  ok('container_do_while', isContainerTag('do_while') === true);
  ok('container_not_reward', isContainerTag('reward_player') === false);

  // ---- bodyChainOf walks out_body → out_next ----
  {
    const N = (id: string, xmlTag: string): MDNode => ({ id, type: 'action', xmlTag, properties: {}, label: id, x: 0, y: 0, propertiesSchema: [], inputs: [], outputs: [] } as any);
    const nodes = [N('g', 'do_if'), N('b1', 'set_value'), N('b2', 'reward_player'), N('s', 'play_sound')];
    const byId = new Map(nodes.map((n) => [n.id, n]));
    const links: MDLink[] = [
      { id: 'l1', sourceNodeId: 'g', sourcePortId: 'out_body', targetNodeId: 'b1', targetPortId: 'in_act' },
      { id: 'l2', sourceNodeId: 'b1', sourcePortId: 'out_next', targetNodeId: 'b2', targetPortId: 'in_act' },
      { id: 'l3', sourceNodeId: 'g', sourcePortId: 'out_next', targetNodeId: 's', targetPortId: 'in_act' }, // sibling, NOT body
    ];
    const body = bodyChainOf('g', byId, links).map((n) => n.id).join(',');
    ok('body_chain_excludes_sibling', body === 'b1,b2', body);
    ok('has_body_true', hasBody('g', links) === true);
    ok('has_body_false', hasBody('s', links) === false);
  }

  const passed = checks.filter((c) => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * P3 — agent multi-file orchestration over ExtensionProject.
 *
 * Stateless and deterministic: agents pass/receive a whole ExtensionProject and can
 * create, add files, generate a bounded starter project, validate, and package it
 * without mutating the active Studio workspace.
 */

import {
  addFile,
  buildContentXml,
  classifyPath,
  createProject,
  indexCueReferences,
  validateProjectStructure,
  type ContentMeta,
  type ExtensionProject,
  type ProjectFile,
} from './extensionProject';
import { aiInfluenceChatBlocks, buildLuaLogicScript } from './luaLogicBlocks';
import { generateContractMdScript, generateHttpGlueLua, type IntegrationContract } from './contractGlue';
import { analyzeLuaFiles } from './luaStaticAnalysis';
import { validateProjectCrossFile } from './projectCrossFileValidation';

export interface ProjectCreateRequest {
  id: string;
  name?: string;
  version?: string;
  author?: string;
  description?: string;
  deps?: ContentMeta['deps'];
}

export interface ProjectGenerationSpec extends ProjectCreateRequest {
  kind?: 'ai_influence_starter';
}

function safeId(id: string): string {
  return String(id || 'ai_influence').trim().toLowerCase().replace(/[^a-z0-9_]+/g, '_').replace(/^_+|_+$/g, '') || 'ai_influence';
}

function normalizeProject(project: ExtensionProject): ExtensionProject {
  let out = createProject(safeId(project.id), project.name || project.id || 'Extension Project');
  for (const file of project.files || []) {
    out = addFile(out, { ...file, kind: file.kind || classifyPath(file.path) });
  }
  return out;
}

export function createAgentProject(req: ProjectCreateRequest): ExtensionProject {
  const id = safeId(req.id);
  let project = createProject(id, req.name || id);
  project = addFile(project, {
    path: 'content.xml',
    kind: 'content',
    content: buildContentXml({
      id,
      name: req.name || id,
      version: req.version || '1.0.0',
      author: req.author || 'X4 Forge',
      description: req.description || '',
      deps: req.deps || [],
    }),
  });
  return project;
}

export function createProjectFile(project: ExtensionProject, file: Pick<ProjectFile, 'path' | 'content'> & Partial<ProjectFile>): ExtensionProject {
  return addFile(normalizeProject(project), {
    path: file.path,
    kind: file.kind || classifyPath(file.path),
    content: file.content || '',
  });
}

function aiInfluenceContract(): IntegrationContract {
  return {
    namespace: 'ai_influence',
    baseUrl: 'http://127.0.0.1:8713',
    endpoints: [
      {
        id: 'chat',
        method: 'POST',
        path: '/v1/chat',
        request: [{ name: 'prompt', type: 'string', required: true }],
        response: [{ name: 'reply', type: 'string' }],
      },
    ],
  };
}

function aiInfluenceMainMd(modId: string): string {
  return `<?xml version="1.0" encoding="utf-8"?>
<mdscript name="${modId}_main" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xsi:noNamespaceSchemaLocation="md.xsd">
  <cues>
