</mdscript>`;
}

export function generateAgentProject(spec: ProjectGenerationSpec): ExtensionProject {
  const id = safeId(spec.id || 'ai_influence');
  const contract = aiInfluenceContract();
  let project = createAgentProject({
    id,
    name: spec.name || 'AI Influence',
    version: spec.version || '1.0.0',
    author: spec.author || 'X4 Forge',
    description: spec.description || 'Generated AI Influence starter project.',
    deps: spec.deps || [{ id: 'djfhe_http', optional: true }],
  });
  project = createProjectFile(project, { path: `md/${id}_main.xml`, content: aiInfluenceMainMd(id) });
  project = createProjectFile(project, { path: `md/${id}_contract.xml`, content: generateContractMdScript(contract, `${id}_contract`) });
  project = createProjectFile(project, { path: `ui/${id}_contract.lua`, content: generateHttpGlueLua(contract) });
  project = createProjectFile(project, { path: `ui/ai_influence_chat.lua`, content: buildLuaLogicScript(aiInfluenceChatBlocks()) });
  return project;
}

export function packageAgentProject(project: ExtensionProject) {
  const normalized = normalizeProject(project);
  const files: Record<string, string> = {};
  for (const file of normalized.files) {
    files[file.path.replace(/\\/g, '/').replace(/^\/+/, '')] = file.content || '';
  }
  const structure = validateProjectStructure(normalized);
  const cueIndex = indexCueReferences(normalized);
  const luaFiles = normalized.files
    .filter(f => f.path.toLowerCase().endsWith('.lua'))
    .map(f => ({ rel: f.path, text: f.content || '', source: 'loose' as const, sourcePath: 'project', extension: { folder: normalized.id, id: normalized.id, name: normalized.name } }));
  const lua = analyzeLuaFiles(luaFiles);
  const crossFile = validateProjectCrossFile(normalized);
  const errors = structure.filter(i => i.severity === 'error').length + cueIndex.unresolved.length + lua.findings.filter(f => f.severity === 'error').length + crossFile.summary.errors;
  return {
    ok: errors === 0,
    project: normalized,
    files,
    summary: {
      files: Object.keys(files).length,
      structuralErrors: structure.filter(i => i.severity === 'error').length,
      unresolvedCueRefs: cueIndex.unresolved.length,
      luaFiles: lua.filesScanned,
      luaErrors: lua.findings.filter(f => f.severity === 'error').length,
      crossFileErrors: crossFile.summary.errors,
      mdLuaMissingRegisters: crossFile.summary.mdLuaMissingRegisters,
      luaMdMissingListeners: crossFile.summary.luaMdMissingListeners,
    },
    validation: { structure, cueIndex, lua, crossFile },
  };
}

export function runProjectOrchestrationSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const created = createAgentProject({ id: 'AI Influence', name: 'AI Influence', deps: [{ id: 'djfhe_http', optional: true }] });
  ok('create_adds_content_xml', created.files.some(f => f.path === 'content.xml' && f.content?.includes('<dependency id="djfhe_http"')));

  const withFile = createProjectFile(created, { path: 'md/extra.xml', content: '<mdscript name="Extra"><cues><cue name="Start"/></cues></mdscript>' });
  ok('file_create_classifies_and_adds', withFile.files.some(f => f.path === 'md/extra.xml' && f.kind === 'md'));

  const generated = generateAgentProject({ id: 'ai_influence', kind: 'ai_influence_starter' });
  const pkg = packageAgentProject(generated);
  ok('generate_creates_multifile_project', generated.files.length >= 5, generated.files.map(f => f.path));
  ok('generate_includes_ai_influence_lua', !!pkg.files['ui/ai_influence_chat.lua'] && pkg.files['ui/ai_influence_chat.lua'].includes('poll_chat_response'));
  ok('generate_includes_contract_md_and_lua', !!pkg.files['md/ai_influence_contract.xml'] && !!pkg.files['ui/ai_influence_contract.lua']);
  ok('package_returns_file_manifest', pkg.ok && Object.keys(pkg.files).includes('content.xml'), pkg.summary);
  ok('package_validates_cross_file_refs', pkg.validation.cueIndex.references.some(r => r.scope === 'cross_file' && r.resolved), pkg.validation.cueIndex);
  ok('package_luaparse_clean', pkg.summary.luaFiles >= 2 && pkg.summary.luaErrors === 0, pkg.validation.lua.findings);
  ok('package_cross_file_validation_clean', pkg.summary.crossFileErrors === 0 && pkg.validation.crossFile.ok, pkg.validation.crossFile.findings);

  const badPkg = packageAgentProject(createProjectFile(created, { path: '../evil.lua', content: 'return true' }));
  ok('package_blocks_invalid_paths', !badPkg.ok && badPkg.validation.structure.some(i => i.code === 'invalid_path'), badPkg.validation.structure);

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, pass: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * A4.2 — Proposal review engine. Turns an AI-proposed workspace into a reviewable,
 * verifiable artifact BEFORE it can be applied: a node-level diff plus three
 * independent, separately-sourced verdicts (Codex round-2 three-verdict model):
 *   - Schema  : XSD/MD legality            (validateModWorkspace)
 *   - Graph   : ports/links/lineage sanity (analyzeCueLineage)
 *   - Intent  : does it satisfy the ask?   (A4.9 — not yet implemented → 'not-checked')
 *
 * Pure (no I/O), so it is the shared, unit-testable basis for both the review
 * card (A4.2 UI) and the Architect per-step done-checks (A5.3). The AI is never
 * the authority here — the deterministic verdicts are.
 */
import { ModWorkspace, generateMDXML, validateModWorkspace, sanitizeWorkspace, NODE_TEMPLATES } from '../types';
import { analyzeCueLineage } from './cueLineage';
import { checkIntent, type IntentRequirement, type IntentRequirementResult } from './intentCheck';

// A4.5 — boundary hardening. The curated visual vocabulary; combined at call time
// with the live md.xsd element set so legitimate schema-driven tags are NOT
// false-flagged (the trap sanitizeWorkspace documents).
const CURATED_TAGS = new Set(NODE_TEMPLATES.map((t: any) => t.xmlTag));

export type VerdictStatus = 'pass' | 'warn' | 'fail' | 'not-checked';

export interface ProposalVerdict {
  status: VerdictStatus;
  errors: number;
  warnings: number;
  detail?: string;
}

interface NodeBrief { id: string; label: string; xmlTag: string }

export interface ProposalReview {
  diff: { added: NodeBrief[]; removed: NodeBrief[]; changed: NodeBrief[] };
  nodeCounts: { base: number; proposed: number };
  verdicts: { schema: ProposalVerdict; graph: ProposalVerdict; intent: ProposalVerdict };
  /** A4.5 — nodes whose xmlTag is unrecognized (likely hallucinated); flagged, not silently carried. */
  unknownTags: NodeBrief[];
  /** A4.9 — per-requirement intent results when requirements are supplied. */
  intentResults?: IntentRequirementResult[];
  /** Safe to apply outright = no hard schema/graph error AND no unknown tags. */
  applySafe: boolean;
}

function brief(n: any): NodeBrief {
  return { id: String(n?.id ?? ''), label: String(n?.label ?? n?.id ?? ''), xmlTag: String(n?.xmlTag ?? '') };
}

/**
 * A4.5 — flag nodes carrying an xmlTag that matches neither the curated visual
 * vocabulary, the (optionally supplied) live md.xsd element set, nor a `custom*`
 * escape hatch. These are the most likely hallucinations (e.g. `set_god_mode`).
 * Pure; `knownTags` lets a caller inject the schema-derived tag set at runtime.
 */
export function findUnknownTags(ws: ModWorkspace, knownTags?: Set<string>): NodeBrief[] {
  const out: NodeBrief[] = [];
  for (const n of (ws?.nodes || []) as any[]) {
    const tag = String(n?.xmlTag ?? '').trim();
    if (!tag) continue;
    if (/^custom/i.test(tag)) continue; // intentional escape hatch (custom_xml, custom_event, …)
    if (CURATED_TAGS.has(tag)) continue;
    if (knownTags && knownTags.has(tag)) continue;
    out.push(brief(n));
  }
  return out;
}

function toVerdict(errors: number, warnings: number, detail?: string): ProposalVerdict {
  return { status: errors > 0 ? 'fail' : warnings > 0 ? 'warn' : 'pass', errors, warnings, detail };
}

/**
 * Compute the reviewable artifact for a proposed workspace against the current one.
 * Never throws — verdict computation is individually guarded so a malformed
 * proposal degrades to a 'fail' verdict rather than crashing the review.
 */
export function reviewProposal(base: ModWorkspace, proposed: ModWorkspace, opts?: { knownTags?: Set<string>; requirements?: IntentRequirement[] }): ProposalReview {
  const baseNodes = new Map<string, any>((base?.nodes || []).map(n => [n.id, n]));
  const propNodes = new Map<string, any>((proposed?.nodes || []).map(n => [n.id, n]));

  const added: NodeBrief[] = [];
  const removed: NodeBrief[] = [];
  const changed: NodeBrief[] = [];
  for (const [id, n] of propNodes) {
    if (!baseNodes.has(id)) added.push(brief(n));
    else if (JSON.stringify(baseNodes.get(id)) !== JSON.stringify(n)) changed.push(brief(n));
  }
  for (const [id, n] of baseNodes) {
    if (!propNodes.has(id)) removed.push(brief(n));
  }

  // Schema verdict — XSD/MD legality of the proposed workspace.
  let schema: ProposalVerdict;
  try {
    const code = generateMDXML(proposed);
    const diags = validateModWorkspace(proposed, code) || [];
    schema = toVerdict(
      diags.filter(d => d.severity === 'error').length,
      diags.filter(d => d.severity === 'warning').length,
    );
  } catch (e: any) {
    schema = { status: 'fail', errors: 1, warnings: 0, detail: e?.message || 'schema check threw' };
  }

  // Graph verdict — ports/links/cue-lineage coherence.
  let graph: ProposalVerdict;
  try {
    const findings = analyzeCueLineage(proposed?.nodes || [], (proposed as any)?.links || []).findings || [];
    graph = toVerdict(
      findings.filter(f => f.severity === 'error').length,
      findings.filter(f => f.severity === 'warning').length,
    );
  } catch (e: any) {
    graph = { status: 'fail', errors: 1, warnings: 0, detail: e?.message || 'graph check threw' };
  }

  // Intent verdict — A4.9 requirement-pattern assertions. When requirements are
  // supplied (extracted from the prompt), each is verified deterministically; a
  // green Schema/Graph can NEVER imply the prompt was satisfied. With no
  // requirements it stays 'not-checked' (honest — never "pass").
  let intent: ProposalVerdict;
  let intentResults: IntentRequirementResult[] | undefined;
  if (opts?.requirements && opts.requirements.length > 0) {
    const report = checkIntent(proposed, opts.requirements);
    intent = { status: report.verdict.status, errors: report.verdict.errors, warnings: report.verdict.warnings, detail: report.verdict.detail };
    intentResults = report.results;
  } else {
    intent = {
      status: 'not-checked',
      errors: 0,
      warnings: 0,
      detail: 'No requirements supplied — output legality does not prove the request was satisfied.',
    };
  }

  const unknownTags = findUnknownTags(proposed, opts?.knownTags);

  return {
    diff: { added, removed, changed },
    nodeCounts: { base: baseNodes.size, proposed: propNodes.size },
    verdicts: { schema, graph, intent },
    unknownTags,
    intentResults,
    // applySafe gates on hard legality (schema/graph/unknown tags). Intent failures
    // are surfaced loudly but do NOT hard-block apply — a valid-but-incomplete build
    // is safe to apply and iterate on (the user decides), per A4.2.
    applySafe: schema.status !== 'fail' && graph.status !== 'fail' && unknownTags.length === 0,
  };
}

// ---------------------------------------------------------------------------
// Deterministic oracle (synthetic fixtures; no disk/AI/key). Asserts the review
// engine's contract: diff exactness, verdict shape, and applySafe consistency.
// ---------------------------------------------------------------------------
function mkNode(id: string, type: string, xmlTag: string, props: Record<string, any> = {}): any {
  return { id, type, label: id, xmlTag, x: 0, y: 0, properties: props };
}
function mkWs(nodes: any[], links: any[] = []): ModWorkspace {
  return sanitizeWorkspace({ name: 'Selftest_WS', version: '1.0.0', author: 'oracle', description: '', nodes, links, uiWidgets: [], uiTheme: {} });
}

export function runProposalReviewSelftest(): {
  allPassed: boolean; pass: boolean; passed: number; total: number;
  checks: { name: string; pass: boolean; detail?: string }[];
} {
  const checks: { name: string; pass: boolean; detail?: string }[] = [];
  const expect = (name: string, cond: boolean, detail?: string) => checks.push({ name, pass: !!cond, detail });

  // Base: a cue + an action. Proposed: keep the cue (modified), drop the action, add a new action.
  const base = mkWs([
    mkNode('cue_0', 'cue', 'cue', { name: 'Start' }),
    mkNode('act_0', 'action', 'show_help', { text: 'hi' }),
  ]);
  const proposed = mkWs([
    mkNode('cue_0', 'cue', 'cue', { name: 'Start_Renamed' }), // changed
    mkNode('act_1', 'action', 'reward_player', { money: '5000' }), // added
  ]);

  const r = reviewProposal(base, proposed);

  expect('added detected', r.diff.added.length === 1 && r.diff.added[0].id === 'act_1', JSON.stringify(r.diff.added));
  expect('removed detected', r.diff.removed.length === 1 && r.diff.removed[0].id === 'act_0', JSON.stringify(r.diff.removed));
  expect('changed detected', r.diff.changed.length === 1 && r.diff.changed[0].id === 'cue_0', JSON.stringify(r.diff.changed));
  expect('node counts', r.nodeCounts.base === 2 && r.nodeCounts.proposed === 2, JSON.stringify(r.nodeCounts));

  // No-op proposal (identical) → empty diff.
  const same = reviewProposal(base, base);
  expect('identical → empty diff', same.diff.added.length === 0 && same.diff.removed.length === 0 && same.diff.changed.length === 0);

  // Verdict shape + statuses are valid enum members.
  const validStatus = (v: ProposalVerdict) => ['pass', 'warn', 'fail', 'not-checked'].includes(v.status);
  expect('schema verdict valid', validStatus(r.verdicts.schema), r.verdicts.schema.status);
  expect('graph verdict valid', validStatus(r.verdicts.graph), r.verdicts.graph.status);
  expect('intent is not-checked (A4.9 stub)', r.verdicts.intent.status === 'not-checked');

  // applySafe is consistent with the schema/graph verdicts + unknown tags.
  const expectedSafe = r.verdicts.schema.status !== 'fail' && r.verdicts.graph.status !== 'fail' && r.unknownTags.length === 0;
  expect('applySafe consistent', r.applySafe === expectedSafe);

  // A4.5 — unknown-tag flagging. Hallucinated tag flagged; curated/custom not; never applySafe.
  const halluc = mkWs([
    mkNode('cue_0', 'cue', 'cue', { name: 'X' }),
    mkNode('act_h', 'action', 'set_god_mode', {}),   // invented capability
    mkNode('act_c', 'action', 'custom_xml', { xml: '<x/>' }), // escape hatch — NOT unknown
  ]);
  const hr = reviewProposal(base, halluc);
  expect('hallucinated tag flagged', hr.unknownTags.length === 1 && hr.unknownTags[0].id === 'act_h', JSON.stringify(hr.unknownTags));
  expect('custom_* not flagged', !hr.unknownTags.some(u => u.id === 'act_c'));
  expect('curated tag (cue) not flagged', !hr.unknownTags.some(u => u.id === 'cue_0'));
  expect('unknown tag → not applySafe', hr.applySafe === false);
  // Injected knownTags (schema-derived) suppress the flag.
  const hr2 = reviewProposal(base, halluc, { knownTags: new Set(['set_god_mode']) });
  expect('knownTags suppresses flag', hr2.unknownTags.length === 0);

  // A4.9 integration: supplied requirements drive the Intent verdict (base has a 'cue').
  const reqReview = reviewProposal(base, base, { requirements: [{ id: 'r', label: 'has a cue', check: { kind: 'nodePresent', xmlTag: 'cue' } }] });
  expect('intent verdict from requirements', reqReview.verdicts.intent.status !== 'not-checked' && Array.isArray(reqReview.intentResults), JSON.stringify(reqReview.verdicts.intent));
  expect('intent default not-checked w/o reqs', reviewProposal(base, base).verdicts.intent.status === 'not-checked');

  // A workspace whose graph has a hard error (dangling link) must NOT be applySafe.
  const broken = mkWs(
    [mkNode('cue_0', 'cue', 'cue', { name: 'X' })],
    [{ id: 'l0', sourceNodeId: 'cue_0', sourcePortId: 'out_act', targetNodeId: 'ghost', targetPortId: 'in_act' }],
  );
  const br = reviewProposal(base, broken);
  expect('dangling link → graph fail', br.verdicts.graph.status === 'fail', JSON.stringify(br.verdicts.graph));
  expect('graph fail → not applySafe', br.applySafe === false);

  const passed = checks.filter(c => c.pass).length;
  const allPassed = passed === checks.length;
  return { allPassed, pass: allPassed, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * UI layout — the engine-correct, responsive model for X4 menus/HUD.
 *
 * X4's UI is fTable-native (Helper.createFtable rows/cells), NOT absolute pixels, and
 * absolute coordinates clip/overflow across resolutions, aspect ratios, and HUD scale.
 * So the canonical *compile model* is a logical grid (rows/cols + row/col span) emitted
 * as a declarative Lua table that a generic createMenu loader builds into an ftable at
 * runtime. This module is that model + its validation + its Lua emit, PLUS the bridge
 * (`pixelLayoutToGrid`) that turns the free-form designer's pixel widgets into a
 * validated grid descriptor — so the comfortable visual editor feeds the engine-correct
 * pipeline instead of a parallel one.
 *
 * Honesty note: `generateLayoutLua` emits DATA only (no fabricated Helper calls); the
 * generic runtime loader that turns this table into real ftable construction is the
 * deferred, in-game-verified piece (T1.3).
 */

export type UIWidgetType =
  | 'window' | 'table' | 'button' | 'label' | 'progressbar'
  | 'textinput' | 'selector' | 'chatlog' | 'icon';

export const UI_WIDGET_TYPES: UIWidgetType[] = [
  'window', 'table', 'button', 'label', 'progressbar', 'textinput', 'selector', 'chatlog', 'icon'
];

export interface GridWidget {
  id: string;
  type: UIWidgetType;
  row: number;   // 1-based
  col: number;   // 1-based
  rowSpan?: number;
  colSpan?: number;
  label?: string;
  binding?: string;
}

export interface UILayoutDescriptor {
  name: string;
  rows: number;
  cols: number;
  widgets: GridWidget[];
}

export type UILayoutSeverity = 'error' | 'warning';
export type UILayoutCode =
  | 'bad_name' | 'bad_grid' | 'duplicate_id' | 'bad_id'
  | 'invalid_type' | 'out_of_bounds' | 'overlap' | 'empty_layout';

export interface UILayoutFinding {
  severity: UILayoutSeverity;
  code: UILayoutCode;
  widgetId?: string;
  message: string;
}

const ID_RE = /^[a-z][a-z0-9_]*$/i;

function span(n: number | undefined): number {
  return Number.isInteger(n) && (n as number) >= 1 ? (n as number) : 1;
}

export function validateUILayout(layout: UILayoutDescriptor): UILayoutFinding[] {
  const f: UILayoutFinding[] = [];
  if (!layout || typeof layout !== 'object') return [{ severity: 'error', code: 'bad_name', message: 'Layout is missing or not an object.' }];

  if (!layout.name || !ID_RE.test(layout.name)) f.push({ severity: 'error', code: 'bad_name', message: `Layout name "${layout.name ?? ''}" must match ${ID_RE}.` });
  const rows = layout.rows, cols = layout.cols;
  if (!Number.isInteger(rows) || rows < 1 || !Number.isInteger(cols) || cols < 1) {
    f.push({ severity: 'error', code: 'bad_grid', message: `Grid must be at least 1×1 (got ${rows}×${cols}).` });
  }

  const widgets = Array.isArray(layout.widgets) ? layout.widgets : [];
  if (widgets.length === 0) f.push({ severity: 'warning', code: 'empty_layout', message: 'Layout has no widgets.' });

  const gridOk = Number.isInteger(rows) && rows >= 1 && Number.isInteger(cols) && cols >= 1;
  const occupied = new Map<string, string>();
  const seen = new Set<string>();

  for (const w of widgets) {
    if (!w || typeof w !== 'object') { f.push({ severity: 'error', code: 'bad_id', message: 'A widget entry is missing or not an object.' }); continue; }
    if (!w.id || !ID_RE.test(w.id)) f.push({ severity: 'error', code: 'bad_id', widgetId: w.id, message: `Widget id "${w.id ?? ''}" must match ${ID_RE}.` });
    else if (seen.has(w.id)) f.push({ severity: 'error', code: 'duplicate_id', widgetId: w.id, message: `Duplicate widget id "${w.id}".` });
    else seen.add(w.id);

    if (UI_WIDGET_TYPES.indexOf(w.type) === -1) f.push({ severity: 'error', code: 'invalid_type', widgetId: w.id, message: `Widget "${w.id}" has invalid type "${w.type}".` });

    const rs = span(w.rowSpan), cs = span(w.colSpan);
    const inBounds = Number.isInteger(w.row) && Number.isInteger(w.col) && w.row >= 1 && w.col >= 1;
    if (!inBounds) {
      f.push({ severity: 'error', code: 'out_of_bounds', widgetId: w.id, message: `Widget "${w.id}" has an invalid position (row ${w.row}, col ${w.col}).` });
      continue;
    }
    if (gridOk && (w.row + rs - 1 > rows || w.col + cs - 1 > cols)) {
      f.push({ severity: 'error', code: 'out_of_bounds', widgetId: w.id, message: `Widget "${w.id}" (row ${w.row}, col ${w.col}, span ${rs}×${cs}) extends past the ${rows}×${cols} grid.` });
      continue;
    }
    if (gridOk) {
      for (let r = w.row; r < w.row + rs; r++) {
        for (let c = w.col; c < w.col + cs; c++) {
          const key = `${r},${c}`;
          const other = occupied.get(key);
          if (other) f.push({ severity: 'error', code: 'overlap', widgetId: w.id, message: `Widget "${w.id}" overlaps "${other}" at cell (${r}, ${c}).` });
          else occupied.set(key, w.id || '?');
        }
      }
    }
  }
  return f;
}

function luaStr(s: string): string {
  return '"' + String(s).replace(/\\/g, '\\\\').replace(/"/g, '\\"').replace(/\r?\n/g, ' ') + '"';
}

export function generateLayoutLua(layout: UILayoutDescriptor, modId: string): string {
  const errs = validateUILayout(layout).filter(x => x.severity === 'error');
  if (errs.length > 0) throw new Error(`Cannot generate layout Lua: ${errs.length} error(s): ${errs.map(e => e.message).join('; ')}`);

  const widgetLines = layout.widgets.map(w => {
    const parts = [
      `id = ${luaStr(w.id)}`, `type = ${luaStr(w.type)}`,
      `row = ${w.row}`, `col = ${w.col}`,
      `rowSpan = ${span(w.rowSpan)}`, `colSpan = ${span(w.colSpan)}`
    ];
    if (w.label) parts.push(`label = ${luaStr(w.label)}`);
    if (w.binding) parts.push(`binding = ${luaStr(w.binding)}`);
    return `        { ${parts.join(', ')} }`;
  }).join(',\n');

  return [
    `-- Auto-generated by X4:MD Studio — responsive UI layout descriptor for "${layout.name}" (mod ${modId})`,
    `-- DATA descriptor: a generic createMenu loader builds an ftable (rows/cells) from this`,
    `-- table at runtime, so it scales across resolutions / aspect ratios / HUD scale.`,
    `-- No runtime Helper/widgetSystem calls are fabricated here.`,
    ``,
    `local layout = {`,
    `    name = ${luaStr(layout.name)},`,
    `    grid = { rows = ${layout.rows}, cols = ${layout.cols} },`,
    `    widgets = {`,
    widgetLines,
    `    }`,
    `}`,
    ``,
    `return layout`,
    ``
  ].join('\n');
}

// ---------------------------------------------------------------------------------------
// BRIDGE: free-form pixel widgets (the existing Layout GUI Designer model) -> grid descriptor
// ---------------------------------------------------------------------------------------

export interface PixelWidget {
  id: string;
  type?: string;
  x: number; y: number; w: number; h: number;
  label?: string;
  properties?: Record<string, any>;
}

/** Map the designer's free-form widget types to the engine-grid widget types. */
const PIXEL_TYPE_MAP: Record<string, UIWidgetType> = {
  window: 'window', table: 'table', button: 'button', text: 'label', label: 'label',
  progressbar: 'progressbar', dropdown: 'selector', selector: 'selector', header: 'label',
  input: 'textinput', textinput: 'textinput', chat: 'chatlog', chatlog: 'chatlog', icon: 'icon'
};

/** Sorted unique numbers within an epsilon (snap near-equal coordinates together). */
function uniqSorted(nums: number[], eps = 4): number[] {
  const s = nums.slice().sort((a, b) => a - b);
  const out: number[] = [];
  for (const n of s) if (out.length === 0 || n - out[out.length - 1] > eps) out.push(n);
  return out;
}
function trackIndex(edges: number[], value: number, eps = 4): number {
  for (let i = 0; i < edges.length; i++) if (Math.abs(edges[i] - value) <= eps) return i;
  // nearest lower edge
  let idx = 0;
  for (let i = 0; i < edges.length; i++) if (edges[i] <= value + eps) idx = i;
  return idx;
}

/**
 * Quantize free-form pixel widgets into a validated grid descriptor. Column boundaries
 * are derived from the distinct widget left/right edges (rows from top/bottom), so each
 * widget maps to a row/col + span by which grid lines it crosses — turning an absolute
 * layout into the engine-correct logical grid. `name` should be a valid identifier.
 */
export function pixelLayoutToGrid(widgets: PixelWidget[], name = 'hud_layout'): UILayoutDescriptor {
  const list = (Array.isArray(widgets) ? widgets : []).filter(w => w && w.w > 0 && w.h > 0);
  if (list.length === 0) return { name, rows: 1, cols: 1, widgets: [] };

  const colEdges = uniqSorted(list.flatMap(w => [w.x, w.x + w.w]));
  const rowEdges = uniqSorted(list.flatMap(w => [w.y, w.y + w.h]));
  const cols = Math.max(1, colEdges.length - 1);
  const rows = Math.max(1, rowEdges.length - 1);

  const seen = new Set<string>();
  const gridWidgets: GridWidget[] = list.map((w, i) => {
    const c0 = trackIndex(colEdges, w.x), c1 = trackIndex(colEdges, w.x + w.w);
    const r0 = trackIndex(rowEdges, w.y), r1 = trackIndex(rowEdges, w.y + w.h);
    const col = c0 + 1, row = r0 + 1;
    const colSpan = Math.max(1, c1 - c0), rowSpan = Math.max(1, r1 - r0);
    let id = (w.id && ID_RE.test(w.id)) ? w.id : `w_${i + 1}`;
    while (seen.has(id)) id = `${id}_`;
    seen.add(id);
    const type = PIXEL_TYPE_MAP[(w.type || '').toLowerCase()] || 'label';
    const gw: GridWidget = { id, type, row, col, rowSpan, colSpan };
    if (w.label) gw.label = w.label;
    const bind = w.properties && (w.properties.binding || w.properties.value);
    if (bind) gw.binding = String(bind);
    return gw;
  });

  return { name: ID_RE.test(name) ? name : 'hud_layout', rows, cols, widgets: gridWidgets };
}

export function runUILayoutSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const clean: UILayoutDescriptor = {
    name: 'hud_panel', rows: 3, cols: 3,
    widgets: [
      { id: 'title', type: 'window', row: 1, col: 1, colSpan: 3, label: 'Status' },
      { id: 'shields', type: 'progressbar', row: 2, col: 1, colSpan: 2, binding: '$shield' },
      { id: 'refresh', type: 'button', row: 2, col: 3, label: 'Refresh' },
      { id: 'log', type: 'chatlog', row: 3, col: 1, colSpan: 3 }
    ]
  };
  ok('clean_validates', validateUILayout(clean).filter(x => x.severity === 'error').length === 0);
  let lua = '', threw = false;
  try { lua = generateLayoutLua(clean, 'mymod'); } catch { threw = true; }
  ok('generates_without_throwing', !threw && lua.length > 0);
  ok('lua_has_grid', lua.includes('grid = { rows = 3, cols = 3 }'));
  ok('lua_has_all_widgets', clean.widgets.every(w => lua.includes(`id = "${w.id}"`)));
  ok('lua_is_data_only', lua.includes('return layout') && !/Helper\.|CreateWidget|widgetSystem\./.test(lua));

  const bad: UILayoutDescriptor = {
    name: 'Bad Name', rows: 2, cols: 2,
    widgets: [
      { id: 'a', type: 'window', row: 1, col: 1, colSpan: 2 },
      { id: 'a', type: 'button', row: 2, col: 1 },
      { id: 'c', type: 'sparkle' as any, row: 2, col: 2 },
      { id: 'd', type: 'label', row: 2, col: 2 },
      { id: 'e', type: 'icon', row: 3, col: 1 }
    ]
  };
  const bf = validateUILayout(bad);
  const has = (code: string) => bf.some(x => x.code === code);
  ok('flags_bad_name', has('bad_name'));
  ok('flags_duplicate_id', has('duplicate_id'));
  ok('flags_invalid_type', has('invalid_type'));
  ok('flags_overlap', has('overlap'));
  ok('flags_out_of_bounds', has('out_of_bounds'));
  let badThrew = false; try { generateLayoutLua(bad, 'x'); } catch { badThrew = true; }
  ok('generator_refuses_broken_layout', badThrew);
  ok('empty_widgets_warns', validateUILayout({ name: 'x', rows: 1, cols: 1, widgets: [] }).some(x => x.code === 'empty_layout'));

  // --- bridge: pixel -> grid ---
  const pix: PixelWidget[] = [
    { id: 'title', type: 'header', x: 0, y: 0, w: 300, h: 30, label: 'Status' },     // full top row, spans both cols
    { id: 'bar', type: 'progressbar', x: 0, y: 30, w: 150, h: 20 },                   // bottom-left (contiguous)
    { id: 'btn', type: 'button', x: 150, y: 30, w: 150, h: 20, label: 'Go' }          // bottom-right (contiguous)
  ];
  const grid = pixelLayoutToGrid(pix, 'hud_from_pixels');
  ok('bridge_clean', validateUILayout(grid).filter(x => x.severity === 'error').length === 0, validateUILayout(grid));
  ok('bridge_derives_cols', grid.cols === 2);
  ok('bridge_derives_rows', grid.rows === 2);
  ok('bridge_title_spans_cols', !!grid.widgets.find(w => w.id === 'title' && w.row === 1 && w.col === 1 && w.colSpan === 2));
  ok('bridge_maps_types', grid.widgets.find(w => w.id === 'title')!.type === 'label' && grid.widgets.find(w => w.id === 'btn')!.type === 'button');
  ok('bridge_no_overlap', !validateUILayout(grid).some(x => x.code === 'overlap'));
  ok('bridge_empty_safe', pixelLayoutToGrid([]).widgets.length === 0);

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * UI widget validation for the existing HUD & LUA UI **Layout GUI Designer**
 * (free-form `uiWidgets` with x/y/w/h pixel positions). This is the genuinely-useful
 * capability brought over from the (now-removed) parallel grid canvas: the free-form
 * designer has no structural validation, so this flags duplicate ids, degenerate sizes,
 * negative positions, out-of-frame placement, and overlaps — without inventing a second
 * widget model. Pure and testable.
 */

export interface ValidatableWidget {
  id: string;
  type?: string;
  x: number;
  y: number;
  w: number;
  h: number;
  label?: string;
  includeInBuild?: boolean;
}

export type UiWidgetSeverity = 'error' | 'warning';
export type UiWidgetCode = 'duplicate_id' | 'bad_id' | 'degenerate_size' | 'negative_position' | 'out_of_frame' | 'overlap';

export interface UiWidgetFinding {
  severity: UiWidgetSeverity;
  code: UiWidgetCode;
  widgetId?: string;
  otherId?: string;
  message: string;
}

function rectsOverlap(a: ValidatableWidget, b: ValidatableWidget): boolean {
  return a.x < b.x + b.w && b.x < a.x + a.w && a.y < b.y + b.h && b.y < a.y + a.h;
}

/**
 * Validate the designer's widgets. `frame` (optional) is the cockpit/module frame size;
 * widgets outside it won't render in-game. Overlaps are warnings (HUD layering can be
 * intentional); duplicate ids / degenerate sizes / negative positions are errors.
 */
export function validateUiWidgets(widgets: ValidatableWidget[], frame?: { w: number; h: number }): UiWidgetFinding[] {
  const list = Array.isArray(widgets) ? widgets : [];
  const findings: UiWidgetFinding[] = [];
  const seen = new Set<string>();

  for (const w of list) {
    if (!w || typeof w !== 'object') continue;
    if (!w.id) findings.push({ severity: 'error', code: 'bad_id', message: 'A widget has no id.' });
    else if (seen.has(w.id)) findings.push({ severity: 'error', code: 'duplicate_id', widgetId: w.id, message: `Duplicate widget id "${w.id}".` });
    else seen.add(w.id);

    if (!(w.w > 0) || !(w.h > 0)) findings.push({ severity: 'error', code: 'degenerate_size', widgetId: w.id, message: `Widget "${w.id}" has a non-positive size (${w.w}×${w.h}).` });
    if (w.x < 0 || w.y < 0) findings.push({ severity: 'error', code: 'negative_position', widgetId: w.id, message: `Widget "${w.id}" has a negative position (${w.x}, ${w.y}).` });
    if (frame && frame.w > 0 && frame.h > 0 && (w.x + (w.w || 0) > frame.w || w.y + (w.h || 0) > frame.h)) {
      findings.push({ severity: 'warning', code: 'out_of_frame', widgetId: w.id, message: `Widget "${w.id}" extends past the frame (${frame.w}×${frame.h}); it may not render in-game.` });
    }
  }

  // pairwise overlap (warning)
  for (let i = 0; i < list.length; i++) {
    for (let j = i + 1; j < list.length; j++) {
      const a = list[i], b = list[j];
      if (!a || !b || !(a.w > 0) || !(a.h > 0) || !(b.w > 0) || !(b.h > 0)) continue;
      if (rectsOverlap(a, b)) findings.push({ severity: 'warning', code: 'overlap', widgetId: a.id, otherId: b.id, message: `Widget "${a.id}" overlaps "${b.id}".` });
    }
  }
  return findings;
}

/** Self-test oracle. */
export function runUiWidgetValidateSelftest() {
  const checks: { name: string; pass: boolean; detail?: any }[] = [];
  const ok = (name: string, pass: boolean, detail?: any) => checks.push({ name, pass, detail });

  const clean: ValidatableWidget[] = [
    { id: 'title', type: 'header', x: 0, y: 0, w: 200, h: 30 },
    { id: 'bar', type: 'progressbar', x: 0, y: 40, w: 200, h: 20 },
    { id: 'btn', type: 'button', x: 0, y: 70, w: 90, h: 24 }
  ];
  ok('clean_no_findings', validateUiWidgets(clean, { w: 300, h: 200 }).length === 0, validateUiWidgets(clean, { w: 300, h: 200 }));

  const dup: ValidatableWidget[] = [{ id: 'x', x: 0, y: 0, w: 10, h: 10 }, { id: 'x', x: 50, y: 50, w: 10, h: 10 }];
  ok('flags_duplicate_id', validateUiWidgets(dup).some(f => f.code === 'duplicate_id'));

  ok('flags_degenerate', validateUiWidgets([{ id: 'a', x: 0, y: 0, w: 0, h: 10 }]).some(f => f.code === 'degenerate_size'));
  ok('flags_negative', validateUiWidgets([{ id: 'a', x: -5, y: 0, w: 10, h: 10 }]).some(f => f.code === 'negative_position'));

  const overlap: ValidatableWidget[] = [{ id: 'a', x: 0, y: 0, w: 100, h: 100 }, { id: 'b', x: 50, y: 50, w: 100, h: 100 }];
  ok('flags_overlap_as_warning', validateUiWidgets(overlap).some(f => f.code === 'overlap' && f.severity === 'warning'));

  ok('flags_out_of_frame', validateUiWidgets([{ id: 'a', x: 280, y: 0, w: 100, h: 20 }], { w: 300, h: 200 }).some(f => f.code === 'out_of_frame'));
  ok('no_out_of_frame_without_frame', !validateUiWidgets([{ id: 'a', x: 9999, y: 0, w: 100, h: 20 }]).some(f => f.code === 'out_of_frame'));
  ok('adjacent_not_overlapping', validateUiWidgets([{ id: 'a', x: 0, y: 0, w: 50, h: 50 }, { id: 'b', x: 50, y: 0, w: 50, h: 50 }]).every(f => f.code !== 'overlap'));
  ok('empty_safe', validateUiWidgets([]).length === 0);

  const passed = checks.filter(c => c.pass).length;
  return { allPassed: passed === checks.length, passed, total: checks.length, checks };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * X4 Foundations packed archive (.cat / .dat) reader.
 *
 * Format (same as X Rebirth):
 *   - A `.cat` file is a UTF-8 manifest. Each non-empty line describes one
 *     packed file as:  `<relative/path> <byteSize> <unixTimestamp> <md5hash>`
 *     The path may itself contain spaces, so the three trailing tokens
 *     (size, timestamp, hash) are parsed from the RIGHT.
 *   - The paired `.dat` file (same basename) is the raw concatenation of every
 *     listed file's bytes, in manifest order, with no separators or headers.
 *     The byte offset of entry N is the sum of all preceding entry sizes.
 *
 * We never read a whole `.dat` into memory — only the exact byte range of the
 * entries we want (via a positioned `fs.readSync`).
 */

import fs from 'fs';
import path from 'path';
import os from 'os';
import zlib from 'zlib';

export interface CatEntry {
  /** forward-slash normalized relative path, e.g. "libraries/wares.xml" */
  name: string;
  size: number;
  offset: number;
}

export interface CatDatArchive {
  catPath: string;
  datPath: string;
  entries: CatEntry[];
}

/** Parse a single `.cat` manifest into entries with computed byte offsets. */
export function parseCat(catPath: string): CatEntry[] {
  const text = fs.readFileSync(catPath, 'utf8');
  const lines = text.split(/\r?\n/);
  const entries: CatEntry[] = [];
  let offset = 0;
  for (const raw of lines) {
    const line = raw.trim();
    if (!line) continue;
    const parts = line.split(' ');
    if (parts.length < 4) continue;
    const size = parseInt(parts[parts.length - 3], 10);
    if (!Number.isFinite(size) || size < 0) continue;
    const name = parts.slice(0, parts.length - 3).join(' ').replace(/\\/g, '/');
    entries.push({ name, size, offset });
    offset += size;
  }
  return entries;
}

/**
 * Enumerate usable `.cat`/`.dat` archive pairs under the given roots.
 * Looks at each root directory itself (base game `01.cat`..`NN.cat`) and one
 * level of `extensions/<id>/` subfolders (DLC `ext_NN.cat`).
 *
 * @param includeSubst include `subst_*.cat` substitution archives (default false).
 */
export function findCatDatArchives(roots: string[], includeSubst = false): CatDatArchive[] {
  const archives: CatDatArchive[] = [];
  const seenCat = new Set<string>();

  const collectFromDir = (dir: string) => {
    let entries: fs.Dirent[];
    try {
      entries = fs.readdirSync(dir, { withFileTypes: true });
    } catch {
      return;
    }
    for (const e of entries) {
      if (!e.isFile()) continue;
      const lower = e.name.toLowerCase();
      if (!lower.endsWith('.cat')) continue;
      if (!includeSubst && lower.startsWith('subst_')) continue;
      const catPath = path.join(dir, e.name);
      const datPath = catPath.slice(0, -4) + '.dat';
      const key = catPath.toLowerCase();
      if (seenCat.has(key)) continue;
      if (!fs.existsSync(datPath)) continue;
      seenCat.add(key);
      archives.push({ catPath, datPath, entries: [] });
    }
  };

  for (const root of roots) {
    if (!root) continue;
    let stat: fs.Stats | undefined;
    try {
      stat = fs.statSync(root);
    } catch {
      continue;
    }
    if (!stat.isDirectory()) continue;
    // Base archives in the root itself.
    collectFromDir(root);
    // One level of extension archives.
    const extRoot = path.join(root, 'extensions');
    try {
      if (fs.existsSync(extRoot) && fs.statSync(extRoot).isDirectory()) {
        for (const ext of fs.readdirSync(extRoot, { withFileTypes: true })) {
          if (ext.isDirectory()) collectFromDir(path.join(extRoot, ext.name));
        }
      }
    } catch {
      /* ignore */
    }
  }

  // Sort so lower-numbered base archives come first, archives are deterministic.
  archives.sort((a, b) => a.catPath.toLowerCase().localeCompare(b.catPath.toLowerCase()));
  return archives;
}

/** Read the raw bytes of one entry from its `.dat` using a positioned read. */
export function readEntryBytes(datPath: string, entry: CatEntry): Buffer {
  const fd = fs.openSync(datPath, 'r');
  try {
    const buf = Buffer.allocUnsafe(entry.size);
    let read = 0;
    while (read < entry.size) {
      const n = fs.readSync(fd, buf, read, entry.size - read, entry.offset + read);
      if (n <= 0) break;
      read += n;
    }
    return read === entry.size ? buf : buf.subarray(0, read);
  } finally {
    fs.closeSync(fd);
  }
}

/**
 * Magic-sniffing decoder for packed entry bytes. X4 stores most entries as
 * plain UTF-8, but `.pck` entries (and some others) are gzip- or zlib-
 * compressed. Defensive by design: the cat/dat format is community-documented,
 * not an Egosoft public contract — on any decompression failure we fall back
 * to returning the raw bytes as UTF-8 rather than throwing.
 */
export function decodeEntryBuffer(buf: Buffer): { text: string; encoding: 'plain' | 'gzip' | 'zlib' } {
  if (buf.length >= 2) {
    if (buf[0] === 0x1f && buf[1] === 0x8b) {
      try { return { text: zlib.gunzipSync(buf).toString('utf8'), encoding: 'gzip' }; } catch { /* fall through to raw */ }
    }
    if (buf[0] === 0x78 && ((buf[0] << 8) + buf[1]) % 31 === 0) {
      try { return { text: zlib.inflateSync(buf).toString('utf8'), encoding: 'zlib' }; } catch { /* fall through to raw */ }
    }
  }
  return { text: buf.toString('utf8'), encoding: 'plain' };
}

/** Read one entry as UTF-8 text, transparently decompressing gzip/zlib (.pck) entries. */
export function readEntryText(datPath: string, entry: CatEntry): string {
  return decodeEntryBuffer(readEntryBytes(datPath, entry)).text;
}

export interface ExtractMatch {
  name: string;
  text: string;
  catPath: string;
}

/**
 * Walk all archives under `roots` and extract the text of every entry whose
 * normalized name satisfies `wanted(name)`. Later archives (DLC/patches) take
 * precedence for an identical path, mirroring X4's override order.
 *
 * @param maxBytesPerEntry skip entries larger than this (default 48 MB).
 */
export function extractEntries(
  roots: string[],
  wanted: (name: string) => boolean,
  options: { maxBytesPerEntry?: number; includeSubst?: boolean; dedupeByName?: boolean } = {}
): { matches: ExtractMatch[]; archiveCount: number; entryCount: number } {
  const maxBytes = options.maxBytesPerEntry ?? 48 * 1024 * 1024;
  // Default true: one result per path (last archive wins) — correct for fetching
  // a single base file. Pass false to accumulate EVERY archive's copy, which is
  // required for additive catalogs (each DLC ships its own index/macros.xml and
  // libraries/factions.xml containing only that DLC's additions).
  const dedupe = options.dedupeByName !== false;
  const archives = findCatDatArchives(roots, options.includeSubst);
  const byName = new Map<string, ExtractMatch>();
  const all: ExtractMatch[] = [];
  let entryCount = 0;

  for (const archive of archives) {
    let entries: CatEntry[];
    try {
      entries = parseCat(archive.catPath);
    } catch {
      continue;
    }
    for (const entry of entries) {
      entryCount++;
      if (entry.size <= 0 || entry.size > maxBytes) continue;
      const lname = entry.name.toLowerCase();
      if (!wanted(lname)) continue;
      try {
        const text = readEntryText(archive.datPath, entry);
        const match = { name: entry.name, text, catPath: archive.catPath };
        if (dedupe) {
          byName.set(lname, match); // archives are sorted ascending; later wins
        } else {
          all.push(match);
        }
      } catch {
        /* unreadable entry — skip */
      }
    }
  }

  return { matches: dedupe ? [...byName.values()] : all, archiveCount: archives.length, entryCount };
}

/**
 * Diagnostic helper: enumerate archives under the given roots and, for each,
 * report entry count, whether the key catalog/library files are present, and a
 * small sample of entry names. Used to debug why an install indexes few rows.
 */
export function debugScan(roots: string[], includeSubst = false) {
  const archives = findCatDatArchives(roots, includeSubst);
  const wantedNames = ['index/macros.xml', 'index/components.xml', 'libraries/factions.xml', 'libraries/wares.xml', 'libraries/jobs.xml'];
  const report = archives.map(a => {
    let entries: CatEntry[] = [];
    let parseError: string | null = null;
    try {
      entries = parseCat(a.catPath);
    } catch (e: any) {
      parseError = String(e?.message || e);
    }
    const names = entries.map(e => e.name.toLowerCase());
    const found: Record<string, boolean> = {};
    for (const w of wantedNames) found[w] = names.includes(w);
    return {
      catPath: a.catPath,
      datExists: fs.existsSync(a.datPath),
      entryCount: entries.length,
      parseError,
      found,
      sampleNames: entries.slice(0, 6).map(e => e.name),
      firstLineRaw: (() => { try { return fs.readFileSync(a.catPath, 'utf8').split(/\r?\n/)[0].slice(0, 160); } catch { return null; } })()
    };
  });
  return { roots, archiveCount: archives.length, archives: report };
}

/**
 * Locate and extract a single game file by its relative path (case-insensitive),
 * e.g. "libraries/wares.xml". Returns the merged/overridden content (last
 * archive wins) or null if not found in any archive.
 */
/**
 * Candidate packed names for a requested path: X4 ships some files as
 * compressed `.pck` siblings of their logical name (e.g. `t/0001.xml` may be
 * stored as `t/0001.pck`). The exact name always wins over an alias.
 */
function pckAliases(target: string): Set<string> {
  const out = new Set<string>([target]);
  out.add(target + '.pck');
  if (/\.(xml|lua)$/.test(target)) out.add(target.replace(/\.(xml|lua)$/, '.pck'));
  return out;
}

export function extractGameFile(roots: string[], relativePath: string): ExtractMatch | null {
  const target = relativePath.replace(/\\/g, '/').toLowerCase().replace(/^\/+/, '');
  const candidates = pckAliases(target);
  const result = extractEntries(roots, name => candidates.has(name), { includeSubst: true });
  const exact = result.matches.find(m => m.name.toLowerCase() === target);
  return exact || result.matches[0] || null;
}

/**
 * Extract a single file from the BASE-GAME archives only — i.e. `.cat`/`.dat`
 * pairs that live directly in the game root, ignoring `extensions/<dlc>/`
 * archives whose copies are additive/partial. This yields the canonical full
 * base file (e.g. the complete `libraries/wares.xml`) that XML `<diff>` patches
 * are authored against. Returns the highest-numbered base archive's copy
 * (later base archives patch earlier ones) or null.
 */
export function extractBaseGameFile(gameRoot: string, relativePath: string): ExtractMatch | null {
  if (!gameRoot) return null;
  const target = relativePath.replace(/\\/g, '/').toLowerCase().replace(/^\/+/, '');
  const candidates = pckAliases(target);
  let stat: fs.Stats | undefined;
  try {
    stat = fs.statSync(gameRoot);
  } catch {
    return null;
  }
  if (!stat.isDirectory()) return null;

  let entriesDir: fs.Dirent[];
  try {
    entriesDir = fs.readdirSync(gameRoot, { withFileTypes: true });
  } catch {
    return null;
  }
  // Root-level .cat files only, sorted ascending so the last (highest patch) wins.
  const cats = entriesDir
    .filter(e => e.isFile() && e.name.toLowerCase().endsWith('.cat') && !e.name.toLowerCase().startsWith('subst_'))
    .map(e => e.name)
    .sort((a, b) => a.toLowerCase().localeCompare(b.toLowerCase()));

  let found: ExtractMatch | null = null;
  for (const catName of cats) {
    const catPath = path.join(gameRoot, catName);
    const datPath = catPath.slice(0, -4) + '.dat';
    if (!fs.existsSync(datPath)) continue;
    let entries: CatEntry[];
    try {
      entries = parseCat(catPath);
    } catch {
      continue;
    }
    for (const entry of entries) {
      if (!candidates.has(entry.name.toLowerCase())) continue;
      try {
        found = { name: entry.name, text: readEntryText(datPath, entry), catPath };
      } catch {
        /* skip */
      }
    }
  }
  return found;
}

// ---------------------------------------------------------------------------
// T4.1 Inc 0 — spike oracle: prove the cat parse → positioned dat read →
// decompress round-trip against a SYNTHETIC fixture built in os.tmpdir()
// (never a shipped game file). Covers: right-tokenized paths with spaces,
// malformed manifest lines, cumulative offsets, plain/gzip/zlib entries,
// truncated-compressed graceful fallback, cat-without-dat discovery, archive
// override order, and .pck alias resolution.
// ---------------------------------------------------------------------------

export interface CatDatSelftestCheck { name: string; pass: boolean; detail?: string }

export function runCatDatSelftest(): { pass: boolean; checks: CatDatSelftestCheck[] } {
  const checks: CatDatSelftestCheck[] = [];
  const ok = (name: string, pass: boolean, detail?: string) => checks.push({ name, pass, detail });
  const tmp = fs.mkdtempSync(path.join(os.tmpdir(), 'x4catdat-selftest-'));
  try {
    const plainV1 = '<wares note="v1"><ware id="a"/></wares>';
    const plainV2 = '<wares note="v2"><ware id="a"/><ware id="b"/></wares>';
    const mdText = '<mdscript name="Packed"><cues><cue name="C1"/></cues></mdscript>';
    const tText = '<language id="44"><t id="1">Hello</t></language>';
    const spacesText = '<doc kind="spaces in path"/>';

    const gz = zlib.gzipSync(Buffer.from(mdText, 'utf8'));
    const zl = zlib.deflateSync(Buffer.from(tText, 'utf8'));
    const corrupt = zlib.gzipSync(Buffer.from('boom', 'utf8')).subarray(0, 8); // truncated gzip

    // 01.cat/.dat — plain v1 + gzip + zlib(.pck) + spaces path + corrupt, then a malformed line.
    const parts1 = [
      { name: 'libraries/plain.xml', data: Buffer.from(plainV1, 'utf8') },
      { name: 'md/packed.xml', data: gz },
      { name: 't/0001.pck', data: zl },
      { name: 'path with spaces/file.xml', data: Buffer.from(spacesText, 'utf8') },
      { name: 'broken/corrupt.xml', data: corrupt }
    ];
    let catLines = '';
    for (const p of parts1) catLines += p.name + ' ' + p.data.length + ' 1700000000 ' + '0'.repeat(32) + '\n';
    catLines += 'malformed line\n';
    fs.writeFileSync(path.join(tmp, '01.cat'), catLines);
    fs.writeFileSync(path.join(tmp, '01.dat'), Buffer.concat(parts1.map(p => p.data)));

    // 02.cat/.dat — overrides libraries/plain.xml (later archive must win).
    const d2 = Buffer.from(plainV2, 'utf8');
    fs.writeFileSync(path.join(tmp, '02.cat'), 'libraries/plain.xml ' + d2.length + ' 1700000001 ' + '1'.repeat(32) + '\n');
    fs.writeFileSync(path.join(tmp, '02.dat'), d2);

    // 03.cat with no paired .dat — discovery must ignore it.
    fs.writeFileSync(path.join(tmp, '03.cat'), 'ghost/file.xml 4 1700000002 ' + '2'.repeat(32) + '\n');

    const entries = parseCat(path.join(tmp, '01.cat'));
    ok('parseCat: 5 entries, malformed line skipped', entries.length === 5, 'got ' + entries.length);
    const offsetsOk = entries.length === 5 && entries.every((e, i) =>
      e.size === parts1[i].data.length &&
      e.offset === parts1.slice(0, i).reduce((s, p) => s + p.data.length, 0));
    ok('parseCat: cumulative offsets and sizes correct', offsetsOk);
    ok('parseCat: spaces-in-path name tokenized from the right',
      entries.length === 5 && entries[3].name === 'path with spaces/file.xml', entries[3] && entries[3].name);

    const datPath = path.join(tmp, '01.dat');
    ok('positioned read: plain entry byte-identical', readEntryBytes(datPath, entries[0]).equals(parts1[0].data));

    const dPlain = decodeEntryBuffer(readEntryBytes(datPath, entries[0]));
    ok('decode: plain entry stays plain', dPlain.encoding === 'plain' && dPlain.text === plainV1, dPlain.encoding);
    const dGz = decodeEntryBuffer(readEntryBytes(datPath, entries[1]));
    ok('decode: gzip entry round-trips to original XML', dGz.encoding === 'gzip' && dGz.text === mdText, dGz.encoding);
    const dZl = decodeEntryBuffer(readEntryBytes(datPath, entries[2]));
    ok('decode: zlib .pck entry round-trips to original XML', dZl.encoding === 'zlib' && dZl.text === tText, dZl.encoding);
    const dBad = decodeEntryBuffer(readEntryBytes(datPath, entries[4]));
    ok('decode: truncated gzip degrades to raw bytes without throwing', dBad.encoding === 'plain');

    const arcs = findCatDatArchives([tmp]);
    ok('discovery: cat without dat ignored (2 archives found)', arcs.length === 2, 'got ' + arcs.length);

    const over = extractGameFile([tmp], 'libraries/plain.xml');
    ok('override order: later archive wins for a shared path',
      !!over && over.text === plainV2 && /02\.cat$/i.test(over.catPath), over ? over.catPath : 'no match');

    const viaAlias = extractGameFile([tmp], 't/0001.xml');
    ok('pck alias: t/0001.xml resolves to stored t/0001.pck, decompressed',
      !!viaAlias && viaAlias.name === 't/0001.pck' && viaAlias.text === tText, viaAlias ? viaAlias.name : 'no match');

    const baseHit = extractBaseGameFile(tmp, 'md/packed.xml');
    ok('extractBaseGameFile: gzip md entry decompressed from root archives',
      !!baseHit && baseHit.text === mdText);
  } catch (e: any) {
    ok('selftest harness error: ' + String((e && e.message) || e), false);
  } finally {
    try { fs.rmSync(tmp, { recursive: true, force: true }); } catch { /* ignore */ }
  }
  return { pass: checks.every(c => c.pass), checks };
}

