import { DOMParser as XmlDomParser, XMLSerializer as XmlDomSerializer } from '@xmldom/xmldom';
import { ModWorkspace, MDNode, MDLink, NODE_TEMPLATES, X4_SHIP_MACROS, X4_STATION_MACROS } from '../types';
import { isContainerTag } from './portSemantics';

const DOMParserToUse = typeof window !== 'undefined' && window.DOMParser ? window.DOMParser : XmlDomParser;
const XMLSerializerToUse = typeof window !== 'undefined' && window.XMLSerializer ? window.XMLSerializer : XmlDomSerializer;

let schemaTemplatesByTag = new Map<string, Omit<MDNode, 'id' | 'x' | 'y'>>();

export function setSchemaTemplatesForImport(templates: Omit<MDNode, 'id' | 'x' | 'y'>[]) {
  schemaTemplatesByTag = new Map((templates || []).map(template => [template.xmlTag, template]));
}

function attributesToProperties(element: Element): Record<string, any> {
  return Array.from(element.attributes).reduce<Record<string, any>>((props, attr) => {
    props[attr.name] = attr.value;
    return props;
  }, {});
}

function stripMacroPrefix(value: string): string {
  return String(value || '').replace(/^macro\./, '');
}

function stripFactionPrefix(value: string): string {
  return String(value || '').replace(/^faction\./, '');
}

function matchOption(options: string[], value: string): string {
  const clean = stripMacroPrefix(value);
  return options.find(option => option.startsWith(clean)) || clean || value;
}

function parseCheckValueProperties(element: Element): Record<string, any> {
  const value = element.getAttribute("value") || 'player.money';
  const exact = element.getAttribute("exact");
  const min = element.getAttribute("min");
  const max = element.getAttribute("max");
  const list = element.getAttribute("list");

  if (exact !== null) return { value, comparison: 'exact', amount: Number(exact) || exact };
  if (min !== null) return { value, comparison: 'min', amount: Number(min) || min };
  if (max !== null) return { value, comparison: 'max', amount: Number(max) || max };
  if (list !== null) return { value, comparison: 'list', list };

  const oldOperator = element.getAttribute("operator");
  const oldValue2 = element.getAttribute("value2");
  if (oldOperator || oldValue2) {
    const comparison = oldOperator === 'le' || oldOperator === 'lt'
      ? 'max'
      : oldOperator === 'eq' || oldOperator === 'exact'
        ? 'exact'
        : 'min';
    return { value, comparison, amount: Number(oldValue2) || oldValue2 || 1000000 };
  }

  return { value, comparison: 'expression' };
}

// Parser: Egosoft XML script mapping to visual flowchart nodegraph
export function parseXMLToWorkspace(xmlText: string): ModWorkspace | null {
  try {
    const parser = new DOMParserToUse();
    const xmlDoc = parser.parseFromString(xmlText, "text/xml") as unknown as Document;
    
    const parserError = xmlDoc.getElementsByTagName("parsererror");
    if (parserError.length > 0) {
      throw new Error("Malformatted XML script syntax.");
    }

    const mdscript = xmlDoc.getElementsByTagName("mdscript")[0];
    if (!mdscript) {
      throw new Error("Missing main root <mdscript> node.");
    }

    const modName = mdscript.getAttribute("name") || "Parsed_X4_Mod";
    const cuesList = xmlDoc.getElementsByTagName("cue");
    
    const nodes: MDNode[] = [];
    const links: MDLink[] = [];
    
    const elementToId = new Map<Element, string>();
    const cueDepth = new Map<Element, number>();
    const depthCounts = new Map<number, number>();
    
    function getDepth(el: Element): number {
      if (cueDepth.has(el)) return cueDepth.get(el)!;
      let depth = 0;
      let parent = el.parentElement;
      while (parent) {
        if (parent.tagName === "cue") {
          depth += 1;
        }
        parent = parent.parentElement;
      }
      cueDepth.set(el, depth);
      return depth;
    }

    const serializer = new XMLSerializerToUse();

    // Pass 1: Parse all cues
    for (let i = 0; i < cuesList.length; i++) {
      const cue = cuesList[i];
      const name = cue.getAttribute("name") || `cue_${i}`;
      const instantiate = cue.getAttribute("instantiate") || "false";
      const namespace = cue.getAttribute("namespace") || "this";
      
      const cueId = `cue_${Date.now()}_${i}`;
      elementToId.set(cue, cueId);
      
      const depth = getDepth(cue);
      const count = depthCounts.get(depth) || 0;
      depthCounts.set(depth, count + 1);
      
      // Separate Cues widely to prevent overlap (since we have flowchart nodes inside)
      const x = 100 + depth * 1500;
      const y = 80 + count * 450;

      const cueNode: MDNode = {
        id: cueId,
        type: 'cue',
        label: cue.getAttribute("name") ? `Cue: ${cue.getAttribute("name")}` : 'Mission Cue',
        xmlTag: 'cue',
        x,
        y,
        properties: { name, instantiate, namespace },
        propertiesSchema: NODE_TEMPLATES[0].propertiesSchema,
        inputs: NODE_TEMPLATES[0].inputs,
        outputs: NODE_TEMPLATES[0].outputs
      };
      
      nodes.push(cueNode);
    }
    
    // Pass 2: Reconstruct parent-child cue links (out_sub ➔ in_flow)
    for (let i = 0; i < cuesList.length; i++) {
      const cue = cuesList[i];
      const cueId = elementToId.get(cue);
      if (!cueId) continue;
      
      const parentCuesBlock = cue.parentElement;
      if (parentCuesBlock && parentCuesBlock.tagName === "cues") {
        const parentCueElement = parentCuesBlock.parentElement;
        if (parentCueElement && parentCueElement.tagName === "cue") {
          const parentCueId = elementToId.get(parentCueElement);
          if (parentCueId) {
            links.push({
              id: `link_sub_${Date.now()}_${parentCueId}_${cueId}`,
              sourceNodeId: parentCueId,
              sourcePortId: 'out_sub',
              targetNodeId: cueId,
              targetPortId: 'in_flow'
            });
          }
        }
      }
    }

    // Pass 3: Parse conditions and actions for each cue
    for (let i = 0; i < cuesList.length; i++) {
      const cue = cuesList[i];
      const cueId = elementToId.get(cue);
      if (!cueId) continue;
      const cueNode = nodes.find(n => n.id === cueId)!;

      // Parse conditions
      const conditionsElement = Array.from(cue.children).find(c => c.tagName === "conditions");
      if (conditionsElement) {
        const conditionChildren = Array.from(conditionsElement.children);
        let condIndex = 0;
        conditionChildren.forEach(child => {
          const tag = child.tagName;
          let nodeType: MDNode['type'] = 'condition';
          let xmlTag = tag;
          let label = tag;
          let properties: Record<string, any> = {};

          if (tag === 'event_cue_signalled') {
            nodeType = 'event';
            label = 'Event: Game Started';
            properties = { cue: child.getAttribute("cue") || 'md.Setup.Start' };
          } else if (tag === 'event_object_destroyed') {
            nodeType = 'event';
            label = 'Event: Object Destroyed';
            const ownerCheck = (child.getAttribute("faction") || 'any').replace('faction.', '');
            properties = { object: child.getAttribute("object") || 'player.target', ownerCheck };
          } else if (tag === 'event_object_changed_sector') {
            nodeType = 'event';
            label = 'Event: Sector Entered';
            properties = { object: child.getAttribute("object") || 'playership', sector: child.getAttribute("sector") || 'player.sector' };
          } else if (tag === 'check_value') {
            nodeType = 'condition';
            label = 'Check: Player Wealth';
            properties = parseCheckValueProperties(child);
          } else {
            // Unrecognized / escape hatch
            const schemaTemplate = schemaTemplatesByTag.get(tag);
            if (schemaTemplate) {
              nodeType = schemaTemplate.type;
              xmlTag = schemaTemplate.xmlTag;
              label = schemaTemplate.label;
              properties = attributesToProperties(child);
            } else {
              if (tag.startsWith('event_')) {
                nodeType = 'event';
                xmlTag = 'custom_event';
                label = 'Custom XML Event';
              } else {
                nodeType = 'condition';
                xmlTag = 'custom_condition';
                label = 'Custom XML Condition';
              }
              properties = { rawXml: serializer.serializeToString(child as any) };
            }
          }

          const template = NODE_TEMPLATES.find(t => t.xmlTag === xmlTag) || schemaTemplatesByTag.get(xmlTag);
          if (template) {
            const condNodeId = `${xmlTag}_${Date.now()}_${i}_${condIndex}`;
            const condNode: MDNode = {
              id: condNodeId,
              type: nodeType,
              label,
              xmlTag,
              x: cueNode.x + 300,
              y: cueNode.y + condIndex * 150,
              properties,
              propertiesSchema: template.propertiesSchema,
              inputs: template.inputs,
              outputs: template.outputs
            };
            nodes.push(condNode);

            // Connect Cue -> Condition
            links.push({
              id: `link_cond_${Date.now()}_${cueId}_${condNodeId}`,
              sourceNodeId: cueId,
              sourcePortId: 'out_cond',
              targetNodeId: condNodeId,
              targetPortId: 'in_cond'
            });

            condIndex++;
          }
        });
      }

      // Parse actions
      const actionsElement = Array.from(cue.children).find(c => c.tagName === "actions");
      if (actionsElement) {
        const actionChildren = Array.from(actionsElement.children);
        let actIndex = 0;

        // Build a single action node from an <actions> child element (returns null if untemplated).
        const buildActionNode = (child: any): MDNode | null => {
          const tag = child.tagName;
          let xmlTag = tag;
          let label = tag;
          let properties: Record<string, any> = {};

          if (tag === 'create_ship') {
            label = 'Spawn Ship';
            const name = child.getAttribute("name") || '$EscortShip';
            const ownerEl = child.getElementsByTagName("owner")[0];
            const faction = stripFactionPrefix(ownerEl?.getAttribute("exact") || child.getAttribute("faction") || 'player');
            const macroVal = child.getAttribute("macro") || '';
            const matchingMacro = matchOption(X4_SHIP_MACROS, macroVal);
            const spaceObj = child.getAttribute("sector") || child.getAttribute("zone") || child.getElementsByTagName("space")[0]?.getAttribute("object") || 'player.sector';
            const posEl = child.getElementsByTagName("position")[0];
            const coords = posEl ? `${posEl.getAttribute("x") || 0},${posEl.getAttribute("y") || 0},${posEl.getAttribute("z") || 0}` : '0,0,1000';
            properties = { name, macro: matchingMacro, faction, sector: spaceObj, coords };
          } else if (tag === 'reward_player') {
            label = 'Reward Player';
            const money = Number(child.getAttribute("money")) || 0;
            properties = { money };
          } else if (tag === 'play_sound') {
            label = 'Play Audio/Sound';
            properties = {
              object: child.getAttribute("object") || 'playership',
              sound: child.getAttribute("sound") || 'notification_generic'
            };
          } else if (tag === 'show_help') {
            label = 'Show Briefing';
            const rawText = child.getAttribute("custom") || child.getAttribute("text") || '';
            const text = rawText.replace(/^'|'$/g, '');
            properties = { custom: text, duration: Number(child.getAttribute("duration")) || 5 };
          } else if (tag === 'create_station') {
            label = 'Spawn Station';
            const name = child.getAttribute("name") || '$MyDefenseStation';
            const faction = stripFactionPrefix(child.getAttribute("owner") || child.getAttribute("faction") || 'player');
            const macroVal = child.getAttribute("macro") || '';
            const matchingMacro = matchOption(X4_STATION_MACROS, macroVal);
            const spaceObj = child.getAttribute("sector") || child.getAttribute("zone") || child.getElementsByTagName("space")[0]?.getAttribute("sector") || 'player.sector';
            const posEl = child.getElementsByTagName("position")[0];
            const coords = posEl ? `${posEl.getAttribute("x") || 0},${posEl.getAttribute("y") || 0},${posEl.getAttribute("z") || 0}` : '5000,0,5000';
            properties = { name, macro: matchingMacro, faction, sector: spaceObj, coords };
          } else if (isContainerTag(tag)) {
            // control-flow container (do_if/do_while/…): keep its own attributes (e.g. value);
            // its body is parsed separately into out_body by the recursive walker below.
            const t = NODE_TEMPLATES.find(n => n.xmlTag === tag);
            label = t ? t.label : tag;
            properties = attributesToProperties(child);
          } else {
            // Unrecognized / escape hatch
            const schemaTemplate = schemaTemplatesByTag.get(tag);
            if (schemaTemplate) {
              xmlTag = schemaTemplate.xmlTag;
              label = schemaTemplate.label;
              properties = attributesToProperties(child);
            } else {
              xmlTag = 'custom_xml';
              label = 'Custom XML Action';
              properties = { rawXml: serializer.serializeToString(child as any) };
            }
          }

          const template = NODE_TEMPLATES.find(t => t.xmlTag === xmlTag) || schemaTemplatesByTag.get(xmlTag);
          if (!template) return null;
          const actNodeId = `${xmlTag}_${Date.now()}_${i}_${actIndex}`;
          actIndex++;
          const actNode: MDNode = {
            id: actNodeId,
            type: 'action',
            label,
            xmlTag,
            x: cueNode.x + 600 + actIndex * 300,
            y: cueNode.y,
            properties,
            propertiesSchema: template.propertiesSchema,
            inputs: template.inputs,
            outputs: template.outputs
          };
          nodes.push(actNode);
          return actNode;
        };

        // Recursive walk: chain siblings via out_next (first via parentPort). A control-flow
        // container recurses its element children into out_body, so nested do_if/do_while
        // round-trips losslessly instead of dropping its body (gap G3).
        const walkActions = (children: any[], parentId: string, parentPort: string) => {
          let prevId = parentId, prevPort = parentPort;
          for (const child of children) {
            const node = buildActionNode(child);
            if (!node) continue;
            links.push({
              id: `link_act_${Date.now()}_${prevId}_${node.id}`,
              sourceNodeId: prevId,
              sourcePortId: prevPort,
              targetNodeId: node.id,
              targetPortId: 'in_act'
            });
            if (isContainerTag(node.xmlTag)) {
              walkActions(Array.from(child.children || []), node.id, 'out_body');
            }
            prevId = node.id;
            prevPort = 'out_next';
          }
        };
        walkActions(actionChildren, cueId, 'out_act');
      }
    }
    
    return {
      id: `workspace_${Date.now()}`,
      name: modName,
      version: mdscript.getAttribute("version") || "1.0.0",
      author: mdscript.getAttribute("author") || "ImportedAuthor",
      description: mdscript.getAttribute("description") || `Imported and visually reconstructed with ${nodes.length} cue nodes.`,
      nodes,
      links,
      uiWidgets: [],
      uiTheme: {
        backgroundColor: "#0F1115",
        borderColor: "#06b6d4",
        accentColor: "#0891b2",
        opacity: 0.95,
        showIcons: true
      }
    };
  } catch (err: any) {
    console.warn("XML Import Parsing Error: ", err);
    return null;
  }
}

// xpathSynth.ts — T4.2 Diff-to-Patch engine (Inc 1).
//
// EXTENDS the existing XML Patching domain: this is the synthesis front-end
// for the patches the studio already models/compiles (PatchBlock → <diff>
// documents in modCompiler) — NOT a new patch engine. Given a vanilla file and
// an edited copy, it computes the MINIMAL standard-compliant X4 <diff> ops
// (add / replace / remove at element AND attribute granularity), preferring
// stable id/name selectors over positional [n] indices so patches survive
// vanilla reshuffles (positional fallbacks are surfaced as warnings).
//
// Honesty contract: every generated patch must RE-APPLY cleanly — applyPatch()
// is part of this module precisely so the selftest can prove
// applyPatch(vanilla, synthesizePatch(vanilla, edited)) ≡ edited (structural
// equality, ignoring attribute order and insignificant whitespace).
//
// House pattern: pure engine + runXpathSynthSelftest() + endpoints in
// server.ts (public selftest GET, authed synth POST), THEN UI.

import * as xpathLib from 'xpath';
import { DOMParser, XMLSerializer } from '@xmldom/xmldom';

export interface PatchOp {
  type: 'add' | 'replace' | 'remove';
  /** XPath selector (anchor node for add with pos, target node otherwise). */
  sel: string;
  /** For add: 'child' (append into sel) or 'before' (insert before sel). */
  pos?: 'child' | 'before';
  /** For attribute adds: the attribute name as '@name'. */
  attrType?: string;
  /** Serialized element fragment (add/replace of elements) or attr/text value. */
  content?: string;
}

export interface SynthesizedPatch {
  ops: PatchOp[];
  /** The complete <diff> document for the ops. */
  diffXml: string;
  /** Honest degradations: positional selectors, whole-element replaces, etc. */
  warnings: string[];
}

const serializer = new XMLSerializer();

function parseDoc(xml: string): any {
  let fatal: string | null = null;
  const doc = new DOMParser({
    onError: (level: string, msg: string) => { if (level === 'fatalError') fatal = msg; }
  }).parseFromString(xml, 'text/xml');
  if (fatal || !doc || !doc.documentElement) {
    throw new Error('XML parse failed: ' + (fatal || 'no document element'));
  }
  return doc;
}

function isElement(n: any): boolean { return !!n && n.nodeType === 1; }
function isText(n: any): boolean { return !!n && (n.nodeType === 3 || n.nodeType === 4); }

function elementChildren(el: any): any[] {
  const out: any[] = [];
  for (let i = 0; i < el.childNodes.length; i++) {
    if (isElement(el.childNodes[i])) out.push(el.childNodes[i]);
  }
  return out;
}

function directText(el: any): string {
  let t = '';
  for (let i = 0; i < el.childNodes.length; i++) {
    if (isText(el.childNodes[i])) t += String(el.childNodes[i].data || '');
  }
  return t.trim();
}

function attrMap(el: any): Map<string, string> {
  const m = new Map<string, string>();
  if (el.attributes) {
    for (let i = 0; i < el.attributes.length; i++) {
      const a = el.attributes[i];
      m.set(String(a.name), String(a.value));
    }
  }
  return m;
}

/** Identity key for sibling matching: tag name + @id/@name when present. */
function elKey(el: any): string {
  const id = el.getAttribute && (el.getAttribute('id') || el.getAttribute('name'));
  return id ? el.nodeName + '#' + id : el.nodeName;
}

function escapeXPathLiteral(v: string): string {
  if (!v.includes("'")) return "'" + v + "'";
  if (!v.includes('"')) return '"' + v + '"';
  // contains both quote kinds — concat() form
  return "concat('" + v.split("'").join("',\"'\",'") + "')";
}

/**
 * Build a stable selector for an element: absolute path preferring [@id]/
 * [@name] predicates; positional [n] only when an element has no identity
 * among same-named siblings (recorded in `warnings`).
 */
export function selectorFor(el: any, warnings?: string[]): string {
  const parts: string[] = [];
  let cur: any = el;
  let hops = 0;
  while (cur && isElement(cur) && hops < 64) {
    const name = cur.nodeName;
    const id = cur.getAttribute && (cur.getAttribute('id') || cur.getAttribute('name'));
    if (id) {
      const attr = cur.getAttribute('id') ? 'id' : 'name';
      parts.unshift(name + '[@' + attr + '=' + escapeXPathLiteral(id) + ']');
    } else {
      const parent = cur.parentNode;
      let idx = 1, count = 0;
      if (parent && parent.childNodes) {
        for (let i = 0; i < parent.childNodes.length; i++) {
          const sib = parent.childNodes[i];
          if (isElement(sib) && sib.nodeName === name) {
            count++;
            if (sib === cur) idx = count;
          }
        }
      }
      if (count > 1) {
        parts.unshift(name + '[' + idx + ']');
        if (warnings) {
          warnings.push('positional selector ' + name + '[' + idx + '] — no id/name attribute; this op may break if vanilla reorders siblings');
        }
      } else {
        parts.unshift(name);
      }
    }
    cur = cur.parentNode;
    hops++;
  }
  return '/' + parts.join('/');
}

function serializeEl(el: any): string {
  return String(serializer.serializeToString(el));
}

/** Recursive diff of two matched elements; emits minimal ops. */
function diffElements(vanEl: any, edEl: any, ops: PatchOp[], warnings: string[]): void {
  const vanChildren = elementChildren(vanEl);
  const edChildren = elementChildren(edEl);

  // Leaf text change → replace the whole element (smallest standard op that
  // captures text content). Only when neither side has element children.
  if (vanChildren.length === 0 && edChildren.length === 0) {
    if (directText(vanEl) !== directText(edEl)) {
      ops.push({ type: 'replace', sel: selectorFor(vanEl, warnings), content: serializeEl(edEl) });
      return; // the replace covers attributes too
    }
  }

  // Attribute diffs.
  const vAttrs = attrMap(vanEl);
  const eAttrs = attrMap(edEl);
  for (const [name, val] of eAttrs) {
    if (!vAttrs.has(name)) {
      ops.push({ type: 'add', sel: selectorFor(vanEl, warnings), attrType: '@' + name, content: val });
    } else if (vAttrs.get(name) !== val) {
      ops.push({ type: 'replace', sel: selectorFor(vanEl, warnings) + '/@' + name, content: val });
    }
  }
  for (const name of vAttrs.keys()) {
    if (!eAttrs.has(name)) {
      ops.push({ type: 'remove', sel: selectorFor(vanEl, warnings) + '/@' + name });
    }
  }

  // Child element matching by identity key (first unconsumed same-key wins).
  const consumed = new Set<number>();
  const matchedPairs: { van: any; ed: any }[] = [];
  const edMatched: (any | null)[] = edChildren.map(() => null);

  for (let e = 0; e < edChildren.length; e++) {
    const key = elKey(edChildren[e]);
    for (let v = 0; v < vanChildren.length; v++) {
      if (consumed.has(v)) continue;
      if (elKey(vanChildren[v]) === key) {
        consumed.add(v);
        matchedPairs.push({ van: vanChildren[v], ed: edChildren[e] });
        edMatched[e] = vanChildren[v];
        break;
      }
    }
  }

  // Removals: vanilla children never matched.
  for (let v = 0; v < vanChildren.length; v++) {
    if (!consumed.has(v)) {
      ops.push({ type: 'remove', sel: selectorFor(vanChildren[v], warnings) });
    }
  }

  // Additions: edited children with no vanilla counterpart. Anchor ordering:
  // insert before the next MATCHED edited sibling's vanilla node; else append.
  for (let e = 0; e < edChildren.length; e++) {
    if (edMatched[e]) continue;
    let anchorVan: any = null;
    for (let k = e + 1; k < edChildren.length; k++) {
      if (edMatched[k]) { anchorVan = edMatched[k]; break; }
    }
    if (anchorVan) {
      ops.push({ type: 'add', sel: selectorFor(anchorVan, warnings), pos: 'before', content: serializeEl(edChildren[e]) });
    } else {
      ops.push({ type: 'add', sel: selectorFor(vanEl, warnings), pos: 'child', content: serializeEl(edChildren[e]) });
    }
  }

  // Recurse into matches.
  for (const pair of matchedPairs) diffElements(pair.van, pair.ed, ops, warnings);
}

function xmlEscapeText(v: string): string {
  return v.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function xmlEscapeAttr(v: string): string {
  return xmlEscapeText(v).replace(/"/g, '&quot;');
}

/** Render ops as a standard X4 <diff> document. */
export function buildDiffXml(ops: PatchOp[]): string {
  const lines: string[] = ['<?xml version="1.0" encoding="utf-8"?>', '<diff>'];
  for (const op of ops) {
    if (op.type === 'remove') {
      lines.push('  <remove sel="' + xmlEscapeAttr(op.sel) + '" />');
    } else if (op.type === 'replace') {
      if (op.sel.includes('/@')) {
        lines.push('  <replace sel="' + xmlEscapeAttr(op.sel) + '">' + xmlEscapeText(op.content || '') + '</replace>');
      } else {
        lines.push('  <replace sel="' + xmlEscapeAttr(op.sel) + '">' + (op.content || '') + '</replace>');
      }
    } else {
      if (op.attrType) {
        lines.push('  <add sel="' + xmlEscapeAttr(op.sel) + '" type="' + xmlEscapeAttr(op.attrType) + '">' + xmlEscapeText(op.content || '') + '</add>');
      } else if (op.pos === 'before') {
        lines.push('  <add sel="' + xmlEscapeAttr(op.sel) + '" pos="before">' + (op.content || '') + '</add>');
      } else {
        lines.push('  <add sel="' + xmlEscapeAttr(op.sel) + '">' + (op.content || '') + '</add>');
      }
    }
  }
  lines.push('</diff>');
  return lines.join('\n');
}

/**
 * Synthesize the minimal <diff> turning `vanillaXml` into `editedXml`.
 * Throws on unparseable input or mismatched root elements (a root swap is not
 * expressible as an X4 diff and would mean the wrong base file was picked).
 */
export function synthesizePatch(vanillaXml: string, editedXml: string): SynthesizedPatch {
  const vanDoc = parseDoc(vanillaXml);
  const edDoc = parseDoc(editedXml);
  if (vanDoc.documentElement.nodeName !== edDoc.documentElement.nodeName) {
    throw new Error('Root elements differ (' + vanDoc.documentElement.nodeName + ' vs ' + edDoc.documentElement.nodeName + ') — wrong base file?');
  }
  const ops: PatchOp[] = [];
  const warnings: string[] = [];
  diffElements(vanDoc.documentElement, edDoc.documentElement, ops, warnings);
  return { ops, diffXml: buildDiffXml(ops), warnings };
}

/**
 * Apply ops to a vanilla document — the verification half of the contract.
 * Returns the patched XML. Throws when a selector resolves to nothing (a
 * synthesized patch must never do that against its own base).
 */
export function applyPatch(vanillaXml: string, ops: PatchOp[]): string {
  const doc = parseDoc(vanillaXml);
  for (const op of ops) {
    if (op.type === 'replace' && op.sel.includes('/@')) {
      const cut = op.sel.lastIndexOf('/@');
      const owner = selectOne(doc, op.sel.slice(0, cut), op);
      owner.setAttribute(op.sel.slice(cut + 2), op.content || '');
      continue;
    }
    if (op.type === 'remove' && op.sel.includes('/@')) {
      const cut = op.sel.lastIndexOf('/@');
      const owner = selectOne(doc, op.sel.slice(0, cut), op);
      owner.removeAttribute(op.sel.slice(cut + 2));
      continue;
    }
    const node = selectOne(doc, op.sel, op);
    if (op.type === 'remove') {
      node.parentNode.removeChild(node);
    } else if (op.type === 'replace') {
      const frag = parseDoc(op.content || '').documentElement;
      node.parentNode.replaceChild(doc.importNode(frag, true), node);
    } else if (op.attrType) {
      node.setAttribute(op.attrType.replace(/^@/, ''), op.content || '');
    } else {
      const frag = parseDoc(op.content || '').documentElement;
      const imported = doc.importNode(frag, true);
      if (op.pos === 'before') node.parentNode.insertBefore(imported, node);
      else node.appendChild(imported);
    }
  }
  return String(serializer.serializeToString(doc));
}

function selectOne(doc: any, sel: string, op: PatchOp): any {
  let matches: any;
  try { matches = xpathLib.select(sel, doc); } catch (e: any) {
    throw new Error('bad selector "' + sel + '": ' + String((e && e.message) || e));
  }
  if (!Array.isArray(matches) || matches.length === 0) {
    throw new Error(op.type + ' selector matched nothing: ' + sel);
  }
  return matches[0];
}

/** Structural equality: same tree ignoring attribute order, whitespace-only
 *  text, and comments. Returns null when equal, else a human-readable diff hint. */
export function structuralDiff(aXml: string, bXml: string): string | null {
  const a = parseDoc(aXml).documentElement;
  const b = parseDoc(bXml).documentElement;
  return cmpEl(a, b, '/' + a.nodeName);
}

function cmpEl(a: any, b: any, where: string): string | null {
  if (a.nodeName !== b.nodeName) return where + ': tag ' + a.nodeName + ' != ' + b.nodeName;
  const aA = attrMap(a), bA = attrMap(b);
  if (aA.size !== bA.size) return where + ': attribute count ' + aA.size + ' != ' + bA.size;
  for (const [k, v] of aA) {
    if (!bA.has(k)) return where + ': missing attribute ' + k;
    if (bA.get(k) !== v) return where + ': @' + k + ' "' + v + '" != "' + bA.get(k) + '"';
  }
  if (directText(a) !== directText(b)) return where + ': text "' + directText(a) + '" != "' + directText(b) + '"';
  const aC = elementChildren(a), bC = elementChildren(b);
  if (aC.length !== bC.length) return where + ': child count ' + aC.length + ' != ' + bC.length;
  for (let i = 0; i < aC.length; i++) {
    const r = cmpEl(aC[i], bC[i], where + '/' + aC[i].nodeName + '[' + (i + 1) + ']');
    if (r) return r;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Selftest oracle — every case must round-trip: apply(synthesize()) ≡ edited.
// ---------------------------------------------------------------------------

export interface XpathSynthCheck { name: string; pass: boolean; detail?: string }

export function runXpathSynthSelftest(): { pass: boolean; checks: XpathSynthCheck[] } {
  const checks: XpathSynthCheck[] = [];
  const ok = (name: string, pass: boolean, detail?: string) => checks.push({ name, pass, detail });

  const roundTrip = (name: string, vanilla: string, edited: string, assertOps?: (p: SynthesizedPatch) => string | null) => {
    try {
      const p = synthesizePatch(vanilla, edited);
      const applied = applyPatch(vanilla, p.ops);
      const sd = structuralDiff(applied, edited);
      if (sd) { ok(name, false, 'round-trip mismatch: ' + sd); return; }
      const opErr = assertOps ? assertOps(p) : null;
      ok(name, !opErr, opErr || (p.ops.length + ' op(s)' + (p.warnings.length ? ', ' + p.warnings.length + ' warning(s)' : '')));
    } catch (e: any) {
      ok(name, false, String((e && e.message) || e));
    }
  };

  const base = '<jobs><job id="a"><orders count="5" speed="fast"/></job><job id="b"><orders count="2"/></job></jobs>';

  roundTrip('attribute value change → single attr replace', base,
    '<jobs><job id="a"><orders count="9" speed="fast"/></job><job id="b"><orders count="2"/></job></jobs>',
    p => (p.ops.length === 1 && p.ops[0].type === 'replace' && p.ops[0].sel.endsWith('/@count')) ? null : 'expected 1 attr replace, got ' + JSON.stringify(p.ops));

  roundTrip('attribute added → add type="@attr"', base,
    '<jobs><job id="a"><orders count="5" speed="fast" priority="high"/></job><job id="b"><orders count="2"/></job></jobs>',
    p => (p.ops.length === 1 && p.ops[0].type === 'add' && p.ops[0].attrType === '@priority') ? null : 'expected 1 attr add, got ' + JSON.stringify(p.ops));

  roundTrip('attribute removed → remove /@attr', base,
    '<jobs><job id="a"><orders count="5"/></job><job id="b"><orders count="2"/></job></jobs>',
    p => (p.ops.length === 1 && p.ops[0].type === 'remove' && p.ops[0].sel.endsWith('/@speed')) ? null : 'expected 1 attr remove, got ' + JSON.stringify(p.ops));

  roundTrip('element appended → add into parent with id selector', base,
    '<jobs><job id="a"><orders count="5" speed="fast"/></job><job id="b"><orders count="2"/></job><job id="c"><orders count="7"/></job></jobs>',
    p => (p.ops.length === 1 && p.ops[0].type === 'add' && p.ops[0].pos === 'child' && p.ops[0].sel === '/jobs') ? null : 'expected 1 child add on /jobs, got ' + JSON.stringify(p.ops));

  roundTrip('element inserted in the middle → pos="before" anchored on id', base,
    '<jobs><job id="a"><orders count="5" speed="fast"/></job><job id="x"><orders count="1"/></job><job id="b"><orders count="2"/></job></jobs>',
    p => (p.ops.length === 1 && p.ops[0].type === 'add' && p.ops[0].pos === 'before' && p.ops[0].sel.includes("job[@id='b']")) ? null : 'expected before-anchored add, got ' + JSON.stringify(p.ops));

  roundTrip('element removed → remove with id selector', base,
    '<jobs><job id="a"><orders count="5" speed="fast"/></job></jobs>',
    p => (p.ops.length === 1 && p.ops[0].type === 'remove' && p.ops[0].sel.includes("job[@id='b']")) ? null : 'expected 1 remove, got ' + JSON.stringify(p.ops));

  roundTrip('deep nested change stays minimal (1 op, not a tree replace)',
    '<root><group name="g1"><item id="i1" v="1"/><item id="i2" v="2"/></group><group name="g2"><item id="i3" v="3"/></group></root>',
    '<root><group name="g1"><item id="i1" v="1"/><item id="i2" v="22"/></group><group name="g2"><item id="i3" v="3"/></group></root>',
    p => (p.ops.length === 1 && p.ops[0].sel === "/root/group[@name='g1']/item[@id='i2']/@v") ? null : 'expected minimal deep attr replace, got ' + JSON.stringify(p.ops));

  roundTrip('id-less repeated siblings → positional selector with warning',
    '<list><entry v="1"/><entry v="2"/><entry v="3"/></list>',
    '<list><entry v="1"/><entry v="9"/><entry v="3"/></list>',
    p => (p.ops.length >= 1 && p.warnings.some(w => w.includes('positional'))) ? null : 'expected positional warning, got ' + JSON.stringify(p.warnings));

  roundTrip('text content change → element replace',
    '<conf><note id="n1">old text</note></conf>',
    '<conf><note id="n1">new text</note></conf>',
    p => (p.ops.length === 1 && p.ops[0].type === 'replace' && !p.ops[0].sel.includes('/@')) ? null : 'expected element replace, got ' + JSON.stringify(p.ops));

  roundTrip('identical documents → zero ops', base, base,
    p => p.ops.length === 0 ? null : 'expected 0 ops, got ' + p.ops.length);

  roundTrip('combined multi-op edit round-trips', base,
    '<jobs><job id="a"><orders count="9"/></job><job id="c"><orders count="7" mode="patrol"/></job></jobs>',
    null as any);

  try {
    synthesizePatch('<a/>', '<b/>');
    ok('mismatched roots rejected', false, 'no error thrown');
  } catch {
    ok('mismatched roots rejected', true);
  }

  return { pass: checks.every(c => c.pass), checks };
}

import fs from 'fs';
import path from 'path';
import { XMLParser } from 'fast-xml-parser';
import { schemaLibraryToTemplates, SchemaAttribute, SchemaCategory, SchemaElement, SchemaLibrary } from './schemaTypes';

type AnyNode = Record<string, any>;

const EVENT_GROUPS = new Set(['specificconditions_event', 'commonconditions_event']);
const CONDITION_GROUPS = new Set(['specificconditions_nonevent', 'commonconditions_nonevent']);
const ACTION_GROUPS = new Set(['commonactions']);
const CONTROL_FLOW_TAGS = new Set(['do_if', 'do_else', 'do_elseif', 'do_all', 'do_any', 'do_while', 'do_for_each']);

const parser = new XMLParser({
  ignoreAttributes: false,
  attributeNamePrefix: '',
  allowBooleanAttributes: true,
  commentPropName: '#comment',
  trimValues: true
});

export interface XsdConfig {
  x4GamePath?: string;
  xsdSchemaPath?: string;
  schemaFiles?: string[];
  modWorkspacePath?: string;
  filesystemPath?: string;
  /** optional user-configured X4 debug log path (debuglog.txt) */
  x4LogPath?: string;
}

export interface ResolvedXsdConfig extends XsdConfig {
  schemaDir: string;
  mdXsdPath: string;
  commonXsdPath: string;
  mdExists: boolean;
  commonExists: boolean;
  modWorkspacePath?: string;
  filesystemPath?: string;
}

function arrayOf<T>(value: T | T[] | undefined): T[] {
  if (!value) return [];
  return Array.isArray(value) ? value : [value];
}

function cleanText(value: unknown): string {
  if (value === undefined || value === null) return '';
  if (typeof value === 'string') return value.replace(/\s+/g, ' ').trim();
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (Array.isArray(value)) return value.map(cleanText).filter(Boolean).join(' ');
  if (typeof value === 'object') {
    const node = value as AnyNode;
    if ('#text' in node) return cleanText(node['#text']);
    return Object.values(node).map(cleanText).filter(Boolean).join(' ');
  }
  return '';
}

function documentationOf(node: AnyNode | undefined): string {
  if (!node) return '';
  return cleanText(node['xs:annotation']?.['xs:documentation']);
}

function collectNodesByKey(node: any, key: string, out: AnyNode[] = []): AnyNode[] {
  if (!node || typeof node !== 'object') return out;
  if (Array.isArray(node)) {
    node.forEach(item => collectNodesByKey(item, key, out));
    return out;
  }
  if (node[key]) out.push(...arrayOf(node[key]));
  Object.values(node).forEach(value => collectNodesByKey(value, key, out));
  return out;
}

function collectEnums(node: AnyNode | undefined): string[] {
  if (!node) return [];
  const enums = collectNodesByKey(node, 'xs:enumeration')
    .map(en => en.value)
    .filter((value): value is string => typeof value === 'string' && value.length > 0);
  return Array.from(new Set(enums));
}

function collectSimpleTypes(schemaRoots: AnyNode[]): Record<string, string[]> {
  const simpleTypes: Record<string, string[]> = {};
  schemaRoots.forEach(root => {
    arrayOf(root['xs:schema']?.['xs:simpleType']).forEach((simpleType: AnyNode) => {
      if (!simpleType.name) return;
      const enums = collectEnums(simpleType);
      if (enums.length > 0) simpleTypes[simpleType.name] = enums;
    });
  });
  return simpleTypes;
}

function collectAttributeGroups(schemaRoots: AnyNode[]): Map<string, AnyNode> {
  const groups = new Map<string, AnyNode>();
  schemaRoots.forEach(root => {
    arrayOf(root['xs:schema']?.['xs:attributeGroup']).forEach((group: AnyNode) => {
      if (group.name) groups.set(group.name, group);
    });
  });
  return groups;
}

function attributeType(attr: AnyNode): string {
  if (attr.type) return attr.type;
  const inlineEnums = collectEnums(attr['xs:simpleType']);
  if (inlineEnums.length > 0) return 'enum';
  return 'expression';
}

function attributeToDescriptor(attr: AnyNode, simpleTypes: Record<string, string[]>): SchemaAttribute | null {
  if (!attr?.name) return null;
  const type = attributeType(attr);
  const inlineEnums = collectEnums(attr['xs:simpleType']);
  const enumValues = inlineEnums.length > 0 ? inlineEnums : simpleTypes[type];
  return {
    name: attr.name,
    type,
    required: attr.use === 'required',
    documentation: documentationOf(attr),
    enumValues,
    defaultValue: attr.default
  };
}

function collectAttributes(
  node: AnyNode,
  simpleTypes: Record<string, string[]>,
  attributeGroups: Map<string, AnyNode>,
  seenGroups = new Set<string>()
): SchemaAttribute[] {
  const attrs: SchemaAttribute[] = [];

  collectNodesByKey(node, 'xs:attribute').forEach(attr => {
    const descriptor = attributeToDescriptor(attr, simpleTypes);
    if (descriptor) attrs.push(descriptor);
  });

  collectNodesByKey(node, 'xs:attributeGroup').forEach(groupRef => {
    const ref = groupRef.ref || groupRef.name;
    if (!ref || seenGroups.has(ref)) return;
    const group = attributeGroups.get(ref);
    if (!group) return;
    seenGroups.add(ref);
    attrs.push(...collectAttributes(group, simpleTypes, attributeGroups, seenGroups));
  });

  const byName = new Map<string, SchemaAttribute>();
  attrs.forEach(attr => {
    const existing = byName.get(attr.name);
    byName.set(attr.name, {
      ...existing,
      ...attr,
      required: Boolean(existing?.required || attr.required),
      documentation: attr.documentation || existing?.documentation || ''
    });
  });
  return Array.from(byName.values()).sort((a, b) => Number(b.required) - Number(a.required) || a.name.localeCompare(b.name));
}

function childElementsOf(node: AnyNode, category: SchemaCategory): SchemaElement['childElements'] {
  return collectNodesByKey(node['xs:complexType'] || {}, 'xs:element')
    .map(child => child.name || child.ref)
    .filter((tag): tag is string => typeof tag === 'string' && tag.length > 0)
    .map(tag => ({ tag, category, documentation: '' }))
    .slice(0, 50);
}

function classifyFromGroup(groupName: string, tag: string): SchemaCategory {
  if (CONTROL_FLOW_TAGS.has(tag)) return 'control_flow';
  if (EVENT_GROUPS.has(groupName) || tag.startsWith('event_')) return 'event';
  if (CONDITION_GROUPS.has(groupName)) return 'condition';
  if (ACTION_GROUPS.has(groupName)) return CONTROL_FLOW_TAGS.has(tag) ? 'control_flow' : 'action';
  return tag.startsWith('event_') ? 'event' : 'action';
}

function collectGroupElements(
  schemaRoots: AnyNode[],
  simpleTypes: Record<string, string[]>,
  attributeGroups: Map<string, AnyNode>,
  groupNames: Set<string>
): SchemaElement[] {
  const elements = new Map<string, SchemaElement>();

  schemaRoots.forEach(root => {
    const sourceFile = root.__sourceFile || '';
    arrayOf(root['xs:schema']?.['xs:group']).forEach((group: AnyNode) => {
      if (!group.name || !groupNames.has(group.name)) return;
      collectNodesByKey(group, 'xs:element').forEach(element => {
        const tag = element.name || element.ref;
        if (!tag) return;
        const category = classifyFromGroup(group.name, tag);
        elements.set(tag, {
          tag,
          category,
          documentation: documentationOf(element),
          attributes: collectAttributes(element, simpleTypes, attributeGroups),
          childElements: childElementsOf(element, category),
          sourceFile
        });
      });
    });
  });

  return Array.from(elements.values()).sort((a, b) => a.tag.localeCompare(b.tag));
}

export function getDefaultGamePath(): string {
  if (process.env.X4_GAME_PATH) return process.env.X4_GAME_PATH;
  if (fs.existsSync(configPath())) {
    try {
      const config = readXsdConfig();
      if (config.x4GamePath) return config.x4GamePath;
    } catch {
      // Ignore malformed config here; startup will still report schema load errors.
    }
  }
  return 'G:\\SteamLibrary\\steamapps\\common\\X4 Foundations';
}

export function getDefaultSchemaDir(gamePath = getDefaultGamePath()): string {
  if (process.env.X4_XSD_PATH) return process.env.X4_XSD_PATH;
  if (fs.existsSync(configPath())) {
    try {
      const config = readXsdConfig();
      if (config.xsdSchemaPath) return path.isAbsolute(config.xsdSchemaPath)
        ? config.xsdSchemaPath
        : path.join(gamePath, config.xsdSchemaPath);
    } catch {
      // Ignore malformed config here; startup will still report schema load errors.
    }
  }
  return path.join(gamePath, 'extensions', 'x4_ai_influence', 'md');
}

function configPath(): string {
  return path.resolve(process.cwd(), 'config.json');
}

export function readXsdConfig(): XsdConfig {
  const fullPath = configPath();
  if (!fs.existsSync(fullPath)) return {};
  return JSON.parse(fs.readFileSync(fullPath, 'utf8'));
}

export function writeXsdConfig(config: XsdConfig): void {
  fs.writeFileSync(configPath(), `${JSON.stringify(config, null, 2)}\n`, 'utf8');
}

export function resolveXsdConfig(config = readXsdConfig()): ResolvedXsdConfig {
  const gamePath = process.env.X4_GAME_PATH || config.x4GamePath || 'G:\\SteamLibrary\\steamapps\\common\\X4 Foundations';
  const schemaDir = process.env.X4_XSD_PATH
    || (config.xsdSchemaPath
      ? (path.isAbsolute(config.xsdSchemaPath) ? config.xsdSchemaPath : path.join(gamePath, config.xsdSchemaPath))
      : path.join(gamePath, 'extensions', 'x4_ai_influence', 'md'));

  const files = config.schemaFiles?.length ? config.schemaFiles : ['md.xsd', 'common.xsd'];
  const mdFile = files.find(file => path.basename(file).toLowerCase() === 'md.xsd') || 'md.xsd';
  const commonFile = files.find(file => path.basename(file).toLowerCase() === 'common.xsd') || 'common.xsd';
  const mdXsdPath = path.isAbsolute(mdFile) ? mdFile : path.join(schemaDir, mdFile);
  const commonXsdPath = path.isAbsolute(commonFile) ? commonFile : path.join(schemaDir, commonFile);

  return {
    ...config,
    x4GamePath: gamePath,
    xsdSchemaPath: config.xsdSchemaPath || schemaDir,
    schemaFiles: files,
    schemaDir,
    mdXsdPath,
    commonXsdPath,
    mdExists: fs.existsSync(mdXsdPath),
    commonExists: fs.existsSync(commonXsdPath)
  };
}

export function loadSchemaLibrary(schemaDir = getDefaultSchemaDir(), files = ['md.xsd', 'common.xsd']): SchemaLibrary {
  const schemaRoots = files.map(file => {
    const fullPath = path.isAbsolute(file) ? file : path.join(schemaDir, file);
    const parsed = parser.parse(fs.readFileSync(fullPath, 'utf8'));
    parsed.__sourceFile = fullPath;
    return parsed;
  });

  const simpleTypes = collectSimpleTypes(schemaRoots);
  const attributeGroups = collectAttributeGroups(schemaRoots);

  const events = collectGroupElements(schemaRoots, simpleTypes, attributeGroups, EVENT_GROUPS);
  const conditions = collectGroupElements(schemaRoots, simpleTypes, attributeGroups, CONDITION_GROUPS);
  const actionLike = collectGroupElements(schemaRoots, simpleTypes, attributeGroups, ACTION_GROUPS);
  const controlFlow = actionLike.filter(element => element.category === 'control_flow');
  const actions = actionLike.filter(element => element.category !== 'control_flow');

  const libraryBase = {
    events,
    conditions,
    actions,
    controlFlow,
    simpleTypes,
    sourceFiles: files.map(file => path.isAbsolute(file) ? file : path.join(schemaDir, file)),
    loaded: true
  };

  return {
    ...libraryBase,
    templates: schemaLibraryToTemplates(libraryBase)
  };
}

export function createEmptySchemaLibrary(error?: string): SchemaLibrary {
  return {
    events: [],
    conditions: [],
    actions: [],
    controlFlow: [],
    simpleTypes: {},
    templates: [],
    sourceFiles: [],
    loaded: false,
    error
  };
}

/**
 * @license
 * SPDX-License-Identifier: Apache-2.0
 *
 * Schema-backed XML validation. Builds an element -> allowed-attributes index
 * from the real X4 `.xsd` schema files (md.xsd + common.xsd) and validates
 * generated XML against it. This is a pragmatic subset of full XSD validation:
 * it covers the highest-confidence, highest-value checks —
 *   - enumeration violations (attribute value not in the schema's allowed set)
 *   - missing `use="required"` attributes
 *   - unknown attributes on a recognized element
 *   - unknown elements (info-level, since the schema index can be incomplete)
 * — with raw-text line numbers for actionable sourceRefs. It deliberately does
 * NOT attempt full sequence/cardinality/choice validation.
 */

import fs from 'fs';
import { XMLParser } from 'fast-xml-parser';

export interface XsdDiagnostic {
  severity: 'error' | 'warning' | 'info';
  domain: string;
  filePath?: string;
  message: string;
  line?: number;
  sourceRef?: string;
  code?: string;
}

interface AttrSpec {
  required: boolean;
  enumValues?: string[];
  type?: string;
}

interface ElementSpec {
  attributes: Map<string, AttrSpec>;
  /** true when the element's complexType permits arbitrary attributes (anyAttribute) */
  openAttributes: boolean;
  /** true when we successfully resolved the element's type (inline or named) */
  resolved: boolean;
  /** lowercased names of child elements this element may contain (best-effort) */
  children: Set<string>;
}

export interface SchemaIndex {
  elements: Map<string, ElementSpec>; // key: lowercased element name
  loaded: boolean;
  sourceFiles: string[];
  elementCount: number;
}

type AnyNode = Record<string, any>;

const parser = new XMLParser({
  ignoreAttributes: false,
  attributeNamePrefix: '',
  allowBooleanAttributes: true,
  trimValues: true
});

function arrayOf<T>(v: T | T[] | undefined): T[] {
  if (v === undefined || v === null) return [];
  return Array.isArray(v) ? v : [v];
}

function collectByKey(node: any, key: string, out: AnyNode[] = []): AnyNode[] {
  if (!node || typeof node !== 'object') return out;
  if (Array.isArray(node)) {
    node.forEach(item => collectByKey(item, key, out));
    return out;
  }
  if (node[key]) out.push(...arrayOf(node[key]));
  for (const v of Object.values(node)) collectByKey(v, key, out);
  return out;
}

function collectEnums(node: AnyNode | undefined): string[] {
  if (!node) return [];
  const enums = collectByKey(node, 'xs:enumeration')
    .map(e => e.value)
    .filter((v): v is string => typeof v === 'string' && v.length > 0);
  return Array.from(new Set(enums));
}

let cached: { key: string; index: SchemaIndex } | null = null;

/**
 * Build (and cache) a schema element/attribute index from the given XSD files.
 * Caches on file paths + mtimes so a schema edit invalidates it.
 */
export function buildSchemaIndex(xsdPaths: string[]): SchemaIndex {
  const existing = xsdPaths.filter(p => p && fs.existsSync(p));
  if (!existing.length) {
    return { elements: new Map(), loaded: false, sourceFiles: [], elementCount: 0 };
  }
  const key = existing.map(p => {
    try { return `${p}:${fs.statSync(p).mtimeMs}`; } catch { return p; }
  }).join('|');
  if (cached && cached.key === key) return cached.index;

  const roots = existing.map(p => parser.parse(fs.readFileSync(p, 'utf8')));

  // Global named simpleTypes -> enum lists, attributeGroups + complexTypes for ref resolution.
  const simpleTypeEnums: Record<string, string[]> = {};
  const attributeGroups = new Map<string, AnyNode>();
  const complexTypes = new Map<string, AnyNode>();
  const groups = new Map<string, AnyNode>();
  for (const root of roots) {
    arrayOf(root['xs:schema']?.['xs:simpleType']).forEach((st: AnyNode) => {
      if (st.name) {
        const e = collectEnums(st);
        if (e.length) simpleTypeEnums[st.name] = e;
      }
    });
    arrayOf(root['xs:schema']?.['xs:attributeGroup']).forEach((g: AnyNode) => {
      if (g.name) attributeGroups.set(g.name, g);
    });
    arrayOf(root['xs:schema']?.['xs:complexType']).forEach((ct: AnyNode) => {
      if (ct.name) complexTypes.set(ct.name, ct);
    });
    arrayOf(root['xs:schema']?.['xs:group']).forEach((g: AnyNode) => {
      if (g.name) groups.set(g.name, g);
    });
  }

  // Collect the child-element names an element may contain, following named
  // complexTypes (via `type`/`base`) and xs:group references. Best-effort and
  // intentionally over-inclusive (used to avoid false "unknown element" flags).
  function collectChildren(typeNode: AnyNode, into: Set<string>, seenTypes: Set<string>, seenGroups: Set<string>, depth = 0) {
    if (!typeNode || typeof typeNode !== 'object' || depth > 40) return;
    for (const [k, v] of Object.entries(typeNode)) {
      if (k === 'xs:attribute' || k === 'xs:attributeGroup' || k === 'xs:annotation' || k === 'xs:simpleType') continue;
      if (k === 'xs:element') {
        for (const el of arrayOf(v)) {
          const nm = el?.name || el?.ref;
          if (typeof nm === 'string' && nm) into.add(nm.toLowerCase());
          // descend into inline-typed children? No — only THIS element's direct
          // particle membership matters, but X4 nests via groups, handled below.
        }
        continue;
      }
      if (k === 'xs:group') {
        for (const g of arrayOf(v)) {
          const ref = g?.ref || g?.name;
          if (ref && groups.has(ref) && !seenGroups.has(ref)) {
            seenGroups.add(ref);
            collectChildren(groups.get(ref)!, into, seenTypes, seenGroups, depth + 1);
          } else if (g && typeof g === 'object') {
            collectChildren(g, into, seenTypes, seenGroups, depth + 1);
          }
        }
        continue;
      }
      if (k === 'base' && typeof v === 'string' && complexTypes.has(v) && !seenTypes.has(v)) {
        seenTypes.add(v);
        collectChildren(complexTypes.get(v)!, into, seenTypes, seenGroups, depth + 1);
        continue;
      }
      // recurse into structural containers (sequence/choice/all/complexContent/extension/restriction)
      if (typeof v === 'object' && v !== null) collectChildren(v, into, seenTypes, seenGroups, depth + 1);
    }
  }

  const addAttr = (attr: AnyNode, into: Map<string, AttrSpec>) => {
    if (!attr?.name) return;
    const inlineEnums = collectEnums(attr['xs:simpleType']);
    const typeEnums = attr.type ? simpleTypeEnums[attr.type] : undefined;
    const enumValues = inlineEnums.length ? inlineEnums : typeEnums;
    const lname = String(attr.name).toLowerCase();
    const prev = into.get(lname);
    into.set(lname, {
      required: Boolean(prev?.required) || attr.use === 'required',
      enumValues: enumValues && enumValues.length ? enumValues : prev?.enumValues,
      type: attr.type || prev?.type
    });
  };

  const addGroupRefs = (node: AnyNode, into: Map<string, AttrSpec>, seenGroups: Set<string>, open: { v: boolean }) => {
    for (const gref of arrayOf(node['xs:attributeGroup'])) {
      const ref = gref.ref || gref.name;
      if (!ref || seenGroups.has(ref)) continue;
      seenGroups.add(ref);
      const g = attributeGroups.get(ref);
      if (g) collectTypeAttrs(g, into, seenGroups, new Set(), open);
    }
  };

  // Collect ONLY the attributes that belong to this complexType/attributeGroup —
  // its direct xs:attribute/xs:attributeGroup plus those inside
  // complexContent/simpleContent > extension/restriction (following `base`).
  // Deliberately does NOT descend into xs:sequence/choice/all element children.
  function collectTypeAttrs(typeNode: AnyNode, into: Map<string, AttrSpec>, seenGroups: Set<string>, seenTypes: Set<string>, open: { v: boolean }) {
    if (!typeNode || typeof typeNode !== 'object') return;
    if (typeNode['xs:anyAttribute']) open.v = true;
    for (const attr of arrayOf(typeNode['xs:attribute'])) addAttr(attr, into);
    addGroupRefs(typeNode, into, seenGroups, open);

    for (const wrapper of ['xs:complexContent', 'xs:simpleContent']) {
      const content = typeNode[wrapper];
      if (!content) continue;
      for (const deriv of ['xs:extension', 'xs:restriction']) {
        const ext = content[deriv];
        if (!ext) continue;
        if (ext['xs:anyAttribute']) open.v = true;
        for (const attr of arrayOf(ext['xs:attribute'])) addAttr(attr, into);
        addGroupRefs(ext, into, seenGroups, open);
        const base = ext.base;
        if (base && complexTypes.has(base) && !seenTypes.has(base)) {
          seenTypes.add(base);
          collectTypeAttrs(complexTypes.get(base)!, into, seenGroups, seenTypes, open);
        }
      }
    }
  }

  const resolveElementAttrs = (el: AnyNode): { attrs: Map<string, AttrSpec>; open: boolean; resolved: boolean; children: Set<string> } => {
    const into = new Map<string, AttrSpec>();
    const children = new Set<string>();
    const open = { v: false };
    let resolved = false;
    // inline complexType
    if (el['xs:complexType']) {
      collectTypeAttrs(el['xs:complexType'], into, new Set(), new Set(), open);
      collectChildren(el['xs:complexType'], children, new Set(), new Set());
      resolved = true;
    }
    // named type reference
    if (typeof el.type === 'string' && complexTypes.has(el.type)) {
      const t = complexTypes.get(el.type)!;
      collectTypeAttrs(t, into, new Set(), new Set([el.type]), open);
      collectChildren(t, children, new Set([el.type]), new Set());
      resolved = true;
    }
    return { attrs: into, open: open.v, resolved, children };
  };

  const elements = new Map<string, ElementSpec>();
  const addElement = (name: string, attrs: Map<string, AttrSpec>, open: boolean, resolved: boolean, children: Set<string>) => {
    const lname = name.toLowerCase();
    const prev = elements.get(lname);
    if (prev) {
      for (const [k, v] of attrs) {
        const p = prev.attributes.get(k);
        prev.attributes.set(k, {
          required: Boolean(p?.required) && Boolean(v.required),
          enumValues: v.enumValues || p?.enumValues,
          type: v.type || p?.type
        });
      }
      prev.openAttributes = prev.openAttributes || open;
      prev.resolved = prev.resolved || resolved;
      for (const c of children) prev.children.add(c);
    } else {
      elements.set(lname, { attributes: attrs, openAttributes: open, resolved, children });
    }
  };

  for (const root of roots) {
    for (const el of collectByKey(root, 'xs:element')) {
      const name = el?.name;
      if (typeof name !== 'string' || !name) continue;
      const { attrs, open, resolved, children } = resolveElementAttrs(el);
      addElement(name, attrs, open, resolved, children);
    }
  }

  const index: SchemaIndex = { elements, loaded: true, sourceFiles: existing, elementCount: elements.size };
  cached = { key, index };
  return index;
}

interface RawTag {
  name: string;
  attrs: { name: string; value: string }[];
  line: number;
  selfClosing: boolean;
}

/** Lightweight scanner: yields each opening/self-closing tag with line numbers. */
function scanTags(xml: string): RawTag[] {
  const tags: RawTag[] = [];
  // match opening or self-closing tags, skip closing tags, comments, PIs, declarations
  const re = /<([a-zA-Z_][\w.-]*)((?:\s+[\w.\-:]+\s*=\s*(?:"[^"]*"|'[^']*'))*)\s*(\/?)>/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(xml)) !== null) {
    const before = xml.slice(0, m.index);
    const line = before.split('\n').length;
    const name = m[1];
    const attrStr = m[2] || '';
    const attrs: { name: string; value: string }[] = [];
    const attrRe = /([\w.\-:]+)\s*=\s*(?:"([^"]*)"|'([^']*)')/g;
    let a: RegExpExecArray | null;
    while ((a = attrRe.exec(attrStr)) !== null) {
      attrs.push({ name: a[1], value: a[2] !== undefined ? a[2] : (a[3] || '') });
    }
    tags.push({ name, attrs, line, selfClosing: m[3] === '/' });
  }
  return tags;
}

// Structural/known tags that may not carry attribute specs in our index but are
// valid; never report these as "unknown element".
const ALWAYS_KNOWN = new Set([
  'mdscript', 'cues', 'cue', 'cues', 'library', 'conditions', 'actions', 'params', 'param',
  'attention', 'check_value', 'check_any', 'check_all', 'do_if', 'do_else', 'do_elseif',
  'do_all', 'do_any', 'do_while', 'do_for_each', 'set_value', 'patch', 'diff', 'add', 'replace',
  'remove', 'aiscript', 'order', 'init', 'interrupt', 'blocks', 'resume', 'label', 'sumitemstodo'
]);

export interface ValidateOptions {
  filePath?: string;
  domain?: string;
  reportUnknownElements?: boolean; // default false (info-only, can false-positive)
  reportUnknownAttributes?: boolean; // default true (warning)
  checkTimeFormat?: boolean; // default true
  /**
   * Real game-data reference sets, keyed by the schema's semantic attribute
   * types. When provided, literal values of attributes with that type are
   * checked for existence (catches runtime "no ship generated" / unknown id).
   */
  references?: {
    macros?: Set<string>;   // type "macroname"/"macro"
    wares?: Set<string>;    // type "warename"/"ware" (literal only)
    factions?: Set<string>; // type "faction" (literal only)
  };
}

// X4 time-typed attributes are schema-typed as permissive "expression", so the
// XSD can't catch a bare number. These names are time values at runtime and a
// literal integer without a unit (e.g. "8") fails as "not of type time".
const TIME_ATTR_NAMES = new Set(['duration', 'timeout', 'delay', 'interval']);

/** A literal (non-expression) reference value we can check against an index. */
function isLiteralRef(v: string): boolean {
  return !!v && !/[{}$\s]/.test(v) && !v.includes('.');
}

/**
 * Validate XML text against the schema index. Returns diagnostics for enum
 * violations (error), missing required attributes (warning), unknown attributes
 * (warning), and optionally unknown elements (info).
 */
export function validateXmlAgainstSchema(xml: string, index: SchemaIndex, opts: ValidateOptions = {}): XsdDiagnostic[] {
  const out: XsdDiagnostic[] = [];
  if (!index.loaded || !index.elements.size) return out;
  const domain = opts.domain || 'md';
  const filePath = opts.filePath;
  const reportUnknownAttr = opts.reportUnknownAttributes !== false;
  const reportUnknownEl = opts.reportUnknownElements === true;

  for (const tag of scanTags(xml)) {
    const lname = tag.name.toLowerCase();
    const spec = index.elements.get(lname);

    if (!spec) {
      if (reportUnknownEl && !ALWAYS_KNOWN.has(lname)) {
        // WARNING (not info): an element the game schema doesn't recognize is a real
        // risk — almost always a typo or a fabricated element name. Surfacing it as a
        // warning makes it count in the Doctor and matches the on-canvas node badge,
        // instead of being buried as info. The wording stays honest about the rare
        // schema-incompleteness case.
        out.push({
          severity: 'warning',
          domain,
          filePath,
          line: tag.line,
          sourceRef: `${tag.name}`,
          code: 'XSD_UNKNOWN_ELEMENT',
          message: `Element <${tag.name}> is not declared in the game schema (md.xsd/common.xsd) — likely a typo or wrong element name. (If it is a deliberate custom element, it can be ignored.)`
        });
      }
      continue;
    }

    const present = new Set(tag.attrs.map(a => a.name.toLowerCase()));

    // enum + unknown-attr checks
    for (const attr of tag.attrs) {
      const aname = attr.name.toLowerCase();
      if (aname.startsWith('xmlns') || aname.startsWith('xsi:')) continue;
      const aspec = spec.attributes.get(aname);
      if (!aspec) {
        // Only flag unknown attributes when we actually resolved this element's
        // attribute set; otherwise we'd false-positive on unresolved types.
        if (reportUnknownAttr && !spec.openAttributes && spec.resolved && spec.attributes.size > 0) {
          out.push({
            severity: 'warning',
            domain,
            filePath,
            line: tag.line,
            sourceRef: `${tag.name}@${attr.name}`,
            code: 'XSD_UNKNOWN_ATTRIBUTE',
            message: `<${tag.name}> has attribute "${attr.name}" which is not declared for this element in the schema.`
          });
        }
        continue;
      }
      if (aspec.enumValues && aspec.enumValues.length && attr.value && !/\{/.test(attr.value)) {
        // skip MD expressions like {param.x}; only validate literal values
        const ok = aspec.enumValues.some(v => v.toLowerCase() === attr.value.toLowerCase());
        if (!ok) {
          out.push({
            severity: 'error',
            domain,
            filePath,
            line: tag.line,
            sourceRef: `${tag.name}@${attr.name}`,
            code: 'XSD_ENUM_VIOLATION',
            message: `<${tag.name}> attribute "${attr.name}"="${attr.value}" is not a valid value. Allowed: ${aspec.enumValues.slice(0, 12).join(', ')}${aspec.enumValues.length > 12 ? ', …' : ''}.`
          });
        }
      }

      // Time-format check (schema type is permissive "expression", so this is a
      // curated semantic rule): a bare integer on a time attribute fails at runtime.
      if (opts.checkTimeFormat !== false && TIME_ATTR_NAMES.has(aname) && attr.value && /^\d+(\.\d+)?$/.test(attr.value)) {
        out.push({
          severity: 'warning',
          domain,
          filePath,
          line: tag.line,
          sourceRef: `${tag.name}@${attr.name}`,
          code: 'XSD_TIME_FORMAT',
          message: `<${tag.name}> attribute "${attr.name}"="${attr.value}" looks like a time but has no unit. X4 rejects bare numbers for time values at runtime — use "${attr.value}s" (or ms/min/h).`
        });
      }

      // Faction reference: the explicit "faction.<id>" literal form is
      // unambiguous (unlike bare expressions), so validate it even though the
      // schema type is often an expression union.
      if (opts.references?.factions?.size && attr.value && /^faction\.\w+$/i.test(attr.value)) {
        if (!opts.references.factions.has(attr.value.toLowerCase())) {
          out.push({
            severity: 'error', domain, filePath, line: tag.line,
            sourceRef: `${tag.name}@${attr.name}`, code: 'REF_UNKNOWN_FACTION',
            message: `<${tag.name}> ${attr.name}="${attr.value}" is not a known faction. Valid factions come from libraries/factions.xml in the indexed game data.`
          });
        }
      }

      // Reference existence check, driven by the schema's semantic type.
      const refs = opts.references;
      if (refs && attr.value && isLiteralRef(attr.value)) {
        const t = (aspec.type || '').toLowerCase();
        const lv = attr.value.toLowerCase();
        if ((t === 'macroname' || t === 'macro') && refs.macros && refs.macros.size && !refs.macros.has(lv)) {
          out.push({
            severity: 'error', domain, filePath, line: tag.line,
            sourceRef: `${tag.name}@${attr.name}`, code: 'REF_UNKNOWN_MACRO',
            message: `<${tag.name}> ${attr.name}="${attr.value}" is not a known macro in the indexed game data (${refs.macros.size} macros). X4 will not resolve it at runtime — pick a real macro from the Object Browser.`
          });
        } else if ((t === 'warename' || t === 'ware') && refs.wares && refs.wares.size && !refs.wares.has(lv)) {
          out.push({
            severity: 'warning', domain, filePath, line: tag.line,
            sourceRef: `${tag.name}@${attr.name}`, code: 'REF_UNKNOWN_WARE',
            message: `<${tag.name}> ${attr.name}="${attr.value}" is not a known ware id in the indexed game data (${refs.wares.size} wares).`
          });
        }
      }
    }

    // required attribute presence
    for (const [aname, aspec] of spec.attributes) {
      if (aspec.required && !present.has(aname)) {
        out.push({
          severity: 'warning',
          domain,
          filePath,
          line: tag.line,
          sourceRef: `${tag.name}@${aname}`,
          code: 'XSD_MISSING_REQUIRED',
          message: `<${tag.name}> is missing required attribute "${aname}" per the schema.`
        });
      }
    }
  }

  return out;
}

import {StrictMode} from 'react';
import {createRoot} from 'react-dom/client';
import App from './App.tsx';
import './index.css';

declare global {
  interface Window {
    __STUDIO_API_TOKEN__?: string;
  }
}

const injectedToken = window.__STUDIO_API_TOKEN__;
if (injectedToken) {
  sessionStorage.setItem('studio_session_token', injectedToken);
}

// Override fetch globally before rendering the app safely.
const originalFetch = window.fetch;

// H3 boot-race: Vite (3000) starts proxying before the tsx API (3001) finishes
// transpiling server.ts (~2-3s), so early /api calls hit the proxy's soft 503
// ("API server is restarting") or a transient connection error. We transparently
// retry — but ONLY idempotent /api GETs, with a small capped backoff. Mutations
// (POST/PUT/PATCH/DELETE) are NEVER auto-retried (could double-apply a change).
const API_BOOT_BACKOFFS_MS = [200, 350, 500, 650]; // ~1.7s total, within the boot window
const delay = (ms: number) => new Promise<void>(r => setTimeout(r, ms));

function methodOf(input: RequestInfo | URL, init?: RequestInit): string {
  const m = init?.method || (typeof input === 'object' && input instanceof Request ? input.method : undefined) || 'GET';
  return m.toUpperCase();
}

const customFetch = async function(this: any, input: RequestInfo | URL, init?: RequestInit) {
  const url = typeof input === 'string' ? input : (input instanceof URL ? input.href : input.url);
  // Security: only attach the session token to SAME-ORIGIN /api/ requests. A bare
  // url.includes('/api/') would leak the bearer token to any future cross-origin URL
  // that happens to contain '/api/' (a plugin/analytics script). Resolve against the
  // app origin and require both same-origin AND an /api/ path prefix.
  let isApi = false;
  try {
    const u = new URL(url, location.origin);
    isApi = u.origin === location.origin && u.pathname.startsWith('/api/');
  } catch { isApi = false; } // unparseable URL → never treat as our API
  if (isApi) {
    const token = sessionStorage.getItem('studio_session_token');
    if (token) {
      init = init || {};
      init.headers = init.headers || {};
      if (init.headers instanceof Headers) {
        init.headers.set('Authorization', `Bearer ${token}`);
      } else if (Array.isArray(init.headers)) {
        const authIdx = init.headers.findIndex(([k]) => k.toLowerCase() === 'authorization');
        if (authIdx !== -1) {
          init.headers[authIdx] = ['Authorization', `Bearer ${token}`];
        } else {
          init.headers.push(['Authorization', `Bearer ${token}`]);
        }
      } else {
        (init.headers as Record<string, string>)['Authorization'] = `Bearer ${token}`;
      }
    }
  }

  // Fast path: anything that isn't an idempotent /api GET goes straight through.
  if (!isApi || methodOf(input, init) !== 'GET') {
    return originalFetch.call(this, input, init);
  }

  // Bounded retry for the API boot/restart window only.
  for (let attempt = 0; ; attempt++) {
    try {
      const res = await originalFetch.call(this, input, init);
      if (res.status === 503 && attempt < API_BOOT_BACKOFFS_MS.length) {
        await delay(API_BOOT_BACKOFFS_MS[attempt]);
        continue;
      }
      return res;
    } catch (err) {
      // Transient connection error (API socket not up yet) — retry within budget.
      if (attempt < API_BOOT_BACKOFFS_MS.length) {
        await delay(API_BOOT_BACKOFFS_MS[attempt]);
        continue;
      }
      throw err;
    }
  }
};

try {
  Object.defineProperty(window, 'fetch', {
    value: customFetch,
    writable: true,
    configurable: true,
    enumerable: true
  });
} catch (e) {
  try {
    window.fetch = customFetch;
  } catch (err) {
    console.warn('Failed to intercept window.fetch safely:', err);
  }
}

createRoot(document.getElementById('root')!).render(
  <StrictMode>
    <App />
  </StrictMode>,
);

